-- Adminer 5.4.2 PostgreSQL 18.3 dump

DROP TABLE IF EXISTS "Action";
CREATE TABLE "public"."Action" (
    "ActionID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Cost" character varying,
    "Requirements" character varying,
    "Trigger" character varying,
    "Description" text NOT NULL,
    "Frequency" character varying,
    "Traits" character varying,
    CONSTRAINT "Action_ActionID" PRIMARY KEY ("ActionID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Action"."ActionID" IS 'Unique Action ID';

COMMENT ON COLUMN "public"."Action"."Name" IS 'Action name';

COMMENT ON COLUMN "public"."Action"."Cost" IS 'List of possible Action costs';

COMMENT ON COLUMN "public"."Action"."Requirements" IS 'Action requirements text';

COMMENT ON COLUMN "public"."Action"."Trigger" IS 'Action trigger';

COMMENT ON COLUMN "public"."Action"."Description" IS 'Action description text';

COMMENT ON COLUMN "public"."Action"."Frequency" IS 'Action reuse frequency';

COMMENT ON COLUMN "public"."Action"."Traits" IS 'Action traits';

INSERT INTO "Action" ("ActionID", "Name", "Cost", "Requirements", "Trigger", "Description", "Frequency", "Traits") VALUES
('actImpersonate',	'Impersonate',	NULL,	NULL,	NULL,	'You create a disguise to pass yourself off as someone or something you are not. Assembling a convincing disguise takes 10 minutes and requires a holoskin or similar disguise, but a simpler, quicker disguise might do the job if you''re not trying to imitate a specific individual, at the GM''s discretion.  
In most cases, creatures have a chance to detect your deception only if they use the Seek action to attempt Perception checks against your Deception DC. If you attempt to directly interact with someone while disguised, the GM rolls a secret Deception check for you against that creature''s Perception DC instead.  
If you''re disguised as a specific individual, the GM might give creatures you interact with a circumstance bonus based on how well they know the person you''re imitating, or the GM might roll a secret Deception check even if you aren''t directly interacting with others.

<b>Success</b> You trick the creature into thinking you''re the person you''re disguised as. You might have to attempt a new check if your behavior changes.<br><b>Failure</b> The creature can tell you''re not who you claim to be.<br><b>Critical Failure</b> The creature can tell you''re not who you claim to be, and it recognizes you if it would know you without a disguise.

## Additional Impersonation Rules

Using a holoskin or shapeshifting abilities may allow you to disguise in less time, but assuming a new disguise can still take 10 minutes to get into character and practice your mannerisms as this new creature, at the GM''s discretion.  
You can use this skill to pretend to be someone else on the infosphere, but without a hacking toolkit anyone can use the Hack action to uncover your identity without having to compare it to your Computers DC.',	NULL,	'Concentratem Exploration, Manipulate, Secret'),
('actShove',	'Shove',	'[one-action]',	'You have at least one hand free. The target can''t be more than one size larger than you.',	NULL,	'You push a creature away from you. Attempt an Athletics check against your target''s Fortitude DC.

<b>Critical Success</b> You push your target up to 10 feet away from you. You can Stride after it, but you must move the same distance and in the same direction.<br><b>Success</b> You push your target back 5 feet. You can Stride after it, but you must move the same distance and in the same direction.<br><b>Critical Failure</b> You lose your balance, fall, and land prone.',	NULL,	'Attack'),
('actSqueeze',	'Squeeze',	NULL,	NULL,	NULL,	'You contort yourself to squeeze through a space so small you can barely fit through. This action is for exceptionally small spaces; many tight spaces are difficult terrain that you can move through more quickly and without a check.

<b>Critical Success</b> You squeeze through the tight space in 1 minute per 10 feet of squeezing.<br><b>Success</b> You squeeze through in 1 minute per 5 feet.<br><b>Critical Failure</b> You become stuck in the tight space. While you''re stuck, you can spend 1 minute attempting another Acrobatics check at the same DC. Any result on that check other than a critical failure causes you to become unstuck.

## Sample Squeeze Tasks

<b>Trained</b> space barely fitting your shoulders<br><b>Master</b> space barely fitting your head',	NULL,	'Exploration, Move'),
('actTumbleThrough',	'Tumble Through',	'[one-action]',	NULL,	NULL,	'You Stride up to your Speed. During this movement, you can try to move through the space of one enemy. Attempt an Acrobatics check against the enemy''s Reflex DC as soon as you try to enter its space. You can Tumble Through using Climb, Fly, Swim, or another action instead of Stride in the appropriate environment.

<b>Success</b> You move through the enemy''s space, treating the squares in its space as difficult terrain (every 5 feet costs 10 feet of movement). If you don''t have enough Speed to move all the way through its space, you get the same effect as a failure.<br><b>Failure</b> Your movement ends, and you trigger reactions as if you had moved out of the square you started in.',	NULL,	'Move'),
('actBalance',	'Balance',	'[one-action]',	'You are in a square that contains a narrow surface, uneven ground, or another similar feature.',	NULL,	'You move across a narrow surface or uneven ground, attempting an Acrobatics check against its Balance DC. You are off-guard while on a narrow surface or uneven ground.

<b>Critical Success</b> You move up to your Speed.<br><b>Success</b> You move up to your Speed, treating it as difficult terrain (every 5 feet costs 10 feet of movement).<br><b>Failure</b> You must remain stationary to keep your balance (wasting the action) or you fall. If you fall, your turn ends.<br><b>Critical Failure</b> You fall and your turn ends.

## Sample Balance Tasks

<b>Untrained</b> tangled cables, narrow catwalk<br><b>Trained</b> steel beam<br><b>Expert</b> skyscraper ledge<br><b>Master</b> taut cable, smooth sheet of ice<br><b>Legendary</b> razor’s edge, asteroids falling midair',	NULL,	'Move'),
('actForceOpen',	'Force Open',	'[one-action]',	NULL,	NULL,	'Using your body, a lever, or some other tool, you attempt to forcefully open a door, window, container, or heavy gate. With a high enough result, you can even smash through walls. Without a crowbar, prying something open takes a –2 item penalty to the Athletics check to Force Open.

<b>Critical Success</b> You open the door, window, container, or gate and can avoid damaging it in the process.<br><b>Success</b> You break the door, window, container, or gate open, and it gains the broken condition. If it''s especially sturdy, the GM might have it take damage but not be broken.<br><b>Critical Failure</b> Your attempt jams the door, window, container, or gate shut, imposing a –2 circumstance penalty on future attempts to Force it Open.

## Sample Force Open Tasks

<b>Untrained</b> fabric, flimsy glass<br><b>Trained</b> ice, sturdy glass<br><b>Expert</b> flimsy wooden door or barricade<br><b>Master</b> sturdy wooden door or basic plastic, iron gate, metal bar<br><b>Legendary</b> airlock or reinforced metal door',	NULL,	'Attack'),
('actLeap',	'Leap',	'[one-action]',	NULL,	NULL,	'You take a short horizontal or vertical jump. Jumping a greater distance requires using the Athletics skill for a High Jump or Long Jump.

<b>Horizontal Jump</b> up to 10 feet horizontally if your Speed is at least 15 feet, or up to 15 feet horizontally if your Speed is at least 30 feet. You land in the space where your Leap ends (meaning you can typically clear a 5-foot gap, or a 10-foot gap if your Speed is 30 feet or more). You can''t make a horizontal Leap if your Speed is less than 15 feet.<br><b>Vertical Jump</b> up to 3 feet vertically and 5 feet horizontally onto an elevated surface.',	NULL,	'Move'),
('actLongJump',	'Long Jump',	'[two-actions]',	NULL,	NULL,	'You Stride, then attempt a DC 15 Athletics check to make a long jump in the direction you were Striding. If you didn''t Stride at least 10 feet, you automatically fail your check. The GM might increase or decrease this DC depending on the situation.

<b>Success</b> You Leap up to a distance equal to your check result rounded down to the nearest 5 feet. You can''t jump farther than your land Speed.<br><b>Failure</b> You make a normal horizontal Leap.<br><b>Critical Failure</b> You make a normal horizontal Leap, then fall and land prone.

## Leap

The Leap basic action is used for High Jump and Long Jump. A horizontal Leap lets you jump up to 10 feet horizontally if your Speed is at least 15 feet, or up to 15 feet horizontally if your Speed is at least 30 feet. You land in the space where your Leap ends (meaning you can typically clear a 5-foot gap if your Speed is between 15 feet and 30 feet, or a 10-foot gap if your Speed is 30 feet or more). A vertical Leap lets you jump up to 3 feet vertically and 5 feet horizontally onto an elevated surface.',	NULL,	'Move'),
('actSwim',	'Swim',	'[one-action]',	NULL,	NULL,	'You attempt an Athletics check to move a maximum distance of 10 feet through water. The GM determines the DC based on the turbulence or danger of the water; in most instances of calm water, you get an automatic critical success. If your land Speed is 40 feet or higher, increase the maximum possible distance by 5 feet for every 20 feet of Speed above 20 feet.  
If you end your turn in water and haven''t succeeded at a Swim action that turn, you sink 10 feet or get moved by the current, as determined by the GM. This doesn''t apply if your last action on your turn was to enter the water.

<b>Critical Success</b> You move through the water, increasing the maximum distance by 5 feet.<br><b>Success</b> You move through the water.<br><b>Critical Failure</b> You make no progress. If you''re holding your breath, you lose 1 round of air.',	NULL,	'Move'),
('actGatherInformation',	'Gather Information',	NULL,	NULL,	NULL,	'You canvass local markets, taverns, and gathering places in an attempt to learn about a specific individual or topic. The GM determines the DC of the check and the amount of time it takes (typically 2 hours, but sometimes more), along with any benefit you might be able to gain by spending credits on bribes, drinks, or gifts.

<b>Success</b> You collect information about the individual or topic. The GM determines the specifics.<br><b>Critical Failure</b> You collect incorrect information about the individual or topic.

## Sample Gather Information Tasks

<b>Untrained</b> talk of the town<br><b>Trained</b> common rumor<br><b>Expert</b> obscure rumor, poorly guarded secret<br><b>Master</b> well-guarded or esoteric information<br><b>Legendary</b> information known only to an incredibly select few, or only to extraordinary beings',	NULL,	'Exploration, Secret'),
('actPerform',	'Perform',	'[one-action]',	NULL,	NULL,	'When making a brief performance—one song, a quick dance, or a few jokes—you use the Perform action. This action is most useful when you want to prove your capability or impress someone quickly. Performing rarely has an impact on its own, but it might influence the DCs of subsequent Diplomacy checks against the observers, or even change their attitudes if the GM sees fit.

<b>Critical Success</b> Your performance impresses the observers, and they''re likely to share stories of your ability.<br><b>Success</b> You prove yourself, and observers appreciate the quality of your performance.<br><b>Failure</b> Your performance falls flat.<br><b>Critical Failure</b> You demonstrate only incompetence.

## Sample Perform Tasks

<b>Untrained</b> casual audience<br><b>Trained</b> audience of corporate professionals<br><b>Expert</b> audience of wealthy influencers<br><b>Master</b> audience of discerning industry pros<br><b>Legendary</b> audience of planetary leaders

## Online Presence

Performing online can attract the attention of entire civilizations across an infosphere, propelling your character to untold heights of stardom. However, infosphere users can develop dramatically different opinions of a performer, and once you post a performance, your career can change or sour in a day without you spending a downtime activity to monitor it.',	NULL,	'Concentrate'),
('actStunt',	'Stunt',	'[one-action]',	NULL,	NULL,	'You perform a stunt while Driving your vehicle, temporarily improving its effective capabilities at the risk of losing control. Drive your vehicle and choose a stunt. All Piloting checks attempted as part of your Stunt receive the listed penalty, including Piloting checks made to take a reckless action. If the Drive action and Stunt are both reckless, you must attempt the Piloting check to keep control of the vehicle twice.

