('aftIntuitiveGeometry',	'ancCerean',	'Intuitive Geometry',	'You perceive the world as a grid of angles and potential movements. You can use your Intelligence modifier instead of your Wisdom modifier for Perception checks to determine Initiative.',	'{"perception": {"conditional_bonus": [{"name": "Intuitive Geometry", "value": "substitute INT for WIS (+{int - wis}) for initiative.", "target": "all"}]}}',	'You perceive the world as a grid of angles and potential movements.',	'0',	1,	'Cerean',	NULL),
('aftTuskenWeaponFamiliarity',	'ancTusken',	'Tusken Weapon Familiarity',	'You have trained since childhood with the traditional weapons of your clans. You have familiarity with weapons with the Tusken Raider trait including the gaffi stick (garderffi) and cycler rifle. For the purpose of proficiency, you treat any of these that are martial weapons as simple weapons and any that are advanced weapons as martial weapons.

At 5th level, whenever you get a critical hit with one of these weapons, you get its critical specialization effect.',	'{"attack": [{"weapon_familiarity": ["Tusken Raider"]}]}',	'You have trained since childhood with the traditional weapons of your clans.',	'0',	1,	'Tusken Raider',	NULL),
('aftHardenedHorns',	'ancIktotchi',	'Hardened Horns',	'Your horn attack gains the Forceful trait and deals 1d8 damage instead of 1d6.',	'{"weapon": [{"id": "natCranial Ram", "bulk": null, "name": "Iktotchi Horns", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Forceful, Shove", "category": "Unarmed", "damagedie": "d8", "damagetype": "P", "description": "Your heavy, downward-curving horns are a natural weapon. You gain a horn unarmed attack that deals 1d6 piercing damage. It has the Shove trait, allowing you to Shove enemies even if your hands are full.<br><br>Your horn attack gains the Forceful trait and deals 1d8 damage instead of 1d6."}]}',	'Your horn attack gains the Forceful trait and deals 1d8 damage instead of 1d6.',	'0',	5,	'Iktotchi',	'[{"feat": {"id": "aftCranialRam", "type": "ancestry"}}]'),
('aftUltrasonicSensitivity',	'ancCodruJi',	'Ultrasonic Sensitivity',	'Your ears are tuned to frequencies far above the range of most sapient species.

You can hear the high-pitch whine of active power cells, repulsorlifts, and servo-motors. You gain a +2 circumstance bonus to Perception checks to Seek creatures or objects that have the Tech or Construct trait, or creatures wielding active technological weapons (like blasters or vibro-blades).

You can speak and hear in the ultrasonic register. You can communicate secretly with other creatures who possess this feat (or have ultrasonic sensors) at a range of up to 60 feet. To anyone without this ability, you appear to be silent.',	'{"perception": {"conditional_bonus": [{"name": "Ultrasonic Sensitivity", "value": "+2 circumstance bonus to Perception checks to Seek Tech or Construct creatures, or creatures wielding technological weapons.", "target": "all"}]}}',	'Your ears are tuned to frequencies far above the range of most sapient species.',	'0',	1,	'Codru-Ji, Auditory',	NULL),
('aftEmergencyRepairProtocol',	'ancDroid',	'Emergency Repair Protocol',	'You can use the Crafting skill to Repair yourself as a 2-action activity without needing a repair kit.  The DC for the Crafting check and the healing delivered are the same as if using the Medicine skill to Treat Wounds, but this action does not count as any other form of healing for the purpose of ability immunity timers.

<div class="power-card-display">
