('aftJaggedClaws',	'ancTrandoshan',	'Jagged Claws',	'You possess sharp, retractable claws. You gain a claw unarmed attack that deals 1d4 slashing damage. It has the Agile and Finesse traits.',	'{"weapon": [{"id": "natTrandoshanClaws", "bulk": null, "name": "Trandoshan Claws", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Agile, Finesse", "category": "Unarmed", "damagedie": "d4", "damagetype": "P/S", "description": "You possess sharp, retractable claws. You gain a claw unarmed attack that deals 1d4 slashing damage. It has the Agile and Finesse traits."}]}',	'You possess sharp, retractable claws.',	'0',	1,	'Trandoshan',	NULL),
('aftBinaryProcessing',	'ancCerean',	'Binary Processing',	'Your brain is divided into two independent lobes, allowing you to process information continuously. You gain the Dubious Knowledge skill feat. Furthermore, when you attempt a check to Recall Knowledge, if you roll a Critical Failure, you get a Failure instead (you realize you don''t know, rather than recalling false information).',	'{"feat": {"fixed": [{"id": "feaDubiousKnowledge", "type": "skill"}]}}',	'Your brain is divided into two independent lobes, allowing you to process information continuously.',	'0',	1,	'Cerean, Mental',	NULL),
('aftShakeItOff',	'ancGamorrean',	'Shake It Off',	'You grunt, slap your face, and force your body to focus.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Shake It Off</h3>
