('aftOrdMantellianUnderdog',	'ancSavrip',	'Ord Mantellian Underdog',	'You are entirely used to smaller, heavily armed creatures trying to kite you or ambush you. You gain a +1 circumstance bonus to AC against reactions triggered by your movement (such as Attacks of Opportunity).',	'{"ac": {"conditional_bonus": [{"name": "Ord Mantellian Underdog", "value": "+1 circumstance bonus against reactions triggered by your movement.", "target": "ac"}]}}',	'You are entirely used to smaller, heavily armed creatures trying to kite you or ambush you.',	'0',	5,	'Mantellian Savrip',	NULL),
