('aftSensoryOverdrive',	'ancChubbit',	'Sensory Overdrive',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Sensory Overdrive</h3>
      <span class="power-action-cost">[reaction]</span>
