('aftWrathOfTheSands',	'ancTusken',	'Wrath of the Sands',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Wrath of the Sands</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Tusken Raider</span>
    <span class="trait-tag">Flourish</span>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You become a terrifying blur of movement and violence. You Stride up to your Speed. At any point during this movement, you can make two melee Strikes against one or two different targets. These Strikes apply your multiple attack penalty normally, but you do not increase your penalty until both Strikes are completed.
  </div>
</div>',	'{"action": {"grant": [{"id": "actWrathOfTheSands", "name": "Wrath of the Sands", "traits": "Tusken Raider, Flourish", "action_cost": "[two-actions]", "description": "You become a terrifying blur of movement and violence. You Stride up to your Speed. At any point during this movement, you can make two melee Strikes against one or two different targets. These Strikes apply your multiple attack penalty normally, but you do not increase your penalty until both Strikes are completed."}]}}',	'You become a terrifying blur of movement and violence.',	'0',	17,	'Tusken Raider, Flourish',	NULL),
('aftDontShoot',	'ancDroid',	'Don''t Shoot!',	'<p>You are programmed for pacifism.</p>
<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Control Machine</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 13</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Anzellan</span>
    <span class="trait-tag">Concentrate</span>
    <span class="trait-tag">Incapacitation</span>
    <span class="trait-tag">Manipulate</span>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You take control of a technological creature or object and command it remotely.  One unintelligent Construct creature (or a non-creature technological object) must roll a Will save against your class DC.  You can only have one creature controlled this way.<br><br><strong>Critical Success</strong> The target is stunned 1 as it fights off your commands.<br><strong>Success</strong> You control the target. It gains the controlled condition, but it can attempt a Will save at the end of each of its turns. On a success, the spell ends.<br><strong>Failure</strong> As a success, but the target receives a new save only if it&#39;s sapient and you give it a new order that&#39;s against its nature, such as killing its allies.<br><strong>Critical Failure</strong> You control the target indefinitely, and it only receives new saves when you make your daily preparations.
  </div>
</div>',	'{"action": {"grant": [{"id": "actDontShoot", "name": "Don''t Shoot!", "traits": "Droid", "action_cost": "[one-action]", "description": "You assume a non-threatening posture.  Until the start of your next turn, enemies must succeed at a Will save against your class DC in order to target you with an attack. Taking any hostile action ends this effect immediately and prevents its use for an hour.", "requirements": "You have not taken a hostile action this turn."}]}}',	'You are programmed for pacifism.',	'0',	5,	'Droid',	'[{"heritage": "herDroidClass3"}]'),
('aftHyperReactiveSynapses',	'ancChubbit',	'Hyper-Reactive Synapses',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Hyper-Reactive Synapses</h3>
      <span class="power-action-cost">[free-action]</span>
