('aftJuryRiggedDefense',	'ancSquib',	'Jury-Rigged Defense',	'<p>You can slap together a shield from nearby debris in seconds. By spending a single Interact action and passing a DC 15 Crafting check, you can turn a loose object of Light or 1 Bulk (a plate, a datapad, a piece of hull) into a temporary Shield (Hardness 3, HP 12, BT 6). It functions as a buckler or wooden shield until the end of the encounter or until it breaks, at which point it returns to being junk.</p>
<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Jury-Rigged Defense</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 5</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Squib</span>
    <span class="trait-tag">Manipulate</span>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You can slap together a shield from nearby debris in seconds. You Interact with a loose object of Light or 1 Bulk (a plate, a datapad, a piece of hull) and attempt a Crafting check.<br><br><strong>Success</strong> You turn the objects into a temporary Shield (Hardness 3, HP 12, BT 6). It functions as a buckler or wooden shield until the end of the encounter or until it breaks, at which point it returns to being junk.
  </div>
</div>',	'{"action": {"grant": [{"id": "actJuryRiggedDefense", "name": "Jury-Rigged Defense", "traits": "Squib, Manipulate", "action_cost": "[one-action]", "description": "You can slap together a shield from nearby debris in seconds. You Interact with a loose object of Light or 1 Bulk (a plate, a datapad, a piece of hull) and attempt a Crafting check.\n\n**Success** You turn the objects into a temporary Shield (Hardness 3, HP 12, BT 6). It functions as a buckler or wooden shield until the end of the encounter or until it breaks, at which point it returns to being junk."}]}}',	'You can slap together a shield from nearby debris in seconds.',	'0',	5,	'Manipulate, Squib',	'[{"skill": [{"id": "sklCrafting", "rank": "Trained"}]}]'),
('aftRegenerativeStimulation',	'ancTrandoshan',	'Regenerative Stimulation',	'<div class="power-card-display">
  <header class="power-card-header">
