('aftClanGuardian',	'ancGamorrean',	'Clan Guardian',	'You are expert at intercepting attacks meant for your boss.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Interpose</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 9</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Gamorrean</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>An adjacent ally is hit by a physical attack.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You switch places with the ally (if they are willing) and take the hit instead. You take the damage the ally would have taken, though you can apply your own Resistances or Reactions (like Pain is Weakness) to it.
  </div>
</div>',	'{"action": {"grant": [{"id": "actInterpose", "name": "Interpose", "traits": "Gamorrean", "trigger": "An adjacent ally is hit by a physical attack.", "action_cost": "[reaction]", "description": "You switch places with the ally (if they are willing) and take the hit instead. You take the damage the ally would have taken, though you can apply your own Resistances or Reactions (like Pain is Weakness) to it."}]}}',	'You are expert at intercepting attacks meant for your boss.',	'0',	9,	'Gamorrean',	'[{"feat": [{"id": "aftLivingShield", "type": "ancestry"}]}]'),
('aftWarlordsRoar',	'ancGamorrean',	'Warlord''s Roar',	'<p>You bellow with the authority of a Clan Matriarch.</p>
<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Warlord&#39;s Roar</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 17</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Gamorrean</span>
    <span class="trait-tag">Auditory</span>
    <span class="trait-tag">Emotion</span>
    <span class="trait-tag">Fear</span>
    <span class="trait-tag">Mental</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Frequency</strong>
      <span>Once per minute.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You bellow with the authority of a Clan Matriarch. All enemies within 30 feet must make a Will save against your Class DC.<br><br><strong>Critical Success</strong> Target is unaffected.<br><strong>Success</strong> Target is Frightened 1.<br><strong>Failure</strong> Target is Frightened 2 and Stunned 1.<br><strong>Critical Failure</strong> Target is Frightened 3 and Fleeing for 1 round.
  </div>
</div>',	'{"action": {"grant": [{"id": "actWarlordsRoar", "name": "Warlord''s Roar", "traits": "Gamorrean, Auditory, Emotion, Fear, Mental", "frequency": "Once per minute.", "action_cost": "[one-action]", "description": "You bellow with the authority of a Clan Matriarch. All enemies within 30 feet must make a Will save against your Class DC.\n\n**Critical Success** Target is unaffected.\n**Success** Target is Frightened 1.\n**Failure** Target is Frightened 2 and Stunned 1.\n**Critical Failure** Target is Frightened 3 and Fleeing for 1 round."}]}}',	'You bellow with the authority of a Clan Matriarch.',	'0',	17,	'Gamorrean, Auditory, Emotion, Fear, Mental',	'[{"feat": [{"id": "aftMuscularMenace", "type": "ancestry"}]}]');

DROP TABLE IF EXISTS "Archetype";
CREATE TABLE "public"."Archetype" (
    "ArchetypeID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Description" text,
    "Summary" character varying,
    CONSTRAINT "Archetype_pkey" PRIMARY KEY ("ArchetypeID")
)
WITH (oids = false);

INSERT INTO "Archetype" ("ArchetypeID", "Name", "Description", "Summary") VALUES
('arcBountyHunter',	'Bounty Hunter',	'Whether for credits, glory, or justice, you know how to track, defeat, and capture dangerous individuals. You''re accustomed to perusing wanted posters, following up on leads, and pursuing your quarry to hell and back. Once you locate your prey''s trail, you''re unshakable. Additionally, you have the skills and experience to subdue even the most troublesome mark and bring them in to secure your reward.',	NULL),
('arcScout',	'Scout',	'You''re an expert in espionage and reconnaissance, able to skulk silently through the wilderness to gather intelligence, sneak through enemy lines and report back to your comrades, or suddenly and decisively take down your foes. Your skills ease the difficulty of travel for you and your companions and keep you all alert to approaching danger. It''s not just enemies that you scout out; you also survey the land. You''re able to discover the easiest routes as safely as possible and remain watchful while moving with speed and subtlety. The responsibility of the party''s safe passage depends on you performing your scouting duties with constant and consistent effort. You take pride in your vigilance, and your allies trust your guidance to ensure the safety of everyone traveling.',	NULL),
('arcMedic',	'Medic',	'You''ve studied countless techniques for providing medical aid, making you a peerless doctor and healer. While many healers happily practice the art of medicine in the safety and serenity of stationary buildings, few are in more dire need of medicinal aid than adventurers. Such an occupation comes with frequent injuries that need constant attention. Few parties would ever turn down help from a practicing medic. In fact, the need for medicine is so great that many medics started as adventurers and took up medicine as a necessity. While patching up injuries is the most common practice of medics, they are also invaluable for their ability to help fight diseases and ailments inflicted by all kinds of creatures and traps. The adaptability and utility of the medic are undeniable. Whether you studied medicine for most of your life or picked it up on the road, you are who people turn to for aid.',	NULL),
('arcMandalorian',	'Mandalorian',	'You walk the path of the Mandalore. Honing your body and mind to match the unforgiving metal of your armor, you carry the weight of your culture''s legendary martial history into every battle.',	NULL),
('arcEnvoy',	'Envoy',	'You step up and lead others to victory while manipulating those who stand in your way.',	NULL),
('arcSoldier',	'Soldier',	'You''re a stalwart shield who never stops blasting while protecting your allies from danger, including from your own terrifying destruction.',	NULL),
('arcOperative',	'Operative',	'You’re a professional with crack aim and lethal instincts.',	NULL),
('arcConsular',	'Consular',	'You are a conduit for the cosmic energy known as the Force. While others rely on blasters or brute strength, you rely on the power of your mind and the depth of your connection to the galaxy. ',	NULL),
('arcGuardian',	'Guardian',	'You are the shield of the Order and the hammer of justice.',	NULL),
('arcSentinel',	'Sentinel',	'You are the watcher in the shadows, the investigator of mysteries, and the pragmatic hand of the Order.',	NULL),
('arcDroidCompanion',	'Droid Companion',	'You have acquired, built, or rescued a loyal droid companion that accompanies you on your journeys.',	NULL),
('arcTechSpecialist',	'Tech Specialist',	'You''re a master of machines, code, and jury-rigged miracles. While others rely on ancient religions or brute military force, you know that the true power in the galaxy lies in the hands of those who build, repair, and control its technology. You might be a brilliant slicer infiltrating corporate mainframes, a gritty mechanic keeping a scrap-heap freighter flying, or a combat engineer turning battlefield debris into deadly weapons. You understand the hidden language of circuitry, and you aren''t afraid to push your hardware past its safe operating limits to achieve the impossible.',	NULL),
('arcBeastmaster',	'Beastmaster',	'You possess an unparalleled talent for understanding and taming the galaxy''s diverse fauna. As your expertise in xenobiology and animal handling grows, you can command a larger menagerie of creatures, direct them with subtle cues and specialized training, and coordinate complex tactical maneuvers with your beasts even in the chaos of a firefight.',	NULL);

DROP TABLE IF EXISTS "Armor";
CREATE TABLE "public"."Armor" (
    "ArmorID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Category" character varying NOT NULL,
    "Level" smallint DEFAULT '0',
    "ACBonus" smallint DEFAULT '0',
    "DexCap" smallint,
    "CheckPenalty" smallint DEFAULT '0',
    "SpeedPenalty" smallint DEFAULT '0',
    "MinStrength" smallint DEFAULT '0',
    "Bulk" character varying DEFAULT 'L',
    "Group" character varying,
    "Traits" character varying,
    "Description" text,
    "Features" jsonb,
    "Price" smallint,
    "Upgrades" smallint DEFAULT '0' NOT NULL,
    CONSTRAINT "Armor_ArmorID" PRIMARY KEY ("ArmorID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Armor"."Category" IS 'Light, Medium, Heavy, or Unarmored';

COMMENT ON COLUMN "public"."Armor"."DexCap" IS 'Maximum Dex modifier allowed. NULL = No Cap.';

COMMENT ON COLUMN "public"."Armor"."CheckPenalty" IS 'Penalty to STR/DEX skills (always negative or 0)';

COMMENT ON COLUMN "public"."Armor"."SpeedPenalty" IS 'Penalty to speed in ft (always negative or 0)';

INSERT INTO "Armor" ("ArmorID", "Name", "Category", "Level", "ACBonus", "DexCap", "CheckPenalty", "SpeedPenalty", "MinStrength", "Bulk", "Group", "Traits", "Description", "Features", "Price", "Upgrades") VALUES
('armPoweredAssaultShell',	'Powered Assault Shell',	'Heavy',	1,	6,	0,	-3,	-10,	4,	'4',	'Plate',	'Bulwark, Tech, Powered',	'A fully sealed, servo-assisted suit of heavy durasteel plating. It turns the wearer into a walking tank, immune to small arms fire, but requires immense strength and training to operate effectively.',	NULL,	250,	1),
('armShadowsuit',	'Shadowsuit',	'Light',	1,	2,	3,	-1,	0,	1,	'L',	'Polymer',	'Tech',	'A matte-black body glove designed to dampen sound and reduce thermal signature. Favored by assassins and thieves.',	NULL,	18,	0),
('armPlateCarapace',	'Plate Carapace',	'Medium',	1,	4,	1,	-2,	-5,	2,	'2',	'Plate',	'Tech',	'A solid durasteel chest piece with accompanying greaves and bracers. Offers excellent vital protection while leaving joints exposed for blaster operation.',	NULL,	40,	1),
('armHeavyShockArmor',	'Heavy Shock Armor',	'Heavy',	1,	5,	1,	-3,	-10,	3,	'3',	'Composite',	'Tech',	'Bulky armor used by heavy weapons specialists and shock troopers. It features thick composite plates that can stop high-caliber rounds.',	NULL,	60,	1),
('armFiberMeshUnderlay',	'Fiber-Mesh Underlay',	'Light',	1,	2,	3,	-1,	0,	1,	'1',	'Chain',	'Flexible, Noisy, Tech',	'A mesh of interlocking durafiber rings usually worn under clothing or uniforms. It is effective but tends to rattle during movement.',	NULL,	20,	1),
('armSalvagedDroidPlating',	'Salvaged Droid Plating',	'Heavy',	1,	5,	1,	-3,	-10,	3,	'3',	'Composite',	'Analog',	'Armor cobbled together from the chassis of defunct battle droids. It is heavy and ugly, but the durasteel is battle-tested.',	NULL,	55,	0),
('armBlastVest',	'Blast Vest',	'Light',	1,	1,	4,	-1,	0,	0,	'1',	'Composite',	'Exposed, Tech',	'A thick vest made of treated rancor leather or synthetic weave, designed to absorb the impact of light skirmishes. Common among swoop gangs and cantina bouncers.',	NULL,	3,	1),
('armCeremonialGuardArmor',	'Ceremonial Guard Armor',	'Medium',	1,	4,	1,	-2,	-5,	2,	'2',	'Composite',	'Tech',	'Highly polished plastoid or laminate armor used by planetary security forces. Designed more for intimidation and parade visuals than field mobility.',	NULL,	4,	0),
('armFortifiedVacuumSuit',	'Fortified Vacuum Suit',	'Heavy',	1,	5,	1,	-3,	-10,	3,	'3',	'Plate',	'Tech',	'A heavy-duty spacesuit plated with impact-resistant ceramics. Designed for boarding actions or hazardous zeroes-G work.',	NULL,	75,	0),
('armSpacerFatigues',	'Spacer Fatigues',	'Unarmored',	1,	0,	5,	0,	0,	0,	'L',	'Cloth',	'Comfort, Tech',	'Standard-issue clothing for merchant crews, reinforced with ballistic weave. It looks ordinary but can hold protective enchantments or mod-slots.',	NULL,	2,	0),
('armMercenaryShell',	'Mercenary Shell',	'Medium',	1,	4,	1,	-2,	-5,	2,	'2',	'Plate',	'Tech',	'A mishmash of plates protecting the torso and shoulders, often painted with gang colors or kill marks. Simple, effective, and rugged.',	NULL,	4,	0),
('armMinerExosuit',	'Miner Exosuit',	'Medium',	1,	3,	2,	-2,	-5,	2,	'2',	'Leather',	'Flexible, Tech',	'A rigid suit designed to protect miners from falling rocks and heat. It is heavy and unrefined, but offers decent protection for the price.',	NULL,	12,	0),
('armWarlordBattlePlate',	'Warlord Battle Plate',	'Heavy',	1,	5,	1,	-3,	-10,	3,	'3',	'Plate',	'Bulwark, Tech',	'Masterfully crafted heavy plating often worn by planetary governors or system warlords. It offers superior protection and commands respect.',	NULL,	100,	0),
('armHazardVest',	'Hazard Vest',	'Light',	1,	1,	4,	0,	0,	0,	'L',	'Cloth',	'Comfort, Tech',	'High-visibility protective gear used by dock workers and engineers. It offers minimal protection but is comfortable enough to sleep in.',	NULL,	2,	0),
('armTraditionalRobes',	'Traditional Robes',	'Unarmored',	1,	0,	NULL,	0,	0,	0,	'L',	'Cloth',	'Analog, Comfort, Exposed',	'Loose-fitting woven garments favored by mystics and hermits. While they offer no ballistic protection, the material is high-quality and durable enough to accept protective modifications.',	NULL,	1,	1),
('armHardenedPlating',	'Hardened Plating',	'Heavy',	1,	5,	1,	-3,	-10,	3,	'3',	'Plate',	'Tech',	'An extensive suit of interlocking durasteel plates over a sealed body glove. While not a fully powered servo-suit, it makes the wearer a walking tank.',	NULL,	90,	1),
('armChitinShell',	'Chitin Shell',	'Medium',	1,	3,	2,	-2,	-5,	2,	'2',	'Leather',	'Analog, Exposed',	'Armor crafted from the carapace of native megafauna. While primitive, the natural density of the shell offers surprising resistance to modern weaponry.',	NULL,	8,	0),
('armSecurityRiotShield',	'Security Riot Gear',	'Medium',	1,	4,	1,	-2,	-5,	2,	'2',	'Chain',	'Flexible, Noisy, Tech',	'Heavy impact-resistant padding layered with flex-mesh, designed for crowd control. It absorbs shock well but is cumbersome and loud.',	NULL,	35,	1),
('armCombatJumpsuit',	'Combat Jumpsuit',	'Light',	1,	2,	3,	-1,	0,	1,	'1',	'Leather',	'Comfort, Exposed, Tech',	'A reinforced body glove with composite plating sewn into vital areas. Favored by operatives who need a balance of stealth and protection.',	NULL,	15,	1),
('armFlightSuit',	'Flight Suit',	'Light',	1,	1,	4,	0,	0,	0,	'L',	'Cloth',	'Comfort, Tech',	'A lightweight, insulated jumpsuit worn by pilots and spacers. It offers minimal protection against blaster fire but restricts movement the least.',	NULL,	5,	1),
('armBattleArmor',	'Battle Armor',	'Medium',	1,	4,	1,	-2,	-5,	2,	'2',	'Composite',	'Tech',	'Mass-produced segmented armor plates made of white or grey plastoid. Provides solid protection against kinetic and energy weapons but limits agility.',	NULL,	30,	1),
('armArmoredGreatcoat',	'Armored Greatcoat',	'Light',	1,	1,	4,	-1,	0,	0,	'1',	'Leather',	'Tech, Concealable',	'A heavy leather or synth-hide trench coat lined with ablative mesh. Popular among gunslingers for its style and the ability to hide weapons beneath the folds.',	NULL,	5,	0);

DROP TABLE IF EXISTS "ArmorGrade";
CREATE TABLE "public"."ArmorGrade" (
    "ArmorGradeID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Level" smallint NOT NULL,
    "PriceIncrease" integer NOT NULL,
    "UpgradeIncrease" smallint DEFAULT '0',
    "ACBonus" smallint DEFAULT '0',
    "SaveBonus" smallint DEFAULT '0',
    CONSTRAINT "ArmorGrade_pkey" PRIMARY KEY ("ArmorGradeID")
)
WITH (oids = false);

INSERT INTO "ArmorGrade" ("ArmorGradeID", "Name", "Level", "PriceIncrease", "UpgradeIncrease", "ACBonus", "SaveBonus") VALUES
('argTactical',	'Tactical',	5,	1600,	1,	1,	0),
('argAdvanced',	'Advanced',	8,	3400,	1,	1,	1),
('argSuperior',	'Superior',	11,	9000,	2,	2,	1),
('argElite',	'Elite',	14,	31000,	2,	2,	2),
('argUltimate',	'Ultimate',	18,	195000,	3,	3,	2),
('argParagon',	'Paragon',	20,	460000,	3,	3,	3);

DROP TABLE IF EXISTS "Background";
CREATE TABLE "public"."Background" (
    "BackgroundID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Description" text NOT NULL,
    "Summary" character varying NOT NULL,
    "Features" jsonb,
    CONSTRAINT "Background_BackgroundID" PRIMARY KEY ("BackgroundID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Background"."BackgroundID" IS 'Unique Background ID';

COMMENT ON COLUMN "public"."Background"."Name" IS 'Background Name';

COMMENT ON COLUMN "public"."Background"."Description" IS 'Background description text';

COMMENT ON COLUMN "public"."Background"."Summary" IS 'Background short summary';

INSERT INTO "Background" ("BackgroundID", "Name", "Description", "Summary", "Features") VALUES
('bkgCourier',	'Courier',	'In a galaxy where the HoloNet is monitored, sliced, and censored at every turn, some messages and packages simply must be delivered by hand. You are a runner, entrusted with moving physical data spikes, sensitive intelligence, or high-value contraband across dangerous borders. Whether you relied on a fast swoop bike to navigate the crowded skylanes of a metropolis or a heavily modified light freighter to slip past Imperial blockades, speed and discretion are your lifeblood. Your experiences have given you razor-sharp reflexes, a knack for navigating treacherous routes, and the athletic ability to keep moving when the local authorities are hot on your tail.

Choose two attribute boosts. One must be to Dexterity or Wisdom, and one is a free attribute boost.

You''re trained in the Survival skill, and a Lore skill related to a settlement you''ve worked in.. You gain the Urban Survivalist skill feat.',	'In a galaxy where the HoloNet is monitored, sliced, and censored at every turn, some messages and packages simply must be delivered by hand.',	'{"feat": {"fixed": [{"id": "feaUrbanSurvivalist", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklSurvival", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Settlement Lore Skill", "filter": [{"trait": "Settlement"}]}}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "WIS"]}}}'),
('bkgBartender',	'Bartender',	'You have spent countless rotations wiping down the sticky counter of a bustling cantina, serving up Lum, spotchka, and Corellian ale to a colorful array of smugglers, mercenaries, and moisture farmers. Whether you ran a shady watering hole in the lower levels of Coruscant or poured drinks for nervous Rebel operatives laying low on Ord Mantell, you have mastered the art of listening. You know how to defuse a blaster-drawn standoff with a well-timed word, spot a loaded sabacc deck from across the room, and glean highly classified, galaxy-spanning secrets from patrons who have simply had one drink too many.

Choose two attribute boosts. One must be to Wisdom or Charisma, and one is a free attribute boost.

You''re trained in the Diplomacy skill, and the Alcohol Lore skill. You gain the Seasoned skill feat.',	'You have spent countless rotations wiping down the sticky counter of a bustling cantina, serving up Lum, spotchka, and Corellian ale to a colorful array of smugglers, mercenaries, and moisture farmers.',	'{"feat": {"fixed": [{"id": "feaSeasoned", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklDiplomacy", "rank": "Trained"}, {"id": "sklLoreAlcohol", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["WIS", "CHA"]}}}'),
('bkgGambler',	'Gambler',	'The galaxy is a game of chance, and you intend to win it. You have spent your life in the glittering casinos of Canto Bight, the smoke-filled cantinas of Nar Shaddaa, and the high-stakes VIP lounges of corporate cruisers. Whether you make your living counting cards at the pazaak table, bluffing your way through a cutthroat game of sabacc, or running the odds on illegal swoop races, you rely on a sharp mind and an unreadable expression. You are an expert at calculating risk, reading the subtle tells of your opponents, and knowing exactly when to walk away—or when to double down and bet it all.

Choose two attribute boosts. One must be to Dexterity or Charisma, and one is a free attribute boost.

You''re trained in the Deception skill, and the Gambling Lore skill. You gain the Lie to Me skill feat.',	'The galaxy is a game of chance, and you intend to win it.',	'{"feat": {"fixed": [{"id": "feaLieToMe", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklDeception", "rank": "Trained"}, {"id": "sklLoreGambling", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "CHA"]}}}'),
('bkgLaborer',	'Laborer',	'You are the muscle that builds the galaxy''s grandest projects and moves its heaviest freight. Whether you spent your years hauling bulky cargo containers in the bustling spaceports of Corellia, extracting raw materials in deep-core mines, or riveting hull plating in a sprawling orbital shipyard, your life has been defined by backbreaking physical exertion. You know the value of a hard day''s work and possess a rugged, calloused endurance that most soft-handed Core Worlders can barely comprehend. This life of heavy lifting has given you immense physical strength and a practical understanding of the heavy machinery used to reshape worlds.

Choose two attribute boosts. One must be to Strength or Constitution, and one is a free attribute boost.

You''re trained in the Athletics skill, and the Labor Lore skill. You gain the Hefty Hauler skill feat.',	'You are the muscle that builds the galaxy''s grandest projects and moves its heaviest freight.',	'{"feat": {"fixed": [{"id": "feaHeftyHauler", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklAthletics", "rank": "Trained"}, {"id": "sklLoreLabor", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "CON"]}}}'),
('bkgBountyHunter',	'Bounty Hunter',	'The galaxy is full of people who have a price on their head, and you are the one who collects it. Whether licensed by the Bounty Hunters'' Guild or operating independently on the lawless fringes of the Outer Rim, you make your living tracking down bail jumpers, political dissidents, and dangerous criminals. You are fluent in the language of chain codes, tracking fobs, and shady underworld contacts. This dangerous profession requires a cold, pragmatic approach to the galaxy, leaving you with a talent for intimidation, survival instincts honed in hostile environments, and an unwavering focus on the target—and the payout.

Choose two attribute boosts. One must be to Strength or Constitution, and one is a free attribute boost.

You''re trained in the Survival skill, and the Underworld Lore skill. You gain the Experienced Tracker skill feat.',	'The galaxy is full of people who have a price on their head, and you are the one who collects it.',	'{"feat": {"fixed": [{"id": "feaExperiencedTracker", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklSurvival", "rank": "Trained"}, {"id": "sklLoreUnderworld", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "CON"]}}}'),
('bkgRecruit',	'Recruit',	'You enlisted—or were perhaps conscripted—into one of the galaxy''s many armed forces, trading your civilian life for a uniform, a standard-issue blaster, and the chain of command. You might have survived the grueling, standardized boot camps of the Imperial Academy, volunteered for a local planetary defense force, or joined the desperate, scrappy struggle of the Rebel Alliance. Regardless of whose banner you served under, basic training drilled discipline, camaraderie, and essential tactical skills into your core. You know how to follow orders, maintain your gear in the field, and keep your head down when the blaster bolts start flying.

Choose two attribute boosts. One must be to Strength or Constitution, and one is a free attribute boost.

You''re trained in the Survival skill, and the Warfare Lore skill. You gain the Terrain Expertise skill feat.',	'You enlisted—or were perhaps conscripted—into one of the galaxy''s many armed forces, trading your civilian life for a uniform, a standard-issue blaster, and the chain of command.',	'{"feat": {"fixed": [{"id": "feaTerrainExpertise", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklSurvival", "rank": "Trained"}, {"id": "sklLoreWarfare", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "CON"]}}}'),
('bkgSpacer',	'Spacer',	'The vibration of deck plates under your boots is the closest thing you have ever known to solid ground. You are a creature of the hyperlanes, raised hopping from spaceport to spaceport and trading standard days for parsecs. You know how to coax a few more lightyears out of a failing hyperdrive motivator, how to talk your way past a suspicious planetary customs patrol, and which orbital docking bays offer the cheapest refueling rates. For you, the galaxy isn''t a collection of grand political struggles; it''s an endless web of trade routes, cargo manifests, and the comforting hum of sublight engines.

Choose two attribute boosts. One must be to Dexterity or Constitution, and one is a free attribute boost.

You''re trained in the Piloting skill, and the Hyperspace Lore skill. You gain the Express Driver skill feat.',	'The vibration of deck plates under your boots is the closest thing you have ever known to solid ground.',	'{"feat": {"fixed": [{"id": "feaExpressDriver", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklPiloting", "rank": "Trained"}, {"id": "sklLoreHyperspace", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "CON"]}}}'),
('bkgPrisoner',	'Prisoner',	'You spent agonizing years locked away in the galaxy''s most brutal penal systems. Whether you were unjustly thrown into the sun-scorched labor camps of Wobani, forced to mine raw spice in the pitch-black depths of Kessel, or held in a high-security Imperial detention block, your freedom was entirely stripped from you. Surviving incarceration required a hardened mind, an iron will, and a pragmatic understanding of shifting alliances among both guards and inmates. Though you have finally broken your chains or served your time, you carry the heavy, unseen scars of a life spent behind ray shields, leaving you with an intense appreciation for freedom and the survival instincts of a cornered Loth-cat.

Choose two attribute boosts. One must be to Strength or Constitution, and one is a free attribute boost.

You''re trained in the Stealth skill, and the Underworld Lore skill. You gain the Experienced Smuggler skill feat.',	'You spent agonizing years locked away in the galaxy''s most brutal penal systems.',	'{"feat": {"fixed": [{"id": "feaExperiencedSmuggler", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklLoreUnderworld", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "CON"]}}}'),
('bkgDroidTechnician',	'Droid Technician',	'Droids are the invisible, ticking lifeblood of the galaxy, and you are one of the few who truly understands how they think. You might have operated a dust-choked droid repair shop on Tatooine, served as a specialized astromech handler in a starfighter squadron, or reprogrammed stolen security droids for a local syndicate. You are fluent in binary, comfortable with a hydrospanner in hand, and intimately familiar with the quirks of heuristic processors. You see droids not just as simple appliances, but as complex puzzles of wiring, motivators, and logic gates that you can coax, repair, or completely rewrite to suit your needs.

Choose two attribute boosts. One must be to Dexterity or Intelligence, and one is a free attribute boost.

You''re trained in the Crafting skill and the Droidtech Lore skill.  You gain the Combat Repair skill feat.',	'Droids are the invisible, ticking lifeblood of the galaxy, and you are one of the few who truly understands how they think.',	'{"feat": {"fixed": [{"id": "feaCombatRepair", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}, {"id": "sklLoreDroidtech", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "INT"]}}}'),
('bkgDathomirWitch',	'Dathomir Witch',	'You are a part of one of the many Force-sensitive clans on Dathomir. You and your sisters, under the guidance of the Clan Mother, form powerful connections with one another and the untamed wilds of the planet. Your people are a matriarchal society of warriors who train in the art of war and the usage of both muscle and the Force in combat.

Choose two attribute boosts. One must be to Strength or Wisdom, and one is a free attribute boost.

You''re trained in The Force and the Dathomir Lore skill.  You gain the Force Sensitive skill feat.',	'You are a part of one of the many Force-sensitive clans on Dathomir. You and your sisters, under the guidance of the Clan Mother, form powerful connections with one another and the untamed wilds of the planet. Your people are a matriarchal society of warriors who train in the art of war and the usage of both muscle and the Force in combat.',	'{"feat": {"fixed": [{"id": "feaForceSensitive", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}, {"id": "sklLoreDathomir", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "WIS"]}}}'),
('bkgFringer',	'Fringer',	'You have spent your life on the edge of the galaxy''s map, carving out an existence in the lawless expanse of the Outer Rim or the uncharted territories of Wild Space. Far from the polished bureaucracy of the Core Worlds, you learned to survive where the authorities either don''t care or actively make things worse. Whether you were a homesteader on a volatile moon, a drifter jumping between shadowports, or a scout navigating treacherous asteroid fields, your survival relied entirely on your own wits. You know how to live off the grid, stretch meager resources, and spot trouble long before it crosses your threshold.

Choose two attribute boosts. One must be to Dexterity or Intelligence, and one is a free attribute boost.

You are trained in the Crafting skill and the Salvage Lore skill.  You gain the Quick Repair skill feat.',	'You have spent your life on the edge of the galaxy''s map, carving out an existence in the lawless expanse of the Outer Rim or the uncharted territories of Wild Space.',	'{"feat": {"fixed": [{"id": "feaQuickRepair", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}, {"id": "sklLoreSalvage", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "INT"]}}}'),
('bkgSlicer',	'Slicer',	'You are a master of the digital underworld, fluent in the complex, layered code that regulates the galaxy''s sprawling networks. Whether you spent your time cracking Imperial databanks for the Rebellion, siphoning untraceable fractions of credits from corporate accounts in the Core Worlds, or bypassing the heavy security grids of Hutt crime lords, your weapon of choice is a custom datapad and a pocket full of data spikes. You view firewalls, encryption protocols, and security cameras as puzzles meant to be solved, possessing the technical genius and sheer audacity required to manipulate the galaxy''s most secure systems from the shadows of a cantina booth.

Choose two attribute boosts. One must be to Dexterity or Intelligence, and one is a free attribute boost.

You''re trained in the Computers skill, and the Slicing Lore skill. You gain the Digital Diversion skill feat.',	'You are a master of the digital underworld, fluent in the complex, layered code that regulates the galaxy''s sprawling networks.',	'{"feat": {"fixed": [{"id": "feaDigitalDiversion", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklComputers", "rank": "Trained"}, {"id": "sklLoreSlicing", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "INT"]}}}'),
('bkgHoloNetTechnician',	'HoloNet Technician',	'You are the vital link that keeps a sprawling, fragmented galaxy connected. Whether you spent your cycles maintaining massive orbital HoloNet transceivers, laying sub-surface fiber lines in the depths of Coruscant, or illegally splicing local communication towers for an Outer Rim syndicate, you understand the invisible web of data that binds star systems together. Your work requires a sharp mind, an intricate knowledge of routing protocols, and the technical prowess to bypass heavily encrypted channels. While others see the galaxy as a collection of physical planets, you see it as a ceaseless, manipulable stream of frequencies, bandwidth, and signal relays.

Choose two attribute boosts. One must be to Intelligence or Wisdom, and one is a free attribute boost.

You''re trained in the Computers skill, and the HoloNet Lore skill. You gain the Hologram Skeptic skill feat.',	'You are the vital link that keeps a sprawling, fragmented galaxy connected.',	'{"feat": {"fixed": [{"id": "feaHologramSkeptic", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklComputers", "rank": "Trained"}, {"id": "sklLoreHoloNet", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["INT", "WIS"]}}}'),
('bkgPickpocket',	'Pickpocket',	'You survived the unforgiving lower levels of the galaxy''s sprawling ecumenopolises by lifting what you needed from those who wouldn''t miss it. Whether you were a desperate street urchin dodging local authorities on Lothal, a nimble grifter working the bustling transit hubs of Coruscant, or a slick thief lifting cred-sticks and code cylinders in the casinos of Canto Bight, your hands are quicker than the eye. You have a keen sense for the ebb and flow of a crowd, an eye for easy marks, and the split-second reflexes needed to disappear into the neon-lit alleys the moment someone realizes their pockets are empty.

Choose two attribute boosts. One must be to Dexterity or Intelligence, and one is a free attribute boost.

You''re trained in the Thievery skill, and the Underworld Lore skill. You gain the Pickpocket skill feat.',	'You survived the unforgiving lower levels of the galaxy''s sprawling ecumenopolises by lifting what you needed from those who wouldn''t miss it. ',	'{"feat": {"fixed": [{"id": "feaPickpocket", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklThievery", "rank": "Trained"}, {"id": "sklLoreUnderworld", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "INT"]}}}'),
('bkgCloneEngineer',	'Clone Engineer',	'You are a specialist in the complex and highly guarded science of genetic replication. Whether you honed your craft in the sterile, storm-battered facilities of Kamino, worked within a classified Imperial science division, or operated a black-market medical lab in the Outer Rim, your life''s work has been the design, decanting, and maintenance of biological life. You intimately understand the intricate processes of growth acceleration, behavioral modification, and flash-training regimens. Though you have stepped away from the glowing amber of the cloning cylinders, your deep, clinical knowledge of anatomy, genetics, and biotechnology makes you an unparalleled asset when it comes to keeping your allies functioning—or dismantling your enemies with surgical precision.

Choose two attribute boosts. One must be to Intelligence or Wisdom, and one is a free attribute boost.

You''re trained in the Medicine skill and the Genetic Engineering Lore skill.  You gain the Experienced Professional skill feat.',	'You are a specialist in the complex and highly guarded science of genetic replication.',	'{"feat": {"fixed": [{"id": "feaExperiencedProfessional", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklMedicine", "rank": "Trained"}, {"id": "sklLoreGeneticEngineering", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["INT", "WIS"]}}}'),
('bkgNoble',	'Noble',	'You were born into privilege and power, raised among the elite of the galaxy. Whether your bloodline ties you to the planetary monarchs of worlds like Alderaan or Naboo, or you belong to a wealthy corporate dynasty operating out of the bustling Core Worlds, you were groomed for leadership and high society from an early age. Your upbringing was defined by political tutoring, strict etiquette, and the finest education credits could buy. Though you have traded the safety of your estate for the unpredictable life of an adventurer, you still carry the poise, diplomatic connections, and perhaps the heavy expectations of your family''s legacy.

Choose two attribute boosts.  One must be to Intelligence or Charisma, and one is a free attribute boost.

You''re trained in the Society skill and a Lore skill related to your home planet.  You gain the Courtly Graces skill feat.',	'You were born into privilege and power, raised among the elite of the galaxy.',	'{"feat": {"fixed": [{"id": "feaCourtlyGraces", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklDiplomacy", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Planet Lore", "filter": [{"trait": "Planet"}]}}, "attribute": {"boost": {"free": 1, "choice": ["INT", "CHA"]}}}'),
('bkgWardenOfTheSky',	'Warden of the Sky',	'You are an ascetic protector of the spacelanes, wandering the galaxy''s hyperlanes to safeguard travelers from pirates, marauders, and cosmic hazards. Unlike the Jedi, you do not rely on lightsabers or grand temples; instead, you trust your martial discipline, your attunement to the cosmic flow, and the subtle guidance of the Force to keep the stars safe. Your life hitching rides aboard freighters and transports has made you intimately familiar with the intricacies of deep space travel, and your connection to the energy fields of the galaxy allows you to sense danger long before the proximity alarms begin to chime.

Choose two attribute boosts. One must be Dexterity or Wisdom, and one is a free attribute boost.

You are trained in The Force and in the Spacer Lore skill.  You gain the Force Sensitive skill feat.',	'You are an ascetic protector of the spacelanes, wandering the galaxy''s hyperlanes to safeguard travelers from pirates, marauders, and cosmic hazards.',	'{"feat": {"fixed": [{"id": "feaForceSensitive", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}, {"id": "sklLoreSpacer", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "CHA"]}}}'),
('bkgTempleYoungling',	'Temple Youngling',	'You were brought to the tranquil, echoing halls of the Jedi Temple at a very young age, trading a family you barely remember for the strict, monastic life of an initiate. Under the watchful eyes of wise masters, your childhood was spent mastering meditation, practicing basic lightsaber forms, and learning to sense and manipulate the fundamental flows of the Force. Your early trials and lessons were carefully designed to guide you toward your ultimate destiny within the Order—whether navigating the galaxy as a scholarly Consular, defending the innocent as a martial Guardian, or seeking out the dark side''s shadows as a balanced Sentinel. Even if the galaxy''s turbulent events have prematurely torn you away from the Temple''s safety, you carry the deep-rooted discipline, philosophical teachings, and burgeoning abilities of a dedicated Force initiate.

Choose two attribute boosts. One must be to Wisdom or Charisma, and one is a free attribute boost.

You''re trained in The Force and the Jedi Order Lore skill.  You gain the Force Sensitive skill feat.',	'You were brought to the tranquil, echoing halls of the Jedi Temple at a very young age, trading a family you barely remember for the strict, monastic life of an initiate.',	'{"feat": {"fixed": [{"id": "feaForceSensitive", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}, {"id": "sklLoreJediOrder", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["WIS", "CHA"]}}}'),
('bkgInvestigator',	'Investigator',	'In a galaxy overflowing with corporate corruption, spice smuggling, and political assassinations, you are the one who untangles the truth. You might have been a hardened detective for CorSec, an independent sleuth operating in the rain-slicked lower levels of Nar Shaddaa, or a Sector Ranger piecing together fragmented data trails across the Mid Rim. You have a keen eye for detail, a methodical approach to dissecting a scene, and a talent for interrogating tight-lipped suspects. You know how to read the shadows of the galactic underworld and follow the cred-trail, no matter how deeply the syndicate or the Empire has buried it.

Choose two attribute boosts. One must be to Intelligence or Wisdom, and one is a free attribute boost.

You''re trained in the Society skill, and the Underworld Lore skill. You gain the Streetwise skill feat.',	'In a galaxy overflowing with corporate corruption, spice smuggling, and political assassinations, you are the one who untangles the truth.',	'{"feat": {"fixed": [{"id": "feaStreetwise", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklSociety", "rank": "Trained"}, {"id": "sklLoreUnderworld", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["INT", "WIS"]}}}'),
('bkgSithInitiate',	'Sith Initiate',	'You were forged in the crucible of the dark side, taught to draw power from passion, anger, and the pursuit of absolute control. Whether you survived the brutal, cutthroat trials of an ancient Sith Academy on Korriban, served as a secret apprentice under the shadow of the Rule of Two, or were cultivated by a secretive enclave of dark side cultists, your training was entirely devoid of the Jedi''s pacifism. You were taught to channel your darkest emotions into raw power and aggressive lightsaber combat. Though you may have broken away from your masters or are currently carving your own path through the galaxy, you carry the indomitable will, cunning, and lethal Force connection of a true dark side acolyte.

Choose two attribute boosts. One must be to Strength or Charisma, and one is a free attribute boost.

You''re trained in The Force and the Sith Order Lore skill.  You gain the Force Sensitive skill feat.',	'You were forged in the crucible of the dark side, taught to draw power from passion, anger, and the pursuit of absolute control.',	'{"feat": {"fixed": [{"id": "feaForceSensitive", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}, {"id": "sklLoreSithOrder", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "CHA"]}}}'),
('bkgSmuggler',	'Smuggler',	'You make your living moving illicit cargo from one side of the galaxy to the other, entirely under the radar of local authorities and planetary blockades. Whether you ran glitterstim spice through the Kessel Run, transported black-market blasters for desperate insurgencies, or simply ferried untaxed goods past Imperial customs, your life relies on heavily modified sublight engines and hidden deck compartments. You are a fast-talking risk-taker who knows exactly how to bribe a docking bay official, outrun a tractor beam, and shoot first when a deal inevitably goes sour in a dusty Outer Rim spaceport.

Choose two attribute boosts. One must be to Dexterity or Wisdom, and one is a free attribute boost.

You''re trained in the Stealth skill, and the Piracy Lore skill. You gain the Experienced Smuggler skill feat.',	'You make your living moving illicit cargo from one side of the galaxy to the other, entirely under the radar of local authorities and planetary blockades.',	'{"feat": {"fixed": [{"id": "feaExperiencedSmuggler", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklLorePiracy", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "WIS"]}}}'),
('bkgArtisan',	'Artisan',	'You are a master of physical creation, turning raw materials and scattered components into functional works of art. Whether you operate a bustling industrial forge, run a specialized custom blaster shop on Nar Shaddaa, or meticulously craft lore-accurate armor and weaponry for demanding clients across the Core Worlds, your hands are rarely clean. You understand the deep mechanics of the galaxy''s gear, from the precise calibration of a vibroblade''s ultrasonic generator to the heat dispersion of heavy blast plating. Your dedication to your craft has given you an unparalleled eye for detail and the practical skills to repair, maintain, and upgrade equipment under any conditions.

Choose two attribute boosts. One must be to Strength or Intelligence, and one is a free attribute boost.

You''re trained in the Crafting skill, and the Lore skill related to your artisanal specialty. You gain the Specialty Crafting skill feat.',	'You are a master of physical creation, turning raw materials and scattered components into functional works of art.',	'{"feat": {"fixed": [{"id": "feaSpecialtyCrafting", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Craft Lore", "filter": [{"trait": "Craft"}]}}, "attribute": {"boost": {"free": 1, "choice": ["STR", "INT"]}}}'),
('bkgScientist',	'Scientist',	'Your life is dedicated to the empirical truths of the galaxy. Whether you served in the prestigious Republic Science Division, conducted classified hypermatter research for the Empire, or cataloged bizarre xenobiology in the uncharted reaches of the Unknown Regions, you view the universe through a lens of data, hypotheses, and rigorous experimentation. You are far more comfortable in a pristine laboratory or analyzing sensor readings from a datapad than you are holding a blaster. Your analytical mind, deep knowledge of the physical sciences, and ability to process complex variables make you an invaluable asset when encountering the galaxy''s many unexplained phenomena.

Choose two attribute boosts. One must be to Intelligence or Wisdom, and one is a free attribute boost.

You''re trained in the Crafting skill, and a Lore skill related to your field of research. You gain the Assurance skill feat.',	'Your life is dedicated to the empirical truths of the galaxy.',	'{"feat": {"fixed": [{"id": "feaAssurance", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Science Lore", "filter": [{"trait": "Science"}]}}, "attribute": {"boost": {"free": 1, "choice": ["INT", "WIS"]}}}'),
('bkgDiplomat',	'Diplomat',	'You represent a planetary government, a powerful megacorporation, or a sweeping coalition like the Republic or the Rebel Alliance. Your battlefield is the Senate floor, the tense negotiation table, or the opulent reception halls of the Core Worlds. You are trained to navigate complex treaties, mediate deadly disputes, and sway the opinions of planetary governors and warlords alike. In a galaxy prone to solving its problems with turbolasers and thermal detonators, your silver tongue, deep cultural insight, and ironclad composure are your absolute greatest weapons.

Choose two attribute boosts. One must be to Intelligence or Charisma, and one is a free attribute boost.

You''re trained in the Diplomacy skill, and a Lore skill for a planet of your choosing. You gain the Group Impression skill feat.',	'You represent a planetary government, a powerful megacorporation, or a sweeping coalition like the Republic or the Rebel Alliance.',	'{"feat": {"fixed": [{"id": "feaGroupImpression", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklDiplomacy", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Planet Lore", "filter": [{"trait": "Planet"}]}}, "attribute": {"boost": {"free": 1, "choice": ["INT", "CHA"]}}}'),
('bkgAgent',	'Agent',	'You operate in the shadows of the galaxy''s sprawling conflicts, trading in secrets, sabotage, and subversion. Perhaps you are a ruthless operative maintaining order from within the Imperial Security Bureau, a corporate spy stealing hyperspace schematics, or an undercover asset running covert Rebel Alliance missions in the seedy underworld of Ord Mantell. You have mastered the art of blending in, manipulating the unwary, and extracting vital intelligence before slipping away undetected. The life of a spy is one of constant paranoia and shifting loyalties, leaving you with a sharp mind, a talent for deception, and the instinct to always check your six.

Choose two attribute boosts. One must be Intelligence or Charisma, and one is a free attribute boost.

You''re trained in the Deception skill and a Lore skill related to your employer.  You gain the Without a Trace skill feat.',	'You operate in the shadows of the galaxy''s sprawling conflicts, trading in secrets, sabotage, and subversion.',	'{"feat": {"fixed": [{"id": "feaWithoutATrace", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklDeception", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Org Lore", "filter": [{"trait": "Org"}]}}, "attribute": {"boost": {"free": 1, "choice": ["INT", "CHA"]}}}'),
('bkgSpacePirate',	'Space Pirate',	'The hyperlanes are your hunting ground, and the cargo manifests of passing freighters are your personal catalog. Whether you rode with a ruthless swoop gang that graduated to armed boarding craft, served under the banner of a notorious corsair in the Outer Rim, or mutinied against a corporate shipping conglomerate, you take what you want by force and intimidation. You are well-versed in the chaotic violence of ship-to-ship boarding actions, the tactical use of ion cannons to disable your prey, and the cutthroat politics of dividing the spoils among a crew of hardened criminals.

Choose two attribute boosts. One must be to Strength or Dexterity, and one is a free attribute boost.

You''re trained in the Intimidation skill, and the Piracy Lore skill. You gain the Group Coercion skill feat.',	'The hyperlanes are your hunting ground, and the cargo manifests of passing freighters are your personal catalog.',	'{"feat": {"fixed": [{"id": "feaGroupCoercion", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklIntimidation", "rank": "Trained"}, {"id": "sklLorePiracy", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "DEX"]}}}'),
('bkgEntertainer',	'Entertainer',	'You have made your way through the galaxy by capturing the attention and credits of the masses. You might be a traveling acrobat performing in the zero-gravity circus troupes of the Mid Rim, a charismatic HoloNet personality broadcasting from the heart of the Core Worlds, or a dramatic storyteller weaving tales in fire-lit camps. Unlike a specialized Jizz Wailer or a conceptual Artist, your focus is entirely on the spectacle and the crowd. You know how to read a room, hold an audience in the palm of your hand, and use your natural magnetism to charm your way into—or out of—almost any situation.

Choose two attribute boosts. One must be to Dexterity or Charisma, and one is a free attribute boost.

You''re trained in the Performance skill, and the Media Lore skill. You gain the Virtuosic Performer skill feat.',	'You have made your way through the galaxy by capturing the attention and credits of the masses.',	'{"feat": {"fixed": [{"id": "feaVirtuosicPerformer", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklPerformance", "rank": "Trained"}, {"id": "sklLoreMedia", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "CHA"]}}}'),
('bkgPodracer',	'Podracer',	'You spent your formative years strapped into a cockpit, dragged at breakneck speeds by a pair of massive, over-charged engines. Whether you competed on the dust-choked circuits of Tatooine or the perilous, winding courses of Malastare, podracing requires razor-sharp reflexes and an intimate understanding of high-performance mechanics to keep your racer from violently exploding mid-lap. You survived the most dangerous motorsport in the galaxy, leaving you with an adrenaline addiction, a knack for squeezing every ounce of thrust out of a repulsorlift engine, and the twitch-reflex instincts necessary to act before anyone else even realizes the race has started.

Choose two attribute boosts. One must be to Dexterity or Intelligence, and one is a free attribute boost.

You''re trained in the Piloting skill and the Speeder Engineering Lore skill.  You gain the Incredible Initiative general feat.',	'You spent your formative years strapped into a cockpit, dragged at breakneck speeds by a pair of massive, over-charged engines.',	'{"feat": {"fixed": [{"id": "feaIncredibleInitiative", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklPiloting", "rank": "Trained"}, {"id": "sklLoreSpeederEngineering", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "INT"]}}}'),
('bkgJizzWailer',	'Jizz Wailer',	'You are a working musician, earning your credits playing the upbeat, frenetic rhythms of jizz music in smoky cantinas, neon-lit swoop tracks, and shady underworld clubs across the Outer Rim. With your trusty kloo horn, slitherhorn, or bandfill in hand, you have seen the galaxy from the vantage point of a dimly lit stage. This life has taught you how to read a tough crowd, negotiate with ruthless venue owners, and know exactly when a bar brawl is about to erupt so you can slip out the back door with your instrument and your tip jar intact.

Choose two attribute boosts. One must be to Constitution or Charisma, and one is a free attribute boost.

You''re trained in the Performance skill and the Jizz Lore skill.  You gain the Impressive Performance skill feat.',	'You are a working musician, earning your credits playing the upbeat, frenetic rhythms of jizz music in smoky cantinas, neon-lit swoop tracks, and shady underworld clubs across the Outer Rim.',	'{"feat": {"fixed": [{"id": "feaImpressivePerformance", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklPerformance", "rank": "Trained"}, {"id": "sklLoreJizz", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["CON", "CHA"]}}}'),
('bkgSalvager',	'Salvager',	'The galaxy is littered with the rusted hulks of forgotten wars and discarded technology, and you have made a hard-scrabble living picking their bones clean. Whether you scrambled through the dark, perilous corridors of downed cruisers in a scrapping guild, haggled over droid parts in sun-baked desert canyons, or floated through dangerous orbital debris fields, you possess an eagle eye for valuable tech. You know how to safely bypass decaying security grids, extract a functional hyperdrive motivator from a mountain of slag, and turn a derelict starship''s trash into a pocketful of hard-won credits.

Choose two attribute boosts. One must be to Strength or Dexterity, and one is a free attribute boost.

You''re trained in the Athletics skill, and the Salvage Lore skill. You gain the Combat Climber skill feat.',	'The galaxy is littered with the rusted hulks of forgotten wars and discarded technology, and you have made a hard-scrabble living picking their bones clean.',	'{"feat": {"fixed": [{"id": "feaCombatClimber", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklAthletics", "rank": "Trained"}, {"id": "sklLoreSalvage", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "DEX"]}}}'),
('bkgArtist',	'Artist',	'You see the galaxy not as a battlefield or a marketplace, but as a boundless canvas. You might be a renowned holovid director capturing the drama of the Republic, a subversive street painter leaving anti-authoritarian murals on the plastoid walls of Lothal, or a mesmerizing dancer performing in the opulent courts of the Hutts. Your medium is emotion and expression, and you possess a keen understanding of aesthetics, cultural nuances, and how to captivate an audience. Though venturing into dangerous territories is a far cry from a gallery exhibition, your creative problem-solving, keen observational skills, and deep insight into the galactic condition are invaluable assets.

Choose two attribute boosts. One must be to Dexterity or Charisma, and one is a free attribute boost.

You''re trained in the Crafting skill, and the Art Lore skill. You gain the Specialty Crafting skill feat.',	'You see the galaxy not as a battlefield or a marketplace, but as a boundless canvas.',	'{"feat": {"fixed": [{"id": "feaSpecialtyCrafting", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}, {"id": "sklLoreArt", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "CHA"]}}}'),
('bkgDoctor',	'Doctor',	'Whether you served as a trauma surgeon in a pristine Republic medcenter, a desperate field medic in the muddy trenches of the Outer Rim, or a back-alley cybernetics installer on Nar Shaddaa, your trade is the fragile nature of organic life. You have spent your career up to your elbows in bacta and biosynthetic patches, treating horrific blaster burns, vibroblade gashes, and the myriad diseases of a thousand different worlds. You possess a clinical detachment, a deep understanding of multi-species anatomy, and the steady hands required to save lives when the rest of the galaxy is intent on ending them.

Choose two attribute boosts. One must be to Dexterity or Wisdom, and one is a free attribute boost.

You''re trained in the Medicine skill, and the Life Science Lore skill. You gain the Battle Medicine skill feat.',	'Whether you served as a trauma surgeon in a pristine Republic medcenter, a desperate field medic in the muddy trenches of the Outer Rim, or a back-alley cybernetics installer on Nar Shaddaa, your trade is the fragile nature of organic life.',	'{"feat": {"fixed": [{"id": "feaBattleMedicine", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklMedicine", "rank": "Trained"}, {"id": "sklLoreAnatomy", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "WIS"]}}}'),
('bkgEngineer',	'Engineer',	'You are the grease-stained, hydrospanner-wielding backbone of galactic infrastructure. Whether you spent your career calibrating hyperdrive motivators in a bustling Corellian shipyard, maintaining the failing life-support systems of an Outer Rim mining colony, or designing structural shielding for corporate dreadnoughts, your mind is a steel trap of schematics and thermodynamic principles. You know how to coax miracles out of a failing reactor and can jury-rig a bypass with little more than a fusion cutter and a spool of conductive wire.

Choose two attribute boosts. One must be to Dexterity or Intelligence, and one is a free attribute boost.

You''re trained in Crafting and the Lore skill related to your engineering specialty.  You gain the Specialty Crafting skill feat.',	'You are the grease-stained, hydrospanner-wielding backbone of galactic infrastructure.',	'{"feat": {"fixed": [{"id": "feaSpecialtyCrafting", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Engineering Lore", "filter": [{"trait": "Engineering"}]}}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "INT"]}}}'),
('bkgFarmer',	'Farmer',	'The galaxy relies on the grueling, unglamorous labor of those who work the land, and you are one of them. Whether you spent your life repairing moisture vaporators beneath the twin suns of Tatooine, harvesting vast tracts of nutrient-rich kelp on the oceans of Mon Cala, or tending to terraced vineyards on Naboo, your days were defined by hard physical labor and the unpredictable whims of the environment. You have developed a resilient constitution, an intimate understanding of the natural world, and a pragmatic, calloused toughness that serves you well far beyond the borders of your homestead.

Choose two attribute boosts. One must be to Constitution or Wisdom, and one is a free attribute boost.

You''re trained in the Nature skill and the Lore skill related to the planet you farmed.  You gain the Train Animal skill feat.',	'The galaxy relies on the grueling, unglamorous labor of those who work the land, and you are one of them.',	'{"feat": {"fixed": [{"id": "feaTrainAnimal", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklNature", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Planet Lore", "filter": [{"trait": "Planet"}]}}, "attribute": {"boost": {"free": 1, "choice": ["CON", "WIS"]}}}'),
('bkgHermit',	'Hermit',	'For years, you chose the quiet isolation of the galaxy''s most remote corners over the deafening noise of civilization. You might have retreated to the sun-baked Jundland Wastes, the swampy bogs of a forgotten world, or the icy caves of a desolate moon to escape a haunted past, hide from a galactic purge, or seek quiet enlightenment. This prolonged solitude taught you profound self-reliance, deep patience, and an intimate understanding of the natural, untamed environments around you. Though you have finally stepped back into the wider galaxy, you carry the quiet vigilance and rugged survival instincts of someone who has lived entirely by their own means.

Choose two attribute boosts. One must be to Intelligence or Wisdom, and one is a free attribute boost.

You''re trained in the Nature skill and a Lore skill related to a species (intelligent or otherwise) local to your dwelling.  You gain the Natural Medicine skill feat.',	'For years, you chose the quiet isolation of the galaxy''s most remote corners over the deafening noise of civilization.',	'{"feat": {"fixed": [{"id": "feaNaturalMedicine", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklNature", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Creature or Species Lore", "filter": [{"trait": ["Creature", "Species"]}]}}, "attribute": {"boost": {"free": 1, "choice": ["INT", "WIS"]}}}'),
('bkgOutlaw',	'Outlaw',	'You have lived your life one step ahead of the law, whether that law was the iron grip of the Imperial Security Bureau, the jurisdiction of Republic Sector Rangers, or the relentless enforcers of the Hutt Cartels. You might be a daring swoop-ganger, a spice runner operating out of Mos Eisley, or a notorious pirate raiding hyperlanes in the Outer Rim. Living on the wrong side of the galactic legal code has made you resourceful, paranoid, and quick on the draw. You know how to spot a bounty hunter in a crowded cantina, forge a chain code, and survive when an entire sector is looking for you.

Choose two attribute boosts. One must be to Dexterity or Charisma, and one is a free attribute boost.

You''re trained in the Intimidation skill, and the Underworld Lore skill. You gain the Intimidating Shot skill feat.',	'You have lived your life one step ahead of the law, whether that law was the iron grip of the Imperial Security Bureau, the jurisdiction of Republic Sector Rangers, or the relentless enforcers of the Hutt Cartels.',	'{"feat": {"fixed": [{"id": "feaIntimidatingShot", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklIntimidation", "rank": "Trained"}, {"id": "sklLoreUnderworld", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "CHA"]}}}'),
('bkgSaboteur',	'Saboteur',	'You specialize in dismantling the galaxy''s infrastructure from the inside out. Whether you were a Rebel operative tasked with blowing Imperial shield generators on heavily guarded moons, a ruthless corporate mercenary disabling rival hyperdrive manufacturing facilities, or an independent anarchist sowing chaos in the Core Worlds, your expertise lies in calculated destruction. You possess an intimate understanding of structural weak points, explosive ordnance, and the slicing skills needed to bypass heavy blast doors before the charges detonate. You know firsthand that a well-placed thermal detonator or a subtly severed power conduit can cripple a Star Destroyer just as effectively as a fleet of starfighters.

Choose two attribute boosts. One must be to Dexterity or Wisdom, and one is a free attribute boost.

You are trained in the Thievery skill and the Lore skill related to the type of engineering that you specialize in destroying.  You gain the Concealing Legerdemain skill feat.',	'You specialize in dismantling the galaxy''s infrastructure from the inside out.',	'{"feat": {"fixed": [{"id": "feaConcealingLegerdemain", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklThievery", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Engineering Lore", "filter": [{"trait": "Engineering"}]}}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "WIS"]}}}'),
('bkgStreetRat',	'Street Rat',	'You grew up in the claustrophobic alleys, exhaust-choked ventilation shafts, and bustling marketplaces of the galaxy''s most unforgiving cities. Whether you were an orphaned scavenger dodging Stormtrooper patrols on Lothal, a nimble beggar working the sunless lower levels of Coruscant, or a runaway surviving the neon-lit shadows of Nar Shaddaa, the streets were your only teacher. You lack a formal education or a silver spoon, but you possess an unparalleled instinct for urban survival, a talent for vanishing into a crowd, and the acrobatic agility needed to scramble across rooftops when the local enforcers give chase.

Choose two attribute boosts. One must be to Dexterity or Wisdom, and one is a free attribute boost.

You''re trained in the Survival skill, and a Lore skill about a specific settlement. You gain the Urban Survivalist skill feat.',	'You grew up in the claustrophobic alleys, exhaust-choked ventilation shafts, and bustling marketplaces of the galaxy''s most unforgiving cities.',	'{"feat": {"fixed": [{"id": "feaUrbanSurvivalist", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklSurvival", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Settlement Lore", "filter": [{"trait": "Settlement"}]}}, "attribute": {"boost": {"free": 1, "choice": ["DEX", "WIS"]}}}'),
('bkgMandalorian',	'Mandalorian',	'You were raised in the strict, martial culture of Mandalore. Whether you were born to a clan or taken in as a foundling and raised in the Creed, your childhood was defined by rigorous combat training and a deep reverence for the weapons and armor that keep your people alive. You have sworn the Resol''nare, learning the importance of self-defense, family, and field maintenance of your gear.

Choose two attribute boosts. One must be to Strength or Constitution, and one is a free attribute boost.

You become trained in Crafting and Mandalorian Lore. You gain the Quick Repair skill feat.',	'You were raised in the strict, martial culture of Mandalore.',	'{"feat": {"fixed": [{"id": "feaQuickRepair", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}, {"id": "sklLoreMandalorian", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "CON"]}}}'),
('bkgMercenary',	'Mercenary',	'Your blaster belongs to the highest bidder. Whether you spent your career guarding Hutt spice shipments on Nal Hutta, fighting in corporate proxy wars across the Corporate Sector, or taking highly classified, off-the-books contracts for planetary governors, your loyalty is strictly rented. You are a professional soldier of fortune who views the galaxy''s endless conflicts not as a tragedy, but as a reliable source of income. This life of constant, transactional violence has given you a pragmatic understanding of combat, an ironclad approach to negotiating your cut, and a reputation that ensures people think twice before crossing you.

Choose two attribute boosts. One must be to Strength or Dexterity, and one is a free attribute boost.

You become trained in Intimidation and Mercenary Lore. You gain the Intimidating Glare skill feat.',	'Your blaster belongs to the highest bidder.',	'{"feat": {"fixed": [{"id": "feaIntimidatingGlare", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklIntimidation", "rank": "Trained"}, {"id": "sklLoreMercenary", "rank": "Trained"}]}, "attribute": {"boost": {"free": 1, "choice": ["STR", "DEX"]}}}');

DROP TABLE IF EXISTS "Campaign";
DROP SEQUENCE IF EXISTS "public"."Campaign_CampaignID_seq";
CREATE SEQUENCE "public"."Campaign_CampaignID_seq" INCREMENT 1 MINVALUE 1 MAXVALUE 2147483647 CACHE 1;

CREATE TABLE "public"."Campaign" (
    "CampaignID" integer DEFAULT nextval('"Campaign_CampaignID_seq"') NOT NULL,
    "OwnerID" integer NOT NULL,
    "Name" character varying NOT NULL,
    "Description" text,
    "Status" character varying DEFAULT 'draft' NOT NULL,
    "Structure" jsonb DEFAULT '{"acts": []}' NOT NULL,
    "CreatedAt" timestamptz DEFAULT now(),
    "UpdatedAt" timestamptz DEFAULT now(),
    CONSTRAINT "Campaign_pkey" PRIMARY KEY ("CampaignID")
)
WITH (oids = false);

CREATE INDEX idx_campaign_owner ON public."Campaign" USING btree ("OwnerID");

INSERT INTO "Campaign" ("CampaignID", "OwnerID", "Name", "Description", "Status", "Structure", "CreatedAt", "UpdatedAt") VALUES
(5,	2,	'Rust Anchor Retrieval',	NULL,	'draft',	'{"acts": [{"id": "act_76a4be67-5fb7-4dd2-904d-7520ab28f686", "type": "act", "order": 0, "title": "Phase I: Meeting Aboard the Rust Anchor", "children": [{"id": "scene_cb825ded-a00b-49e8-849b-5188c98eacc8", "type": "scene", "order": 0, "title": "Meeting on the Promenade", "children": [{"id": "enc_d74ac992-3903-4768-bd86-a5c6f11a6498", "type": "encounter", "order": 0, "title": "The Tense Negotiation (Social Encounter)", "children": [{"id": "ch_ae97fbcf-2a1f-4b7f-ac3b-f13b8d97b30c", "type": "challenge", "order": 0, "title": "Passive Actions (The Setups)", "children": [], "difficulty": "normal", "description": "These actions represent specialists analyzing the room to generate leverage. They do not trigger a counter from Valerius.\n\n-   **Underworld Lore (Syndicate Politics):** Analyze Kaelen''s gang colors to identify rivals. A success grants a +2 circumstance bonus to the next Active Action. Threatening to expose Kaelen skimming from his own cartel on a critical success grants a +3 bonus instead.\n    \n-   **Perception (Reading the Room):** Watch Kaelen''s micro-expressions. A success identifies his pressure points, granting the next Active Action a Fortune effect (roll twice and take the higher result).\n    \n-   **Engineering Lore or Crafting (Calling the Bluff):** Scrutinize the thermal detonator. A success reveals the blast radius would vaporize the cylinder too. Pointing this out grants a +2 circumstance bonus to the next Intimidation check.\n    \n-   **Society or Imperial Lore (Protocol Flaws):** Study Valerius''s deployment. A success reveals Valerius is operating \"off the books.\" Calling this out rattles the Director, applying a –2 circumstance penalty to Valerius''s next counter-action.", "challenge_type": "skill_check"}, {"id": "ch_1fdc427a-2b8c-4e97-8cca-28f96fc77189", "type": "challenge", "order": 0, "title": "Active Actions (The Closers)", "children": [], "difficulty": "normal", "description": "Only one Active Action can be made per round. Resolving this action triggers Valerius''s turn.\n\n(Critical Success = 2 VP, Success = 1 VP, Failure = 0 VP & 1 Strike, Critical Failure = -1 VP & 1 Strike)\n\n-   **Diplomacy (The Pragmatic Out):** Argue the Alliance is the only honest broker. On a success, Kaelen demands the credits immediately. On a failure, he dismisses the PCs as idealistic terrorists unable to guarantee his safety.\n    \n-   **Intimidation (The Powder Keg):** Threaten to blow the deck to space. On a success, Kaelen folds to the reckless aggression. On a failure, he calls the bluff and orders weapons hot.\n    \n-   **Deception (The Phantom Fleet):** Bluff that Rebel cruisers are targeting the station. On a success, Kaelen''s paranoia spikes and he agrees. On a failure, he scoffs at the amateur bluff, noting the clear proximity sensors.\n    \n-   **The Force (The Subtle Nudge):** Project absolute calm to override his greed. On a success, Kaelen drops his guard and agrees. On a critical failure, he violently snaps back to reality, realizing his mind was breached, and immediately ends the negotiation.\n\nReaction Note: Valerius can use his Reaction to counter a PC''s Deception check by forcing the PC to roll against his Perception DC 29. He can counter Intimidation by stepping into the line of fire, forcing a loss of 1 VP if the PC''s check fails.", "challenge_type": "skill_check"}, {"id": "ch_57c6a7f9-ea3f-4682-96f7-7367db0afd24", "type": "challenge", "order": 0, "title": "Valerius''s Counters", "children": [], "difficulty": "normal", "description": "After an Active Action, Valerius takes his turn. Roll a d4 or choose one.\n\n-   **The Imperial Coffers:** Valerius offers aurodium, automatically draining 1 VP from the PCs. Kaelen stares hungrily at the wealth.\n    \n-   **The Weight of the Empire:** Valerius attempts a DC 28 Intimidation check against Kaelen''s Will DC. On a success, Kaelen is terrified, increasing the PCs'' next Closer DC to 30.\n    \n-   **Terrorist Smear:** Valerius attempts a DC 28 Society check against Kaelen''s Will DC to attack the Rebellion''s credibility. On a success, Kaelen agrees, and the PCs take a –2 penalty to their next Closer.\n    \n-   **Tactical Escalation:** Valerius silently signals his Death Troopers to rack their blasters. The Death Troopers gain a +2 circumstance bonus to their Initiative rolls when combat begins.", "challenge_type": "skill_check"}], "difficulty": "normal", "description": "The PCs are thrust instantly into a high-level social challenge. This encounter uses a Bidding Track. The Negotiator, Kaelen, starts neutral but anxious.\n\nTo win the bid, the PCs must accrue 4 Victory Points (VP). If the PCs accumulate 3 Failed Active Actions before reaching 4 VP, Director Valerius successfully buys Kaelen out.\n\nThe encounter operates in loose \"rounds.\" First, any number of players can attempt Passive Actions (Setups). Then, one player steps forward to make an Active Action (Closer). Finally, Director Valerius takes his turn to counter.\n\nThe standard DC is DC 28.", "encounter_type": "social"}, {"id": "enc_4aa3c32c-c616-47fa-9ebd-c529cca622d3", "type": "encounter", "order": 0, "title": "The Promenade Shootout (Combat Encounter)", "children": [{"id": "ch_07e9fc29-03aa-4e8a-a60f-68fa0eb3ba3f", "type": "challenge", "order": 0, "title": "Zero-G Plasma Venting (Hazard 11)", "children": [], "difficulty": "normal", "description": "**Traits:** [Environmental] [Complex] [Fire] [Mechanical]\n\n**Stealth** +24 (or **DC 34 Perception** to notice the groaning metal before it bursts). \n\n**Description** The gravity cuts out entirely, leaving combatants floating in mid-air as a ruptured conduit indiscriminately spews bursts of superheated plasma. \n\n**Disable** Achieve the required successes via DC 28 Starship Engineering Lore or DC 30 Crafting to patch it (3 successes), DC 32 Computers to reroute flow (2 successes), or DC 32 The Force to crush it shut (2 successes). \n\n**Routine (1 Action)** The hazard acts on Initiative count 24. \n\n**Passive Effect (Zero Gravity):** The promenade is devoid of gravity. To move, a creature must use the Float action (DC 28 Acrobatics or Athletics). Success allows moving half Speed. Failure means moving 5 feet, becoming Off-Guard, and losing further movement. Critical Failure means drifting 10 feet randomly, becoming Off-Guard, and losing further movement. \n\n**[1 Action] Plasma Eruption:** The conduit unleashes a 20-foot burst of superheated plasma targeting the largest cluster of creatures. All creatures in the burst take 6d8+14 fire damage (DC 30 basic Reflex save). Drifting creatures take a –2 circumstance penalty to this save.", "challenge_type": "hazard"}, {"id": "npc_92efacec-77c4-4073-a972-816295d68758", "npc": {"hp": {"max": 160, "current": 160}, "size": "Medium", "level": 12, "speed": {"base": 25}, "senses": {}, "traits": ["Medium", "Humanoid", "Human"], "actions": [{"id": "25bdcd39-71dd-494e-b5fe-1688fb8fc025", "cost": "1 Action", "name": "Imperial Mandate", "traits": "Auditory, Concentrate, Emotion, Mental", "description": "Valerius orders an allied Imperial unit within 60 feet to immediately use their Reaction to Stride or Strike. If they Strike, they gain a +2 status bonus to the attack roll."}, {"id": "40a6332c-8dd8-49fe-aaf0-b80261756a07", "cost": "Reaction", "name": "Tactical Reposition", "traits": "", "description": "**Trigger:** An enemy moves adjacent to Valerius. **Effect:** Valerius Steps up to 10 feet. In zero gravity, he must end adjacent to a solid surface or begin drifting."}, {"id": "e87b9d16-204f-46ff-8b15-7aff3b1ec01f", "cost": "Reaction", "name": "Calculated Sacrifice", "traits": "", "description": "**Trigger:** Valerius is targeted by an attack or area effect, and an Imperial ally is within 5 feet. **Effect:** Valerius shoves his ally into the line of fire, gaining a +4 circumstance bonus to his AC or saving throw. If the attack misses Valerius, it hits the ally instead."}], "weapons": [{"id": "4c64cb2a-a770-484f-8b06-5e5fe3f66612", "name": "Concealed Vibroblade", "type": "Melee", "traits": "Agile, Finesse", "attribute": "dex", "damage_str": "2d4+10 slashing", "proficiency": "Master"}, {"id": "7f56fc07-a419-42fd-83f7-e29b0ea83511", "name": "Advanced Blaster Pistol", "type": "Ranged", "traits": "Range 60 ft, Blaster", "attribute": "dex", "damage_str": "3d6+10 plasma", "proficiency": "Master"}], "attributes": {"cha": 5, "con": 1, "dex": 2, "int": 5, "str": 0, "wis": 3}, "proficiencies": {"skills": {"sklSociety": "Master", "sklComputers": "Trained", "sklDeception": "Master", "sklDiplomacy": "Master", "sklIntimidation": "Master"}, "perception": "Legendary", "saving_throws": {"ref": "Legendary", "fort": "Master", "will": "Legendary"}}, "armor_item_bonus": 0, "armor_proficiency_rank": "Master"}, "type": "npc", "order": 0, "title": "Director Valerius, ISB Operations Chief", "children": [], "description": "**Magnetic Grip:** While adjacent to a metal surface, Valerius ignores the penalties of zero gravity and does not need to use the Float action to move."}, {"id": "npc_bd8582af-f904-4dc8-a810-406d656d3ef8", "npc": {"hp": {"max": 175, "current": 175}, "size": "Medium", "level": 10, "speed": {"base": 25}, "senses": {}, "traits": ["Medium", "Humanoid", "Human"], "actions": [{"id": "3e504524-b013-4cb5-811a-2bcf09037154", "cost": "2 Actions", "name": "Auto-Fire", "traits": "", "description": "The Death Trooper targets a 30-foot cone. All creatures in the area must attempt a DC 28 basic Reflex save against 2d10+6 plasma damage."}, {"id": "f8d65cfe-2fca-41f1-b3d8-9c1f32930e33", "cost": "2 Actions", "name": "Relentless Advance", "traits": "", "description": "The Death Trooper Strides up to their Speed, ignoring difficult terrain, and makes a Heavy Blaster Rifle Strike."}, {"id": "b5cc0455-bce1-48e4-9a63-a71218ed2928", "cost": "Reaction", "name": "Overwhelming Suppression", "traits": "", "description": "**Trigger:** An enemy within 60 feet uses an action with the Concentrate trait. **Effect:** The Death Trooper makes a ranged Strike. If it hits, the target is disrupted unless they succeed at a **DC 29 Fortitude save**."}], "weapons": [{"id": "29d6719e-7d6d-4537-859d-7f89b068fe01", "name": "Armored Gauntlet", "type": "Melee", "traits": "Agile", "attribute": "str", "damage_str": "2d6+9 bludgeoning", "proficiency": "Master"}, {"id": "30951b78-5be1-452d-87b7-b14c5f4ec9bb", "name": "E-11D Heavy Blaster Rifle", "type": "Ranged", "traits": "Range 100 ft, Automatic", "attribute": "dex", "damage_str": "2d10+6 plasma", "proficiency": "Master"}], "attributes": {"cha": 0, "con": 4, "dex": 4, "int": 0, "str": 5, "wis": 2}, "proficiencies": {"skills": {"sklStealth": "Expert", "sklSurvival": "Expert", "sklAthletics": "Master", "sklIntimidation": "Master"}, "perception": "Master", "saving_throws": {"ref": "Master", "fort": "Legendary", "will": "Expert"}}, "armor_item_bonus": 2, "armor_proficiency_rank": "Expert"}, "type": "npc", "order": 0, "title": "Imperial Death Trooper (x2)", "children": [], "description": "**Juggernaut Plating:** Resistance 5 to damage from Blaster and Laser weapons. \n**Garbled Comms (Aura, Emotion, Fear, Mental)** 30 feet. Enemies within the aura take a –1 status penalty to Will saving throws. \n**Magnetic Grip:** While adjacent to a metal surface, the Death Trooper ignores zero gravity movement penalties."}, {"id": "npc_056ee4b2-1bea-4923-bf1c-d06960cd5de3", "npc": {"hp": {"max": 150, "current": 150}, "size": "Medium", "level": 10, "speed": {"base": 30}, "senses": {}, "traits": ["Medium", "Humanoid"], "actions": [{"id": "b9eba84b-7ac1-4404-9938-2c79e0e3fa4c", "cost": "1 Action", "name": "\"Get Them Off Me!\"", "traits": "Auditory, Concentrate", "description": "Kaelen screams at his bodyguards. Until the start of his next turn, allied Cyber-Enforcers gain a +2 circumstance bonus to damage against a designated target."}, {"id": "d7dbaa62-a9b0-41ca-bce8-b2ce71b03e7b", "cost": "Reaction", "name": "Human Shield", "traits": "", "description": "**Trigger:** Kaelen is targeted by a ranged Strike with an ally adjacent. **Effect:** Kaelen gains a +4 circumstance bonus to his AC. If the attack misses him but beats the ally''s AC, it hits the ally."}, {"id": "9bab8471-80f1-43e5-8367-4d07c701f4be", "cost": "2 Actions", "name": "Slippery Retreat", "traits": "", "description": "Kaelen uses the Float or Stride action. If he succeeds, he can immediately Float or Stride a second time without triggering Reactions."}], "weapons": [{"id": "565f9b75-f323-4965-a827-d66e936d0466", "name": "Concealed Vibroblade", "type": "Melee", "traits": "Agile, Finesse", "attribute": "dex", "damage_str": "2d4+7 slashing", "proficiency": "Master"}, {"id": "72d592e7-309f-47ff-a50e-e425d81bb6b9", "name": "Hold-out Blaster Pistol", "type": "Ranged", "traits": "Concealable, Range 30ft", "attribute": "dex", "damage_str": "2d6+6 plasma", "proficiency": "Master"}], "attributes": {"cha": 4, "con": 2, "dex": 5, "int": 3, "str": 1, "wis": 2}, "proficiencies": {"skills": {"sklSociety": "Expert", "sklStealth": "Expert", "sklThievery": "Master", "sklDeception": "Legendary", "sklDiplomacy": "Legendary", "sklAcrobatics": "Master"}, "perception": "Master", "saving_throws": {"ref": "Master", "fort": "Expert", "will": "Master"}}, "armor_item_bonus": 0, "armor_proficiency_rank": "Expert"}, "type": "npc", "order": 0, "title": "Kaelen, Syndicate Negotiator", "children": [], "description": "**Evasion:** When Kaelen rolls a success on a Reflex save, he gets a critical success instead."}, {"id": "npc_4c87933f-ff0f-4240-9858-a156de722eda", "npc": {"hp": {"max": 175, "current": 175}, "size": "Medium", "level": 9, "speed": {"base": 20}, "senses": {}, "traits": [], "actions": [{"id": "53b426bc-b863-4d42-ac52-f9ecaa9f2de9", "cost": "2 Actions", "name": "Auto-Fire", "traits": "", "description": "The Cyber-Enforcer targets a 30-foot cone or a 15-foot burst. All creatures in the area must attempt a DC 27 basic Reflex save against 4d8+6 fire damage. Expends 10 charges."}, {"id": "9873519b-fddb-43f6-8d90-6de7131d027b", "cost": "1 Action", "name": "Bracing Thrusters", "traits": "Move", "description": "The Cyber-Enforcer anchors themselves, ignoring zero gravity movement penalties until they move. They gain a +2 circumstance bonus to Fortitude saves against being Repositioned or Pushed."}], "weapons": [{"id": "bef26ea7-f65c-4b97-829a-2d42d0d70bd0", "name": "Cybernetic Arm", "type": "Melee", "traits": "Agile, Brawling", "attribute": "str", "damage_str": "2d6+8 bludgeoning", "proficiency": "Master"}, {"id": "721e1777-f718-4f43-af27-b1b69bcf8766", "name": "Customized Rotary Blaster", "type": "Ranged", "traits": "Range 60ft, Automatic", "attribute": "dex", "damage_str": "2d8+6 plasma", "proficiency": "Master"}], "attributes": {"cha": -1, "con": 4, "dex": 3, "int": -1, "str": 5, "wis": 1}, "proficiencies": {"skills": {"sklAthletics": "Master", "sklIntimidation": "Legendary"}, "perception": "Master", "saving_throws": {"ref": "Expert", "fort": "Legendary", "will": "Expert"}}, "armor_item_bonus": 3, "armor_proficiency_rank": "Trained"}, "type": "npc", "order": 0, "title": "Syndicate Cyber-Enforcer (x2)", "children": [], "description": "**Pain Dampeners:** Resistance 5 to physical damage and a +2 status bonus to saves against Sickened or Fatigued conditions."}], "difficulty": "normal", "description": "Regardless of who wins the bidding war, Valerius has no intention of leaving loose ends. As the final deal is struck, the failing station gives out.\n\nA deafening metallic shriek echoes through the promenade. The massive plasma conduit above you violently buckles, and emergency klaxons begin to wail as the gravity plating flickers and dies. Director Valerius draws his weapon. \"Kill them all,\" he barks.\n\nIf the PCs Win the Bid (4 VP): Combat begins as a chaotic Three-Way Firefight. The ISB forces fight both the PCs and the Syndicate bodyguards, splitting the Death Troopers'' aggressive fire between the two factions while Kaelen desperately tries to hand off the cylinder to the party.\nIf Valerius Wins the Bid (3 Failures): Kaelen tosses the cylinder to Valerius. Kaelen and his bodyguards flee the promenade entirely. The PCs are left alone in a Focused Firefight against the full, undivided might of the ISB strike team.", "encounter_type": "combat"}], "description": ">The heavy blast doors of the _Rust Anchor''s_ central promenade groan apart. You step into the cavernous, dimly lit chamber expecting a simple handoff. Above you, a massive, rusted primary plasma conduit throbs ominously against the ceiling, hissing as it vents tiny bursts of superheated blue-white vapor into the air. The station''s gravity plating hums with an unstable, erratic vibration.\n>\n>Standing in the center of the room is an immaculately dressed but visibly tense syndicate negotiator, flanked by two heavily cybernetic bodyguards holding customized rotary blasters. There is no sign of the defector. The negotiator holds up a heavy, encrypted access cylinder.\n>\n>\"The package is secure in the station''s reinforced core,\" the negotiator says, smoothing their coat. \"This cylinder is the only way in. Now, regarding the agreed-upon price—\"\n>\n>Before they can finish, the blast doors on the _opposite_ side of the promenade cycle open. A sharp-featured Imperial Security Bureau Director strides in, flanked by a squad of towering, black-armored Death Troopers. The Imperials instantly raise their blasters at you. Your hands drift to your weapons.\n>\n>\"Hold your fire, Director Valerius, or the cylinder gets vaporized,\" the negotiator snaps, pulling a thermal detonator and holding it flush against the key. They look between your crew and the Imperials, a bead of sweat betraying their confident smile. \"I apologize for the double-booking, but my client''s value has suddenly become... competitive. Let the bidding begin.\""}], "description": "The PCs arrive at the Rust Anchor, a supposedly neutral, derelict mining station floating in the debris field of a shattered moon. They are here to purchase a high-value Imperial defector (an engineer with the shield-gate schematics for a major shipyard) from a rising, ambitious fringe syndicate looking to make a name for itself.\n\nInstead of a briefing, the session begins the moment the airlock cycles open."}, {"id": "act_8e11d349-b849-4989-b9dd-19b4845f3105", "type": "act", "order": 0, "title": "Phase II: Race Through the Ruins", "children": [], "description": "With the promenade in shambles and the station’s structural integrity failing, the PCs must sprint through the derelict mining corridors. Every player character must attempt to overcome each of the four obstacles to survive the gauntlet.\n\n-   **Obstacle 1: The Vacuum Breach:** The PCs must leap across a 40-foot gap of twisting debris exposed to space. Success requires a DC 28 Acrobatics, DC 30 Athletics, or DC 28 Fortitude save. On a failure, the PC takes 4d6 bludgeoning damage and becomes Fatigued for 10 minutes.\n    \n-   **Obstacle 2: The Syndicate Defense Grid:** Panicked syndicate forces have triggered automated lasers. Success requires a DC 28 Stealth, DC 28 Thievery/Computers, or DC 30 Reflex save. On a failure, the PC takes 4d8 fire damage and becomes Dazzled for 10 minutes.\n    \n-   **Obstacle 3: Ruptured Coolant Mains:** Shattered pipes flood catwalks with toxic slush. Success requires a DC 30 Acrobatics, DC 28 Survival/Medicine, or DC 28 The Force check. On a failure, the PC takes 4d6 acid damage and becomes Sickened 1 for 10 minutes.\n    \n-   **Obstacle 4: The Crushing Bulkheads:** Heavy blast doors grind shut randomly. Success requires a DC 28 Perception, DC 30 Athletics, or DC 26 Starship Engineering Lore check. On a failure, the PC takes 6d6 bludgeoning damage and becomes Clumsy 1 for 10 minutes."}, {"id": "act_557674e3-a3cf-4136-b7e2-f6fabc6a9aa4", "type": "act", "order": 0, "title": "Phase III: The Station Core", "children": [{"id": "enc_081e6b8f-fd2a-4ffa-a014-e41f129b47d7", "type": "encounter", "order": 0, "title": "Krag the Unbroken, Syndicate Boss", "children": [{"id": "ch_3f211e5f-d5f1-4d5a-8184-6f349abde3ed", "type": "challenge", "order": 0, "title": "Environmental Mechanics: The Imperial Bombardment", "children": [], "difficulty": "normal", "description": "At the start of the environment''s turn (Initiative count 20), trigger the following effects:\n\n-   **Round 1:** Targeting lasers sweep the room. No mechanical effect.\n    \n-   **Round 2:** Bombardment strikes the outer ring. All creatures must succeed at a DC 28 Reflex save or take 4d6 bludgeoning damage.\n    \n-   **Round 3:** An industrial plasma cutter wildly sweeps the room. All creatures take 4d8 plasma damage (Basic Reflex save DC 28).\n    \n-   **Round 4:** The outer edges of the room shear away into the vacuum. Anyone outside a 30-foot central platform falls into the debris field and is removed from the fight.\n    \n-   **Round 5:** A direct turbolaser strike obliterates the vault.", "challenge_type": "hazard"}, {"id": "npc_6f983b50-3656-416c-b212-19c27a9b8f39", "npc": {"hp": {"max": 245, "current": 240}, "size": "Large", "level": 11, "speed": {"base": 25}, "senses": {}, "traits": ["Large", "Humanoid", "Dowutin"], "actions": [{"id": "98de7567-19b4-4a15-9fdb-63d9c805d627", "cost": "2 Actions", "name": "Seismic Cleave", "traits": "", "description": "Krag makes a Vibro-Ax Strike against all creatures within a 10-foot emanation. The area becomes difficult terrain."}, {"id": "81cbca61-4ea1-45e6-8a20-362b1a71a9ed", "cost": "1 Action", "name": "Repurpose Equipment", "traits": "Manipulate", "description": "Krag rips debris and hurls it. He makes a Ranged Strike (+22) against a target within 60 feet, dealing 3d10+10 bludgeoning damage."}, {"id": "9e92ee7d-1d85-4e2f-b0ba-e6c5ef970e23", "cost": "1 Action", "name": "Hurl Foe", "traits": "", "description": "Krag throws a Grabbed creature up to 30 feet. The creature takes 4d6 bludgeoning damage and falls Prone (a DC 28 Acrobatics check halves damage and prevents falling Prone)."}], "weapons": [{"id": "ba136463-20b0-4e8b-8ac6-eadbab8db465", "name": "Heavy Industrial Vibro-Ax", "type": "Melee", "traits": "Reach 10 feet, Sweep, Forceful", "attribute": "str", "damage_str": "2d12+13 slashing", "proficiency": "Expert"}, {"id": "4b0ecb38-d88a-498a-90db-12e66426ea77", "name": "Massive Fist", "type": "Melee", "traits": "Agile, Reach 10 feet", "attribute": "str", "damage_str": "2d8+13 bludgeoning plus Grab", "proficiency": "Expert"}], "attributes": {"cha": 2, "con": 6, "dex": -1, "int": -1, "str": 7, "wis": -1}, "proficiencies": {"skills": {"sklSurvival": "Trained", "sklAthletics": "Trained", "sklIntimidation": "Trained"}, "perception": "Legendary", "saving_throws": {"ref": "Expert", "fort": "Legendary", "will": "Legendary"}}, "armor_item_bonus": 2, "armor_proficiency_rank": "Master"}, "type": "npc", "order": 0, "title": "Krag the Unbroken, Syndicate Boss", "children": [], "description": "**Cybernetic Redundancies:** Immune to Bleed. Resistance 5 to physical damage. \n\n**Unshakable:** Immune to being Repositioned or Tripped by creatures smaller than Large."}], "difficulty": "normal", "description": "", "encounter_type": "combat"}], "description": "The PCs breach the reinforced doors of the central core.\n\n> The central core of the _Rust Anchor_ is a massive industrial processing vault. At the center, chained to a heavy durasteel pillar, is your prize: Dr. Aris Thorne. Standing over him is a massive, cybernetically augmented Dowutin boss hefting an industrial vibro-ax.\n> \n> \"You''ve ruined everything!\" the Dowutin roars. But before he charges, a deafening explosion rocks the station. The ceiling groans. Outside the viewport, TIE Bombers are making strafing runs. The Empire is destroying the station with everyone inside!"}, {"id": "act_b2e89aba-b859-403b-a3e2-8a1e24bfb752", "type": "act", "order": 0, "title": "Phase IV: Extraction and the Imperial Shadow", "children": [{"id": "enc_a0cb45ec-4550-4805-bd9f-cffc70ff0506", "type": "encounter", "order": 0, "title": "The Jump to Lightspeed (Cinematic Space Combat)", "children": [], "difficulty": "normal", "description": "The PCs must accumulate **5 Jump Points (JP)** to escape. The standard DC is **DC 30**.\n\n**Starship Actions**\n\n-   **Calculate Jump Vector (Science Officer) [2 Actions]:** DC 30 Computers. Crit Success yields 2 JP, Success yields 1 JP. Crit Failure loses 1 JP.\n    \n-   **Evasive Maneuvers (Pilot) [2 Actions]:** DC 30 Piloting. Success grants a +2 circumstance bonus to AC and Reflex saves (+3 on crit success).\n    \n-   **Divert Power to Nav-Computer (Engineer) [2 Actions]:** DC 30 Engineering Lore or Crafting. Success grants the next Science Officer a +2 circumstance bonus to Calculate Jump Vector.\n    \n-   **Point-Defense Fire (Gunner) [2 Actions]:** Ranged Strike (Dex + proficiency) vs TIE AC 31. On hit, deal 6d8+10 damage.\n    \n-   **Hold it Together! (Captain) [1 Action]:** DC 30 Diplomacy or Intimidation. Success grants a +1 status bonus to the next crew member''s starship action.\n    \n\n**Threats** **TIE Interceptor Wing** (Initiative: Piloting +24 | AC 31; Fort +18, Ref +24 | HP 100 | Weaknesses: Area damage 15)\n\n-   **[1 Action] Interceptor Swarm:** Gains a +2 status bonus to attack rolls.\n    \n-   **[2 Actions] Quad Laser Cannons:** Ranged Strike +24 against the PCs'' ship. Damage: 5d10+12 fire.\n    \n\n**The Star Destroyer''s Tractor Beam** (Initiative: Computers +20)\n\n-   **[1 Action] Magnetic Lock:** The Star Destroyer attempts to lock onto the party''s ship. The Pilot must attempt a DC 30 Piloting check. On a success, the Pilot breaks the lock. On a failure, the ship takes a –2 circumstance penalty to AC, and Science Officers take a –2 penalty to Calculate Jump Vector. To recover, the Pilot must spend 2 Actions on their next turn and succeed at a DC 32 Piloting check to break free.", "encounter_type": "space (cinematic)"}], "description": "As the station collapses, the reinforced elevator plummets to the hangar bays. The PCs board their ship and blast out, only to find an Imperial I-class Star Destroyer dropping into their flight path."}, {"id": "act_312f8594-ec93-4238-81d5-332ee27c94ea", "type": "act", "order": 0, "title": "Phase V: Debriefing and Aftermath", "children": [], "description": "Once the PCs reach 5 JP, the ship slams into hyperspace, leaving Director Valerius behind.\n\nWhen the PCs arrive at the Rebel fleet, General Rieekan receives Dr. Thorne and the Kuat Drive Yards shield-gate schematics. Delivering Thorne grants the PCs a high-priority payout of 1,400 credits each and a Level 11 or Level 12 item from the Alliance quartermaster. The PCs gain immense reputation within Alliance High Command, but they have publicly humiliated Director Valerius, who will dedicate significant Imperial resources to hunting them down as a persistent campaign antagonist."}]}',	'2026-04-13 13:31:24.103029+00',	'2026-04-17 19:40:23.702711+00'),
(3,	2,	'Echoes of the Purge',	NULL,	'draft',	'{"acts": [{"id": "act_8651882b-1788-48c4-88c9-aa4220659be0", "type": "act", "order": 0, "title": "Phase I: Mission Briefing", "children": [{"id": "scene_e783dfb3-5a23-4a94-9d2e-5ada7f779d5e", "type": "scene", "order": 0, "title": "The Briefing", "children": [{"id": "ch_b2ae006c-67a3-4de5-828f-afdb73485c02", "type": "challenge", "order": 0, "title": "The Imperial Blockade (Piloting or Starship Engineering Lore)", "children": [], "difficulty": "moderate", "description": "-   **Critical Success:** The PC identifies a flaw in the cruiser''s sensor rotation caused by electromagnetic interference, granting the Pilot a +2 circumstance bonus to their initial Piloting check in the space encounter.\n    \n-   **Success:** The PC recognizes that the TIE fighters rely heavily on the cruiser''s targeting telemetry; jamming the cruiser will effectively blind the fighters.\n    \n-   **Failure:** The PC confirms the ship is an _Arquitens_, but cannot pinpoint any actionable weaknesses.\n    \n-   **Critical Failure:** The PC incorrectly believes the cruiser has powered down its main batteries for maintenance.", "challenge_type": "skill_check"}, {"id": "ch_c79b1608-457f-43f0-a8e9-5a1fb3b5e072", "type": "challenge", "order": 0, "title": "The Inquisitorius (Society or Imperial Lore)", "children": [], "difficulty": "moderate", "description": "-   **Critical Success:** The PC knows Purge Troopers utilize weapons that bypass lightsaber deflection, and knows how to exploit their heavy armor plating, granting a +2 circumstance bonus to the first attack roll against a Purge Trooper.\n    \n-   **Success:** The PC knows Inquisitors use terror-based tactics to break their targets before striking, making Will saves paramount.\n    \n-   **Failure:** The PC only knows terrifying rumors about black-clad warriors.\n    \n-   **Critical Failure:** The PC recalls planted propaganda, believing Purge Troopers lack specialized training.", "challenge_type": "skill_check"}, {"id": "ch_51e1bc10-34f4-4b6d-86fa-3e884960e410", "type": "challenge", "order": 0, "title": "The Atmosphere of Aetoc-4 (Nature or Survival)", "children": [], "difficulty": "moderate", "description": "-   **Critical Success:** The PC realizes the storms are generated by metallic-barked apex trees that attract energy weapons, allowing the party to redirect missed shots during the ground phase.\n    \n-   **Success:** The PC understands the heavy canopy and storms render standard energy shields highly unpredictable.\n    \n-   **Failure:** The PC can''t glean anything beyond the fact that it is a stormy jungle.\n    \n-   **Critical Failure:** The PC believes the storms are purely upper-atmospheric and expects clear ground conditions.", "challenge_type": "skill_check"}, {"id": "ch_365747c8-319f-4a49-9ba5-5f3d597dcb2c", "type": "challenge", "order": 0, "title": "Echoes of the _Starfall_ (The Force)", "children": [], "difficulty": "moderate", "description": "-   **Critical Success:** The PC senses the exact layout of the _Starfall''s_ hidden vault and senses the Inquisitor has not yet breached it.\n    \n-   **Success:** The PC gains a distinct mental signature of their adversary, preventing the Inquisitor from successfully hiding or Ambushing the party later.\n    \n-   **Failure:** The overwhelming dark-side static clouds the PC''s mind.\n    \n-   **Critical Failure:** The PC suffers a psychic backlash, taking 2d6 mental damage and starting the first encounter Stupefied 1.", "challenge_type": "skill_check"}], "description": "The player characters are summoned to the command deck of the Rebel frigate _Defiance_ to receive their operational briefing. When the players are ready to begin, read or paraphrase the following:\n\n> The atmosphere inside the briefing room of the Rebel frigate _Defiance_ is tense. Holographic star-charts flicker in the dim light, casting an icy blue glow over the faces of the command staff.\n> \n> Commander Rist, a stern intelligence officer with a cybernetic arm, activates the central holotable. A projection of a dense, storm-wreathed forest moon materializes. \"This is Aetoc-4,\" Rist begins. \"Twelve hours ago, we intercepted Imperial comms traffic indicating they''ve found the _Starfall_—a Jedi transport that vanished during the Purge.\n> \n> Rist zooms in on the hologram, revealing the angular silhouette of an Imperial cruiser orbiting the moon. \"An _Arquitens_-class cruiser is blockading the moon, and they''ve deployed ground forces. If there are surviving Jedi artifacts, holocrons, or passengers aboard that transport, the Empire cannot be allowed to have them. Your mission is to punch through that blockade, navigate the jungle, and secure the _Starfall''s_ vault before the Inquisition tears it open.\"\n\n## Briefing Q&A\n\nAs veteran operatives, the PCs will want the tactical details. Commander Rist provides the following intel:\n\n-   **\"What are we flying?\"** \"We are assigning you the _Vanguard_, a modified stealth-corvette. It’s fast enough to outrun the cruiser''s main batteries. Due to the highly classified nature of its stealth drives, the _Vanguard_ is configured to automatically self-destruct if disabled or captured. You cannot afford to let the ship''s systems fail.\"\n    \n-   **\"Who exactly is on the ground?\"** \"The comms chatter was highly compartmentalized. Expect elite Purge Troopers. If an actual Inquisitor is leading the expedition, do not engage in a war of attrition. Grab the payload and extract immediately.\"\n    \n-   **\"What are the conditions on Aetoc-4?\"** \"Hostile. The moon’s atmosphere is saturated with electromagnetic storms. You’ll be flying blind, and the Imperials will be too.\""}], "description": ""}, {"id": "act_d39029b0-c94f-422f-8b6f-483f79bc6bde", "type": "act", "order": 0, "title": "Phase II: Blockade Run", "children": [{"id": "enc_75d7f006-dda9-4241-803f-8832279cb361", "type": "encounter", "order": 0, "title": "The Vanguard''s Descent", "children": [{"id": "ch_54288173-f1c3-47c4-a383-d1951b92d2ca", "type": "challenge", "order": 0, "title": "Captain", "children": [], "difficulty": "moderate", "description": "**Inspire Crew [1 Action]:** DC 23 Diplomacy or Intimidation\n\n- Success: Grant +1 circumstance bonus to the next crew member who attempts a starship action this round.", "challenge_type": "skill_check"}, {"id": "ch_64d17b73-b182-4a09-a8c8-c0b212d2b1b4", "type": "challenge", "order": 0, "title": "Engineer", "children": [], "difficulty": "moderate", "description": "**Reroute Power [2 Actions]:** DC 23 Crafting or DC 21 Starship Engineering Lore\n\n- Critical Success: Restore 30 HP to the Vanguard\n- Success: Restore 15 HP", "challenge_type": "skill_check"}, {"id": "ch_a59e9448-88a0-429a-9339-0714a139553a", "type": "challenge", "order": 0, "title": "Gunner", "children": [], "difficulty": "moderate", "description": "**Fire Laser Cannons [2 Actions]:** Ranged Strike (Dex + Martial proficiency) vs TIE AC (25). On hit, deal 4d8+6 plasma damage.", "challenge_type": "skill_check"}, {"id": "ch_c24d24bc-f783-4095-afa5-d14c98161f76", "type": "challenge", "order": 0, "title": "Pilot", "children": [], "difficulty": "moderate", "description": "**Punch It! (Drive):** DC 23 Piloting\n\n- Success: Gain VP equal to the number of actions spent\n- Critical Success: As success, but gain an additional VP\n- Critical Failure: Lose 1 VP; Vanguard takes 2d6 bludgeoning damage\n\n**Evasive Maneuvers [two-actions]:** DC 23 Piloting\n\n- Success: +2 circumstance bonus to the Vanguard''s AC for 1 round\n- Critical Success: As success, but the bonus lasts for 2 rounds\n- Critical Failure: -2 penalty to the Vanguard''s AC for 1 round; Pilot loses remaining actions", "challenge_type": "skill_check"}, {"id": "ch_fa89c41b-2462-4cd4-b568-74ff7dc75fd7", "type": "challenge", "order": 0, "title": "Science Officer", "children": [], "difficulty": "moderate", "description": "**Plot Trajectory [two-actions]:** DC 23 Computers or DC 21 Spacer Lore\n\n- Critical Success: 2 VP\n- Success: 1 VP\n- Critical Failure: Pilot takes a -2 circumstance penalty to their next Piloting check.\n    \n**Electronic Countermeasures [two-actions]:** DC 23 Computers\n\n- Success: TIE Patrol Wing takes a -2 circumstance penalty to attack rolls until the start of your next turn.", "challenge_type": "skill_check"}, {"id": "ch_ed3f22c5-5c19-4abb-a9bf-0c1fddbdbc5b", "type": "challenge", "order": 0, "title": "TIE Patrol Wing", "children": [], "difficulty": "moderate", "description": "**Initiative:** Piloting +18 | **AC** 25; **Saves** Fort +12, Ref +18 | **HP** 60 | **Weaknesses:** Area damage 10\n\n**Threat Routine (3 Actions):**\n\n-   **[1 Action] Swarm Tactics:** Gains a +2 status bonus to its attack rolls this turn.\n    \n-   **[2 Actions] Twin Laser Cannons:** Ranged Strike +17. _Damage:_ 3d10+8 plasma.", "challenge_type": "hazard"}, {"id": "ch_0383385e-6e5a-4a17-bdab-aa1aa04d3a29", "type": "challenge", "order": 0, "title": "Arquitens Cruiser", "children": [], "difficulty": "moderate", "description": "**Initiative:** Computers +14\n\n**Threat Routine (1 Action):**\n\n-   **[1 Action] Turbolaser Barrage:** The _Vanguard_ must attempt a **DC 23 basic Reflex save** (rolled by the Pilot) against 5d10 fire damage.", "challenge_type": "hazard"}], "difficulty": "moderate", "description": "**Victory Conditions:** The PCs must successfully breach the atmosphere by accumulating **6 Victory Points (VP)** before the end of the 5th round. If they survive 5 rounds but fail to reach 6 VP, they are intercepted by a second wave of TIEs and take heavy damage before crashing into the jungle.\n\n-   _Pre-Mission Intel:_ If the PCs critically succeeded on the Imperial Blockade check in Phase 1, they begin with **1 VP**.\n    \n-   _Destroying Pursuers:_ If the Gunner reduces the TIE Patrol Wing to 0 HP, the party immediately gains **2 VP**. A new TIE Patrol Wing spawns at the start of the next round.\n    \n\n**Available Roles:** Captain (1), Engineer (2), Gunner (2), Pilot (1), Science Officer (2)\n\n## The Vanguard\n\n**Starship Bonuses:** The _Vanguard''s_ advanced baffling grants a +2 item bonus to Computers checks made to Jam Sensors.\n\n**AC** 24; **Saves** Fort +15, Ref +18\n\n**Shields** 10 (regains 10 at the start of each round); **HP** 65\n\n**Classified Self-Destruct:** If reduced to 0 HP, the _Vanguard_ detonates, resulting in a total party kill.\n", "encounter_type": "combat"}], "description": "The PCs'' stealth-corvette drops out of hyperspace on the edge of the Aetoc-4 system, placing them face-to-face with the Imperial blockade.\n\n> The _Vanguard_ shudders as it reverts from hyperspace. Ahead, Aetoc-4 hangs like a bruised jewel, its atmosphere boiling with violet electromagnetic storms. Between you and the moon’s surface is the unmistakable dagger-shape of an Imperial _Arquitens_ cruiser. A swarm of twin-ion engine fighters detach from the cruiser''s hull, angling directly for your approach vector."}, {"id": "act_3ce8f6cf-a599-4e8c-a3d6-2af743dac47f", "type": "act", "order": 0, "title": "Phase III: The Ironwood Trek", "children": [{"id": "ch_dc807d9c-b12a-4262-9115-1500777e321e", "type": "challenge", "order": 0, "title": "Obstacle 1: The Sensor Ghosts", "children": [], "difficulty": "moderate", "description": "> The moon''s electromagnetic field is playing havoc with your gear. Your datapads show you walking in circles, and the scanners display massive, phantom heat signatures. How do you pierce this veil of interference or find the true path?\n\n-   **Survival (DC 23):** Track the physical devastation. _(Failure: 2d6 slashing damage)._\n    \n-   **Nature (DC 23):** Observe local fauna. _(Failure: Sickened 1)._\n    \n-   **Computers (DC 25):** Slice the scanner filters. _(Failure: 2d6 electricity damage)._\n    \n-   **Perception (DC 25):** Spot visual anomalies. _(Failure: -1 status penalty to Perception for 1 hour)._", "challenge_type": "skill_check"}, {"id": "ch_cf1fa3e3-e832-4ce1-bfe0-14a742a02096", "type": "challenge", "order": 0, "title": "Obstacle 2: The Viper-Probe Cordon", "children": [], "difficulty": "moderate", "description": "> The Inquisition has deployed a perimeter of hovering Viper probe droids. Their crimson photoreceptors sweep the metallic undergrowth in erratic patrol patterns. How do you bypass or dismantle this silent perimeter?\n\n-   **Stealth (DC 23):** Slip through gaps. _(Failure: 3d6 fire damage)._\n    \n-   **Thievery (DC 23):** Slice the transmission antenna. _(Failure: 3d6 electricity damage)._\n    \n-   **Athletics (DC 25):** Scale the trunks. _(Failure: 3d6 bludgeoning damage)._\n    \n-   **Deception (DC 25):** Create a false thermal signature. _(Failure: 3d6 fire damage)._", "challenge_type": "skill_check"}, {"id": "ch_2a6a47d0-fd31-4573-80f9-5ff56e93bac1", "type": "challenge", "order": 0, "title": "Obstacle 3: The Arcing Ironwood Grove", "children": [], "difficulty": "moderate", "description": "> The final approach is blocked by a dense grove of ironwood trees. The trees are actively absorbing the massive atmospheric storm. Thick bolts of chain-lightning violently arc between the trunks. How do you cross the grove without getting fried?\n\n-   **Acrobatics (DC 23):** Time your sprints. _(Failure: 4d6 electricity damage)._\n    \n-   **The Force (DC 23):** Sense the safest path. _(Failure: Stupefied 1)._\n    \n-   **Engineering Lore or Crafting (DC 25):** Build a grounding rod. _(Failure: 3d6 fire damage)._\n    \n-   **Medicine (DC 25):** Administer nerve-dampeners. _(Failure: 2d6 poison damage, Clumsy 1)._", "challenge_type": "skill_check"}], "description": "How the PCs begin this phase depends on their performance in Phase 2.\n\n-   **Clean Breach (6 VP):** The Pilot manages a controlled landing. The PCs can spend 10 minutes to Refocus, Treat Wounds, or Repair shields.\n    \n-   **Hard Crash (Survived, <6 VP):** The ship crashes. Every PC must attempt a **DC 23 basic Fortitude save** against 4d6 bludgeoning damage. There is no time to rest.\n\n**Challenge Outcomes (Tally Total Failures):**\n\n-   **0-2 Failures:** Arrive undetected. +2 circumstance bonus to Initiative.\n    \n-   **3-4 Failures:** Arrive exactly as Imperials breach the vault. Standard Initiative.\n    \n-   **5+ Failures:** Imperials lay an ambush. -2 circumstance penalty to Initiative; Imperials have advantageous cover."}, {"id": "act_bbe2db56-6188-4dc5-8038-38bda5ece3c7", "type": "act", "order": 0, "title": "Phase 4: The Starfall''s Vault", "children": [{"id": "enc_a206e2e5-e165-4afc-a8ac-68c3e79f5ca5", "type": "encounter", "order": 0, "title": "Combat: The Inquisition (Severe 7)", "children": [{"id": "ch_662c0797-3515-4dfe-a609-47ff1361e74f", "type": "challenge", "order": 0, "title": "The Seventh Brother, Imperial Inquisitor _Creature 8_ [Medium] [Humanoid] ", "children": [], "difficulty": "moderate", "description": "**Perception** +19 **Languages** Basic, High Galactic **Skills** Acrobatics +15, Deception +16, Intimidation +18, Society +14, The Force +20 **Attributes** Str +2, Dex +5, Con +3, Int +2, Wis +6, Cha +4 **Items** Inquisitor Vestments, Crimson Lightsaber\n\n### **AC** 27; **Fort** +15, **Ref** +17, **Will** +20 **HP** 135 **Dark Side Miasma (Aura, Emotion, Fear, Mental)** 30 feet. Enemies within the aura take a –1 status penalty to Will saving throws.\n\n**Speed** 30 feet\n\n**Melee** [1 Action] Crimson Lightsaber +20 [Finesse, Forceful, Sweep], **Damage** 2d8+5 slashing plus 1d6 fire\n\n**Ranged** [1 Action] Telekinetic Impact +20 [Connected, Force Power], **Range** 30 feet. **Damage** 4d8 bludgeoning. _(Spend 2 actions to deal 4d8+6 instead)._\n\n**Precognitive Parry** [Reaction] (Force Power, Sense) **Trigger:** The Inquisitor is hit by an attack from an enemy they can see. **Effect:** The Inquisitor foresaw the blow a split second before it landed. They gain a +2 circumstance bonus to AC against the triggering attack. If this bonus causes the attack to miss, they successfully parried it. **Connected Benefit:** If the attack misses, the Inquisitor can immediately Step (move 5 feet) as part of the reaction.\n\n**Open Connection** [1 Action] (Concentrate, Force Power) Enter the Connected state. _(Begins combat Connected)._\n\n**Niman Stance** [1 Action] (Form, Stance) **Requirements** Wielding a lightsaber. **Effect** A successful lightsaber Strike grants a +1 circumstance bonus to the DC or attack roll of the next Force Power used before the end of his next turn. Due to his mastery, using a Force Power also grants a +1 circumstance bonus to his next lightsaber Strike before the end of his next turn.\n\n**Draw Closer** [1 Action] (Form, Force Power) **Requirements** The Inquisitor is in Niman Stance. **Effect** The Inquisitor pulls an enemy within 30 feet into his blade. The target must succeed at a **DC 26 Fortitude save** or be pulled adjacent. If pulled adjacent, the Inquisitor immediately makes a lightsaber Strike against them. Due to his mastery, this Strike gains a +2 circumstance bonus.\n\n**Force Fear** [2 Actions] (Force Power, Mind, Emotion, Fear, Mental) **Target:** 1 living creature. **Effect:** The Inquisitor projects a nightmarish vision into the target''s mind. The target makes a **DC 26 Will save**. **Connected Benefit:** If the target is already Frightened, they take 4d6 mental damage.\n\n-   **Critical Success:** Unaffected.\n    \n-   **Success:** Frightened 1.\n    \n-   **Failure:** Frightened 2.\n    \n-   **Critical Failure:** Frightened 3 and Fleeing for 1 round.\n    \n\n**Force Push** [2 Actions] (Force Power, Offense, Alter) **Target:** 1 creature or object within 30 feet. **Effect:** The Inquisitor slams the target with a blast of compressed Force energy. The target makes a **DC 26 Fortitude save**. **Connected Benefit:** The Inquisitor can change the area from a single Target to a 15-foot Cone (all creatures in the cone save).\n\n-   **Success:** Pushed 5 feet.\n    \n-   **Failure:** Pushed 10 feet and takes 4d6 Bludgeoning damage.\n    \n-   **Critical Failure:** Pushed 20 feet, takes 5d6 Bludgeoning damage, and falls Prone.\n    \n\n**Force Lightning** [2 Actions] (Force Power, Offense, Electricity) **Area:** 30-foot cone. **Effect:** The Inquisitor unleashes a storm of violet lightning from his fingertips. All creatures in the cone take 8d6 Electricity damage (Basic Reflex save DC 26). **Connected Benefit:** The area increases to a 40-foot Cone.\n\n-   **Critical Failure:** Creatures that critically fail are Slowed 1 for 1 round as their muscles spasm.\n    \n\n**Force Choke** [2 Actions] (Force Power, Offense) **Target:** 1 living creature within 60 feet. **Effect:** The Inquisitor crushes the target''s windpipe. The target must make a **DC 26 Fortitude save**. **Connected Benefit:** The Inquisitor is not Slowed while Sustaining this power.\n\n-   **Success:** 4d8 Bludgeoning damage.\n    \n-   **Failure:** 6d8 Bludgeoning damage and is Grabbed by the Force.\n    \n-   **Critical Failure:** 10d8 Bludgeoning damage and is Restrained in the air (Off-Guard).\n    \n-   **Sustain:** The Inquisitor can Sustain this power. When he does, the target takes the damage again (Basic Fortitude save) and remains Grabbed/Restrained. While Sustaining this power, he is Slowed 1.", "challenge_type": "other"}, {"id": "ch_cc6af268-86b5-4e08-8b79-2a4285445509", "type": "challenge", "order": 0, "title": "Purge Trooper (x2) _Creature 6_ [Medium] [Humanoid] [Human] ", "children": [], "difficulty": "moderate", "description": "**Perception** +15; low-light vision (helmet visor) **Languages** Basic **Skills** Athletics +16, Intimidation +12, Survival +13 **Attributes** Str +5, Dex +3, Con +4, Int +0, Wis +2, Cha +0 **Items** Purge Trooper Armor (Heavy), Electrostaff\n\n### **AC** 24; **Fort** +17, **Ref** +14, **Will** +11 (+14 vs. Mental effects) **HP** 95 **Jedi Hunters:** Gain a +3 status bonus to all saving throws against mental effects. **Cortosis Plating:** Resistance 5 to Fire and Energy damage.\n\n**Speed** 25 feet (30 feet unarmored)\n\n**Melee** [1 Action] Electrostaff +17 [Parry, Reach, Sweep], **Damage** 1d8+8 bludgeoning plus 1d6 electricity\n\n**Melee** [1 Action] Armored Gauntlet +17 [Agile, Brawling], **Damage** 1d6+8 bludgeoning\n\n**Force Hunter''s Strike** [Reaction] **Trigger:** A creature within the Purge Trooper''s reach uses an action with the Concentrate trait. **Effect:** The Purge Trooper makes a melee Strike against the triggering creature. If the attack hits and deals damage, the triggering action is disrupted.\n\n**Overcharge Staff** [2 Actions] The Purge Trooper makes an Electrostaff Strike against up to three different enemies within their reach. This counts as two attacks for their multiple attack penalty, but the penalty doesn''t increase until after all attacks are resolved.", "challenge_type": "other"}], "difficulty": "severe", "description": "As the PCs clear the labyrinth, the jungle gives way to the crashed transport.\n\n> The _Starfall_ is a shattered leviathan of scorched metal. Standing before the glowing interior of the transport''s hidden vault is a striking figure draped in a charcoal-grey cloak.\n> \n> \"I felt you stumbling through the storm,\" the Inquisitor says. In their hand, a crimson lightsaber ignites with a vicious hiss. Flanking the vault are two massive Purge Troopers, the tips of their electrostaffs crackling. \"The Jedi are extinct. Whatever ghosts you are chasing end here.\"\n\n## Tactical Objectives & Environment\n\n-   **The Vault''s Light (Aura):** Any PC ending their turn within 15 feet of the vault entrance recovers 1d6 HP and gains a +1 status bonus to Will saves against Fear effects.\n    \n-   **Shattered Debris:** Jagged hull plating creates patches of difficult terrain.", "encounter_type": "combat"}], "description": ""}, {"id": "act_7e522029-7896-412e-bafa-fd65d9b9f1be", "type": "act", "order": 0, "title": "Phase 5: Debriefing and Aftermath", "children": [], "description": "Once the Inquisitor and the Purge Troopers fall, the oppressive dark side miasma lifts from the clearing. Inside the _Starfall_, the PCs find a perfectly preserved, ancient Jedi Holocron resting on a pedestal, untouched by the crash.\n\nWith the artifact secured, the PCs must return to the _Vanguard_ and blast off through the waning magnetic storm, jumping to hyperspace before the _Arquitens_ cruiser can scramble orbital reinforcements.\n\n## Return to the _Defiance_\n\nWhen the PCs arrive back at the Rebel fleet and meet with Commander Rist for their debriefing, read or paraphrase the following:\n\n> The command deck of the _Defiance_ is a hive of frantic activity, but Commander Rist stands in quiet awe as you place the ancient, glowing Holocron onto the holotable. The intricate crystalline matrix hums with a warm, calming light that seems to push back the sterile blue glow of the ship''s monitors.\n> \n> Rist exhales slowly, his cybernetic hand hovering just inches from the artifact. \"To think this survived the Purge... survived the Inquisition. The data analysts are already projecting what this means. Hidden enclaves, forgotten hyper-routes from the Old Republic—this gives us safe harbors the Empire doesn''t even know exist.\"\n> \n> He looks up, his stern expression replaced with genuine respect. \"You went toe-to-toe with the Emperor''s personal Jedi hunters and walked away with the prize. The Alliance owes you a debt we can likely never repay. Get some rest. You''ve earned it.\""}]}',	'2026-04-04 23:39:36.373621+00',	'2026-04-07 01:32:17.166007+00'),
(4,	2,	'The Ord Mantell Impound',	NULL,	'draft',	'{"acts": [{"id": "act_43f0db8b-0d68-4e45-98f3-aa8a732fd767", "type": "act", "order": 0, "title": "Phase I: The Briefing", "children": [{"id": "ch_3757dc60-2753-4eae-b701-4fa10dce8997", "type": "challenge", "order": 0, "title": "Ord Mantell & The Port Authority (Society DC 18, Underworld Lore DC 16, or Ord Mantell Lore DC 13)", "children": [], "difficulty": "normal", "description": "-   **Critical Success:** The PC knows the impound lot is run by Vargo, a boss currently losing a brutal turf war with a rival swoop gang. He is desperate for credits and deeply paranoid. The PC gains a +2 circumstance bonus to their initial interaction check with Vargo. The PC also knows the lower levels of the scrap heaps are plagued by toxic venting from ancient starship drives, which local gangs use to dispose of bodies.\n    \n-   **Success:** The PC knows Ord Mantell''s scrap economy is ruthless and the local authorities are entirely bought by syndicates. Flashing Republic or Imperial credentials will only escalate tensions. \"Scrap avalanches\" are a deadly and common environmental hazard.\n    \n-   **Failure:** The PC knows Ord Mantell is dangerous, but recalls nothing specific about the impound lot''s management or the terrain.\n    \n-   **Critical Failure:** The PC confidently, but incorrectly, recalls that a strict Imperial crackdown recently cleaned up this sector. They believe the port authority is legitimate, cannot be bribed, and is actively protected by stormtroopers.", "challenge_type": "skill_check"}, {"id": "ch_2784da06-1449-4020-90c3-23083b6b99f5", "type": "challenge", "order": 0, "title": "Impound Security (Computers DC 18 or Piloting DC 18)", "children": [], "difficulty": "normal", "description": "-   **Critical Success:** The PC identifies the exact model of the automated tractor-beam grid locking down the ships. They know it has a local manual override in the boss''s office, granting a +2 circumstance bonus to any Computers checks to slice or disable the system during the mission.\n    \n-   **Success:** The PC recognizes that simply powering up the ship won''t be enough. The facility uses a centralized, heavy-duty tractor beam to clamp ships to the landing pads. It must be disabled before takeoff, or the ship''s engines will rip themselves apart.\n    \n-   **Failure:** The security looks standard, but the PC can''t pinpoint any specific vulnerabilities.\n    \n-   **Critical Failure:** The PC misidentifies the tractor-beam emitters as obsolete junk. They believe the _Krayt''s Scale_ can easily overpower the clamps with maximum thrust.", "challenge_type": "skill_check"}, {"id": "ch_139e084e-9de4-400c-ad65-9b7aca6570db", "type": "challenge", "order": 0, "title": "The Experimental Cargo (Crafting DC 18 or Starship Engineering Lore DC 16)", "children": [], "difficulty": "normal", "description": "-   **Critical Success:** The PC knows this specific prototype uses a highly volatile power matrix. They recognize that if the housing takes physical damage during a firefight, it will trigger a localized EMP burst. The PC knows exactly how to stabilize it, granting them a free action to prevent a detonation if the crate is struck.\n    \n-   **Success:** The PC knows that military-grade ion prototypes are highly sought after but notoriously unstable. They understand the tech is sensitive and should be kept clear of stray blaster fire or heavy impacts.\n    \n-   **Failure:** The PC only knows that ion weapons are highly effective against droids and shields.\n    \n-   **Critical Failure:** The PC misidentifies the prototype as completely inert until installed in a starship''s power grid. They believe the cargo containers can be safely used as hard cover during a firefight without any risk.", "challenge_type": "skill_check"}, {"id": "ch_b5fd5c39-4cf7-4cfa-bc76-8879df191f0c", "type": "challenge", "order": 0, "title": "Sensing the Unseen (The Force DC 18)", "children": [], "difficulty": "normal", "description": "-   **Critical Success:** The PC senses a cold, methodical presence rapidly closing in on Ord Mantell. The Empire is already mobilizing a strike team. They know they are working on a strict time limit before the Imperial garrison arrives.\n    \n-   **Success:** The PC senses a tangle of greed, anxiety, and impending violence centered on the impound lot. The people holding the ship are on edge and ready to draw blasters at the slightest provocation.\n    \n-   **Failure:** The chaotic noise of billions of lives on Ord Mantell clouds the PC''s focus. The Force reveals nothing.\n    \n-   **Critical Failure:** The PC senses a profound, quiet calm. They incorrectly believe the Empire has completely lost the trail and that the party has all the time in the world to complete the mission.", "challenge_type": "skill_check"}], "description": "The player characters are summoned to a secure Rebel safehouse in a quiet sector of the Mid Rim to receive their briefing. When the players are ready to begin, read or paraphrase the following:\n\n> The flickering blue light of a holoprojector illuminates the dust motes dancing in the air of the safehouse. Captain Voren, a grizzled Rebel intelligence officer with tired eyes, leans over the table. He taps a console, bringing up a wireframe schematic of a heavily modified Corellian freighter.\n> \n> \"Command has an urgent extraction for you,\" Voren begins, his voice tight with stress. \"This is the _Krayt''s Scale_. Two rotations ago, it was impounded by the port authority on Ord Mantell for falsified transit codes. The local syndicate holding it doesn''t know what they have. Hidden in a shielded smuggling compartment beneath the main deck plating are stolen Imperial schematics and a prototype for a next-generation starship-scale ion weapon.\n> \n> We need that tech before the Empire tracks it down. Your mission is straightforward: get to the scrapyards of Ord Mantell, secure the release codes from the local port boss, and fly the _Krayt''s Scale_ out of there. Be careful—Ord Mantell is a hive of scum, and the Empire''s shadow is growing longer every day.\"\n\n## Briefing Q&A\n\nThe PCs likely have questions about the mission parameters. Captain Voren can provide the following answers:\n\n-   **\"Do we have credits to buy the ship back?\"** \"The Rebellion isn''t exactly flush with credits right now. I can authorize a slush fund of 300 credits for ''processing fees,'' but if this local boss wants the ship''s actual value, you''ll need to find another way to persuade him. Negotiate, intimidate, or slice the docking clamps and run.\"\n    \n-   **\"What kind of Imperial presence are we looking at?\"** \"Standard planetary garrison, mostly concentrated around the capital, Ten Mile City, and the major spaceports. The scrapyards are largely left to the syndicates, but if you make too much noise, the stormtroopers _will_ show up. Keep it quiet.\"\n    \n-   **\"What does the prototype look like?\"** \"The _Krayt''s Scale_ has a shielded compartment in the main cargo hold. Look for three heavy-duty, unmarked durasteel crates with localized coolant lines attached. Do not open them—just get the ship off the ground.\"\n    \n-   **\"Who exactly are we dealing with?\"** \"Local intel points to a mid-tier scrap-boss named Vargo. He runs a crew of Aqualish and Weequay thugs. He''s not Black Sun or Crimson Dawn, but he’s ambitious enough to be dangerous.\""}, {"id": "act_298d45d9-4040-4907-a0d5-5e9150a19c59", "type": "act", "order": 0, "title": "Phase II: Negotiating with Vargo", "children": [{"id": "scene_e6a9e855-371c-4ad1-b903-b7b92248ce95", "type": "scene", "order": 0, "title": "The Scrapyards of Ord Mantell", "children": [], "description": "Once the PCs secure their own vessel at the public docks, they must traverse the treacherous terrain of Ord Mantell to reach Vargo''s impound lot. When the players begin their trek, read or paraphrase the following:\n\n> The air on Ord Mantell tastes of copper and stale exhaust. A permanent, hazy pink-orange smog hangs over the scrapyards, casting long, bruised shadows across canyons of compressed starship hulls and rusted astromech chassis.\n> \n> The walk from the public docks takes you deep into the scrap-heaps. The ground beneath your boots isn''t dirt, but a compacted layer of stripped wires, sheared bolts, and shattered plasteel. A booming mechanical groan echoes through the canyon as a distant magnetic crane drops a crippled freighter onto a rusted mountain.\n> \n> Finally, you reach a clearing. Nestled in the center of a crater of junk is the impound lot, surrounded by a humming ray shield. Overlooking the lot is Vargo''s \"office\"—the gutted, rust-red command bubble of an old Clone Wars-era gunship, suspended from the jaws of a defunct crane by thick chains.\n\nA metal gantry leads up to the suspended gunship. Two burly Aqualish enforcers holding battered laser rifles flank the rusted door, but they only cross their weapons if the PCs draw their own or attempt to force their way inside. Otherwise, they silently gesture for the PCs to enter."}, {"id": "scene_450bc701-7f12-4f99-bc67-26333cd34c78", "type": "scene", "order": 0, "title": "Negotiating with Vargo", "children": [{"id": "ch_4312897a-d635-49d6-a54b-7a9a51719eff", "type": "challenge", "order": 0, "title": "Gaining an Audience", "children": [], "difficulty": "normal", "description": "Vargo glares down at the PCs as they enter. \"Lot''s closed,\" he grunts, shuffling a stack of physical datapads. \"Unless you''re here to pay off the _Starling''s_ docking fees, walk away.\" The PCs must make an opening impression to get Vargo to listen.\n\n-   **Diplomacy (DC 18):** Make a polite introduction and state they are here on business.\n    \n-   **Intimidation (DC 18):** Lock eyes with the enforcers and demand Vargo''s time.\n    \n-   **Underworld Lore or Ord Mantell Lore (DC 16):** Use proper syndicate etiquette and local slang to show they aren''t tourists.\n    \n-   **Perception (DC 20):** Notice the ledger on his desk is flashing red with debts, allowing the PC to smoothly transition into offering a lucrative deal.", "challenge_type": "skill_check"}, {"id": "ch_ccad6d75-6dcb-4a95-bc2c-2007cdd01fdc", "type": "challenge", "order": 0, "title": "The Pitch", "children": [], "difficulty": "normal", "description": "Vargo leans back, crossing his arms. \"Alright, you''re looking for a ship. The _Krayt''s Scale_. Funny thing... that ship''s transponder codes are scrambled, and the registry is fake. Makes me think it belongs to someone with deep pockets who doesn''t want to be found. So, what''s it worth to you?\" The PCs must convince Vargo to part with the ship without revealing its true value.\n\n-   **Deception (DC 18):** Spin a lie about the ship belonging to a bankrupt spice runner or being a worthless bucket of bolts.\n    \n-   **Mercantile Lore (DC 16):** Professionally haggle, pointing out the exorbitant cost of maintaining the impound lot''s ray shields to prove taking the 300 credits now is better than waiting.\n    \n-   **Engineering Lore (DC 16):** Casually rattle off a list of expensive, fabricated mechanical failures the _Krayt''s Scale_ supposedly has to drive down its perceived value.\n    \n-   **Diplomacy (DC 20):** Appeal to Vargo''s pragmatic side, offering Captain Voren''s 300 credits as a clean, untraceable transaction.", "challenge_type": "skill_check"}, {"id": "ch_5879f1f5-cbf4-49ab-b8da-af6020460033", "type": "challenge", "order": 0, "title": "The Pressure", "children": [], "difficulty": "normal", "description": "Vargo’s datapad suddenly chimes. He glances at it, and his expression sours. \"Well, this complicates things. That was an automated ping from the local Imperial garrison. They''re running a sweep of the sector, looking for contraband. They''ll be here in five minutes. I don''t want the heat, but I also don''t want to let a valuable asset go for cheap. Last chance to impress me.\" The PCs must finalize the deal immediately.\n\n-   **Intimidation (DC 18):** Threaten to loudly blast their way out, bringing the Empire crashing down right on Vargo''s head.\n    \n-   **Diplomacy (DC 18):** Urge Vargo that letting them take the ship _right now_ is the only way to get the contraband out of his lot before the stormtroopers arrive.\n    \n-   **The Force (DC 18):** A subtle mind trick. \"You want to give us the release codes and forget we were here.\" _(Note: If the PC critically fails this check, Vargo recognizes the mental intrusion and immediately orders his thugs to attack, ending the encounter)._", "challenge_type": "skill_check"}, {"id": "npc_e2ee31c0-a4dd-472f-972e-031d97df42f2", "npc": {"hp": {"max": 10, "current": 10}, "size": "Medium", "level": 1, "speed": {"base": 25}, "senses": {}, "traits": [], "actions": [], "weapons": [], "attributes": {"cha": 0, "con": 0, "dex": 0, "int": 0, "str": 0, "wis": 0}, "proficiencies": {"skills": {}, "perception": "Trained", "saving_throws": {"ref": "Trained", "fort": "Trained", "will": "Trained"}}, "armor_item_bonus": 0, "armor_proficiency_rank": "Trained"}, "type": "npc", "order": 0, "title": "New npc", "children": [], "description": ""}], "description": "Inside the cramped, 20-by-20-foot gunship cockpit, the PCs find Vargo, a scarred Weequay scrap-boss. He sits behind a heavy durasteel desk, an unlit cigarra clamped in his teeth.\n\nThis encounter uses the **Victory Point (VP)** subsystem to determine how successfully the PCs can secure the release codes for the _Krayt''s Scale_. The PCs must accumulate Victory Points over three distinct stages of conversation.\n\nThe base DC for checks in this encounter is **DC 18**. During each stage, a PC can attempt one of the listed skill checks, or use the Aid action to assist an ally''s primary check.\n\n-   **Critical Success:** Gain 2 VP.\n    \n-   **Success:** Gain 1 VP.\n    \n-   **Failure:** Gain 0 VP.\n    \n-   **Critical Failure:** Lose 1 VP.\n\n## Encounter Outcomes\n\nTally the party''s total Victory Points at the end of Stage 3 to determine the result.\n\n**High Success (5+ VP): The Professional Courtesy**\n\nVargo tosses the datachip containing the release codes to the PCs. \"Take it and get out. If the Empire asks, you stole it.\"\n\n-   **Reward:** The PCs secure the codes peacefully. They reach the _Krayt''s Scale_ with enough time to unlock the docking clamps and establish advantageous cover before the Imperial strike team arrives. All PCs gain a +2 circumstance bonus to their Initiative rolls for the upcoming Imperial encounter.\n    \n\n**Moderate Success (3-4 VP): The Extortion**\n\nVargo sneers. \"Fine. Give me the 300 credits, plus whatever you have in your pockets, and the codes are yours. But you''re dealing with the Imperials yourself.\"\n\n-   **Reward:** The PCs pay the bribe and grab the codes. They reach the hangar at the exact same time as the Imperial strike team. Standard Initiative rules apply for the upcoming Imperial encounter.\n    \n\n**Failure (2 or fewer VP): The Double-Cross**\n\nVargo draws his heavy projectile pistol. \"I think I''ll keep the ship, hand you over to the Imperials for the bounty, and take your credits anyway. Boys, blast ''em!\"\n\n-   **Penalty:** Vargo and his enforcers attack immediately in the cramped office (see **Combat: Vargo''s Office**). The PCs must defeat them to loot the release codes. Because of the delay, the Imperial strike team will ambush the PCs the moment they step out of the office."}, {"id": "enc_c2c22ee9-c628-4955-8419-eccb42a35428", "type": "encounter", "order": 0, "title": "Combat: Vargo''s Office (Normal 3)", "children": [], "difficulty": "normal", "description": "If negotiations break down, the PCs must fight Vargo and his enforcers in the suspended gunship cockpit.\n\n**Tactical Notes:** * **Cramped Quarters:** The office is only 20 by 20 feet. Vargo''s heavy durasteel desk provides standard cover (+2 AC).\n\n-   **Shattered Viewport (Hazard):** A character can use a 2-Action **Athletics** check (DC 18) to shatter the weakened viewport of the suspended office. Anyone adjacent to the broken window must succeed at a DC 18 Reflex save or fall 15 feet into a pile of scrap below, taking 7 (1d8+3) bludgeoning damage.\n    \n\n## Vargo, Syndicate Scrap-Boss _Creature 3_ [Medium] [Humanoid] [Weequay]\n**Perception** +9; low-light vision **Languages** Basic, Huttese, Weequay **Skills** Athletics +9, Deception +7, Intimidation +10, Stealth +7, Underworld Lore +8 **Attributes** Str +2, Dex +2, Con +3, Int +1, Wis +2, Cha +1 **Items** Heavy Projectile Pistol, Vibroknife, Armored Longcoat, Datachip (Impound Release Codes)\n### **AC** 19; **Fort** +10, **Ref** +7, **Will** +9 **HP** 45\n**Speed** 25 feet\n\n**Melee** [1 Action] Vibroknife +11 [Agile, Finesse], **Damage** 1d4+4 slashing\n\n**Ranged** [1 Action] Heavy Projectile Pistol +11 [Range increment 40 feet, Projectile], **Damage** 1d8+2 piercing\n\n**Scrap-Boss Orders** [1 Action] (Auditory, Concentrate) Vargo barks a command at one of his underlings. One allied Enforcer within 30 feet who can hear Vargo can immediately use their Reaction to either Stride or Strike.\n\n## Aqualish Enforcer (x2) _Creature 1_  [Medium] [Humanoid] [Aqualish] \n**Perception** +6 **Languages** Basic, Aqualish **Skills** Athletics +7, Intimidation +4, Survival +4 **Attributes** Str +3, Dex +1, Con +2, Int -1, Wis +1, Cha -1 **Items** Battered Laser Rifle, Brass Knuckles, Padded Armor\n\n### **AC** 16; **Fort** +7, **Ref** +6, **Will** +4 **HP** 20\n\n**Speed** 25 feet\n\n**Melee** [1 Action] Brass Knuckles +8 [Agile, Unarmed], **Damage** 1d4+3 bludgeoning\n\n**Ranged** [1 Action] Battered Laser Rifle +6 [Range increment 80 feet, Laser], **Damage** 1d8+1 fire\n\n**Thuggish Shove** [2 Actions] The enforcer makes a Brass Knuckles Strike against a target. If the attack hits, the target is also pushed 5 feet backwards.", "encounter_type": "combat"}], "description": ""}]}',	'2026-04-05 21:17:24.893802+00',	'2026-04-10 04:12:01.123557+00');

DROP TABLE IF EXISTS "Character";
DROP SEQUENCE IF EXISTS "public".character_characterid_seq;
CREATE SEQUENCE "public".character_characterid_seq INCREMENT 1 MINVALUE 1 MAXVALUE 9223372036854775807 CACHE 1;

CREATE TABLE "public"."Character" (
    "CharacterID" integer DEFAULT nextval('character_characterid_seq') NOT NULL,
    "Name" character varying NOT NULL,
    "Level" integer DEFAULT '1' NOT NULL,
    "AncestryID" character varying,
    "HeritageID" character varying,
    "ClassID" character varying,
    "SubclassID" character varying,
    "Attributes" jsonb,
    "Choices" jsonb,
    "BackgroundID" character varying,
    "Inventory" jsonb,
    "Credits" integer DEFAULT '150' NOT NULL,
    "Portrait" text,
    "OwnerID" integer NOT NULL,
    "HP_Current" integer,
    "HP_Temp" integer DEFAULT '0' NOT NULL,
    "Wounded" smallint DEFAULT '0' NOT NULL,
    "Dying" smallint DEFAULT '0' NOT NULL,
    "Personal" jsonb
)
WITH (oids = false);

INSERT INTO "Character" ("CharacterID", "Name", "Level", "AncestryID", "HeritageID", "ClassID", "SubclassID", "Attributes", "Choices", "BackgroundID", "Inventory", "Credits", "Portrait", "OwnerID", "HP_Current", "HP_Temp", "Wounded", "Dying", "Personal") VALUES
(122,	'Coria Russ',	11,	'ancTwilek',	NULL,	'clsOperative',	'subStriker',	'{}',	'{"skills": {"sklStealth": "Master", "sklPiloting": "Trained", "sklThievery": "Trained", "sklDeception": "Master", "sklAcrobatics": "Expert"}, "level_1_boost_1": "dex", "level_1_boost_2": "con", "level_1_boost_3": "cha", "level_1_boost_4": "wis", "level_5_boost_1": "dex", "level_5_boost_2": "con", "level_5_boost_3": "wis", "level_5_boost_4": "int", "ancestry_boost_1": "con", "level_10_boost_1": "dex", "level_10_boost_2": "con", "level_10_boost_3": "wis", "level_10_boost_4": "int", "background_boost_1": "con", "background_boost_2": "wis", "class_class_feat_1_1": "cftTacticalAdvance", "class_class_feat_2_0": "cftInstinctiveAim", "class_class_feat_4_0": "cftDevastatingAim", "class_class_feat_6_0": "cftHairTrigger", "class_class_feat_8_0": "cftTopplingShot", "class_skill_feat_2_1": "feaCatFall", "class_skill_feat_4_1": "feaExperiencedSmuggler", "class_skill_feat_6_1": "feaFeignDeath", "class_skill_feat_8_1": "feaFoilSenses", "class_class_feat_10_0": "cftOpportuneRetort", "class_skill_feat_10_1": "feaSwiftSneak", "class_general_feat_3_0": "feaSteadyBalance", "class_general_feat_7_0": "feaSlipperySecrets", "class_ancestry_feat_1_0": "aftArtfulEscape", "class_ancestry_feat_5_0": "aftRylothianGrace", "class_ancestry_feat_9_0": "aftTidalLockTwist", "class_clfSpecializedSkillSet_3_3_target_feat": "feaQuickJump", "class_clfSpecializedSkillSet_7_4_target_feat": "feaDeadlift", "subclass_clfSpecializedSkillSet_1_4_target_feat": "feaCombatClimber"}',	'bkgBountyHunter',	'[{"id": "idClimbingKitT", "bulk": "1", "name": "Climbing Kit (Tactical)", "level": 0, "price": "5", "traits": null, "equipped": true, "features": null, "is_valid": true, "quantity": 1, "container": null, "item_type": "item", "consumable": false, "equippable": true, "instance_id": "item_1774315279057", "is_container": false, "validation_notes": [], "contained_item_ids": [], "container_capacity": 0, "parent_container_id": null}, {"id": "id