": 1, "container": null, "item_type": "item", "consumable": false, "equippable": true, "instance_id": "item_1776121538228", "is_container": false, "validation_notes": [], "contained_item_ids": [], "container_capacity": 0, "parent_container_id": null}, {"id": "idRepairToolkitT", "bulk": "1", "name": "Repair Toolkit (Tactical)", "level": 3, "price": "250", "traits": "Toolkit", "equipped": false, "features": {"skill": {"conditional_bonus": [{"name": "Repair Toolkit", "value": "+1 item bonus to Repair.", "target": "sklCrafting"}]}}, "is_valid": true, "quantity": 1, "container": null, "item_type": "item", "consumable": false, "equippable": true, "instance_id": "item_1776121592389", "is_container": false, "validation_notes": [], "contained_item_ids": [], "container_capacity": 0, "parent_container_id": "granted_customrigfeature_customrig_0"}, {"id": "idMakersToolkitT", "bulk": "2", "name": "Maker''s Toolkit (Tactical)", "level": 3, "price": "500", "traits": "Toolkit", "equipped": false, "features": {"skill": {"conditional_bonus": [{"name": "Maker''s Toolkit", "value": "+1 item bonus to Craft.", "target": "sklCrafting"}]}}, "is_valid": true, "quantity": 1, "container": null, "item_type": "item", "consumable": false, "equippable": true, "instance_id": "item_1776121609603", "is_container": false, "validation_notes": [], "contained_item_ids": [], "container_capacity": 0, "parent_container_id": "granted_customrigfeature_customrig_0"}, {"id": "idInfiltratorsToolkitT", "bulk": "L", "name": "Infiltrator''s Toolkit (Tactical)", "level": 3, "price": "500", "traits": "Toolkit", "equipped": false, "features": {"skill": {"conditional_bonus": [{"name": "Infiltrator''s Toolkit", "value": "+1 item bonus to Pick Locks or Disable Devices.", "target": "sklThievery"}]}}, "is_valid": true, "quantity": 1, "container": null, "item_type": "item", "consumable": false, "equippable": true, "instance_id": "item_1776121641107", "is_container": false, "validation_notes": [], "contained_item_ids": [], "