DROP TABLE IF EXISTS "Class";
CREATE TABLE "public"."Class" (
    "ClassID" character varying NOT NULL,
    "Name" character varying,
    "Description" text,
    "Traits" character varying,
    "HP" smallint,
    "Summary" character varying,
    "Features" jsonb,
    CONSTRAINT "Class_ClassID" PRIMARY KEY ("ClassID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Class"."ClassID" IS 'Unique ClassID';

COMMENT ON COLUMN "public"."Class"."Name" IS 'Class Name';

COMMENT ON COLUMN "public"."Class"."Description" IS 'Class description text';

COMMENT ON COLUMN "public"."Class"."Traits" IS 'Traits';

COMMENT ON COLUMN "public"."Class"."HP" IS 'Hit die size';

COMMENT ON COLUMN "public"."Class"."Summary" IS 'Class short summary';

COMMENT ON COLUMN "public"."Class"."Features" IS 'Class progression data';

INSERT INTO "Class" ("ClassID", "Name", "Description", "Traits", "HP", "Summary", "Features") VALUES
('clsOperative',	'Operative',	'<p>You&#39;re a focused, quick-witted professional who thrives in high-stakes combat. Your deadly aim and tactical training give you an edge over the competition—for you, even the most powerful enemy is just another mark to take out. You have impressive prowess in your chosen field of specialization.</p>
<p><strong>Key Attribute:</strong>  <strong>Dexterity</strong><br>At 1st level, your class gives you an attribute boost to Dexterity.</p>
<p><strong>Hit Points: 8 plus your Constitution modifier</strong><br>You increase your maximum number of HP by this number at 1st level and every level thereafter.</p>
<h3 id="key-terms">Key Terms</h3>
<p>You&#39;ll see the following key terms in many operative class features.<br><strong>Aim:</strong>  An action used to focus on a target and deal additional precision damage.<br><strong>Expend:</strong>  The number of charges or ammunition a ranged weapon consumes each time the weapon is fired.<br><strong>Flourish:</strong>  Actions with this trait are special techniques that require too much exertion for you to perform frequently. You can use only one action with the flourish trait per round.<br><strong>Gun:</strong>  Any ranged weapon with the analog or tech trait.<br><strong>Mark:</strong>  The target of your Aim.</p>
<h2 id="roleplaying-the-operative">Roleplaying the Operative</h2>
<h3 id="during-combat-encounters-">During Combat Encounters…</h3>
<p>You attack and maneuver with tactical precision, whether you’re lining up the perfect headshot from a distance, dueling hand-to-hand, or trading shots at close range. At higher levels, you master your weapons of choice and rain calculated destruction on foes.</p>
<h3 id="during-social-encounters-">During Social Encounters…</h3>
<p>You might fall back on your training, speaking up to give strategic advice to your allies while remaining alert for strangers’ hidden agendas or take the lead about a subject you know.</p>
<h3 id="while-exploring-">While Exploring…</h3>
<p>You take a tactical position like point or rear guard and scan your surroundings, keeping your weapon ready for action.</p>
<h3 id="in-downtime-">In Downtime…</h3>
<p>You train with your weapons, acquire and upgrade equipment, and practice tactical drills for future engagements.</p>
<h3 id="you-might-">You Might…</h3>
<ul>
<li>Have trained with a military organization or mercenary group that you remain allied with or have defected from.</li>
<li>Work as a gun for hire to the highest bidder, taking any job for enough credits.</li>
</ul>
<h3 id="others-probably-">Others Probably…</h3>
<ul>
<li>Rely on you for strategic advice and firepower in a fight but feel put off by your talent for methodical violence.</li>
<li>Want to hire you as a bodyguard or mercenary.</li>
</ul>
<h2 id="initial-proficiencies">Initial Proficiencies</h2>
<p>At 1st level, you gain the listed proficiency ranks in the following statistics. You are untrained in anything not listed unless you gain a better proficiency rank in some other way.</p>
<h3 id="perception">Perception</h3>
<p>Expert in Perception</p>
<h3 id="saving-throws">Saving Throws</h3>
<p>Trained in Fortitude<br>Expert in Reflex<br>Expert in Will</p>
<h3 id="skills">Skills</h3>
<p>Trained in one skill determined by your specialization<br>Trained in a number of additional skills equal to 3 plus your Intelligence modifier</p>
<h3 id="attacks">Attacks</h3>
<p>Expert in simple guns<br>Expert in martial guns<br>Trained in advanced guns<br>Trained in simple weapons<br>Trained in martial weapons<br>Trained in unarmed attacks</p>
<h3 id="defenses">Defenses</h3>
<p>Trained in light armor<br>Trained in unarmored defense</p>
<h3 id="class-dc">Class DC</h3>
<p>Trained in operative class DC</p>
<h2 id="class-features">Class Features</h2>
<p>You gain these abilities as an Operative. Abilities gained at higher levels list the levels at which you gain them next to the features&#39; names.</p>
<table class="sci-fi-table" style="float: left; margin-right: 10px; width: 50%">
  <thead>
    <tr>
      <th>Your Level</th>
