<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Force Premonition</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 1</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Concentrate</span>
    <span class="trait-tag">Force Power</span>
    <span class="trait-tag">Fortune</span>
