('cftVengefulIntercession',	'Vengeful Intercession',	'You make them pay for hurting your friends. When you use the Intercede reaction, you gain a +2 circumstance bonus to damage rolls against the triggering enemy for 1 round.',	'[{"subclass": [{"id": "subCauseOfTheCrusader"}]}]',	'You make them pay for hurting your friends.',	'clsGuardian',	NULL,	'Guardian',	4,	'0',	NULL),
('cftOverclockStabilizer',	'Overclock Stabilizer',	'Your rig is designed to capture and recycle the excess energy generated by dangerous system surges. Whenever you succeed or critically succeed on an Overclock flat check, you immediately gain temporary Hit Points equal to your Intelligence modifier. These temporary Hit Points last until the end of your next turn.',	NULL,	'Your rig is designed to capture and recycle the excess energy generated by dangerous system surges.',	'clsTechSpecialist',	NULL,	'Tech Specialist',	1,	'0',	NULL),
('cftCruelOpportunity',	'Cruel Opportunity',	'You kick them while they are down. Whenever you hit a creature that is Prone or Stunned with a melee Strike, you deal an additional 1d6 precision damage.

',	'[{"subclass": [{"id": "subCauseOfTheDestroyer"}]}]',	'You kick them while they are down.',	'clsGuardian',	NULL,	'Guardian',	6,	'0',	NULL),
('cftSuddenCharge',	'Sudden Charge',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Sudden Charge</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Guardian<span>
    <span class="trait-tag">Flourish</span>
    <span class="trait-tag">Move</span>
  </div>

  <div class="power-card-meta-grid">
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You close the distance in the blink of an eye. You Stride twice. If you end your movement within melee reach of at least one enemy, you can make a melee Strike against that enemy.
  </div>
</div>',	NULL,	'You close the distance in the blink of an eye.',	'clsGuardian',	'{"action": {"grant": [{"id": "actSuddenCharge", "name": "Sudden Charge", "traits": "Guardian, Flourish, Move", "action_cost": "[two-actions]", "description": "You close the distance in the blink of an eye. You Stride twice. If you end your movement within melee reach of at least one enemy, you can make a melee Strike against that enemy."}]}}',	'Guardian, Flourish, Move',	8,	'0',	NULL),
('cftUnstoppableMovement',	'Unstoppable Movement',	'Nothing slows you down. You ignore the effects of difficult terrain, and you move through greater difficult terrain as if it were difficult terrain.

<strong>Focused Benefit</strong> You can Tumble Through enemy spaces without making a check, though you still treat their squares as difficult terrain.',	'[{"feat": [{"id": "cftForceAthleticism", "type": "class"}]}]',	'Nothing slows you down.',	'clsGuardian',	NULL,	'Guardian',	8,	'0',	NULL),
('cftSuppressingFirepower',	'Suppressing Firepower',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Suppressing Firepower</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
  </div>
  <div class="power-card-meta-grid">
