('cftExpandedSecrets',	'Expanded Secrets',	'<p>You have studied deep within the archives or meditated on the nature of the Cosmic Force. You gain one additional Force Power.</p>
<p><strong>Special</strong> You can select this feat more than once. You can take it again at 6th, 10th, 14th, and 18th levels. Each time you select it, you gain a different Force Power.</p>
',	NULL,	'You have studied deep within the archives or meditated on the nature of the Cosmic Force.',	'clsConsular',	'{"power": {"power_slot": [{"count": "1"}]}}',	'Consular',	2,	'1',	NULL),
('cftGrazingShot',	'Grazing Shot',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Grazing Shot</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
