  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
   You call out a specific foe. The target must make a Will save against your class DC.<br><br><strong>Success</strong> The target is unaffected.<br><strong>Failure</strong> The target takes a –2 status penalty to attack rolls against creatures other than you for 1 round.<br><strong>Critical Failure</strong> The target is compelled to move toward you and attack you on its next turn.
  </div>
</div>',	'[{"subclass": [{"id": "subCauseOfTheDuelist"}]}]',	'You call out a specific foe.',	'clsGuardian',	'{"action": {"grant": [{"id": "actCompelledDuel", "name": "Compelled Duel", "traits": "Guardian, Linguistic, Mental", "action_cost": "[one-action]", "description": "You call out a specific foe. The target must make a Will save against your class DC.<br><br><strong>Success</strong> The target is unaffected.<br><strong>Failure</strong> The target takes a –2 status penalty to attack rolls against creatures other than you for 1 round.<br><strong>Critical Failure</strong> The target is compelled to move toward you and attack you on its next turn."}]}}',	'Guardian, Linguistic, Mental',	1,	'0',	NULL),
('cftTelekineticWhirlwind',	'Telekinetic Whirlwind',	'<div class="power-card-display">
  <header class="power-card-header">
