</div>',	'[{"subclass": [{"id": "subCauseOfTheStalwart"}]}]',	'You root yourself with the Force.',	'clsGuardian',	'{"power": {"grant": [{"id": "powImmovableObject", "name": "Immovable Object", "level": 8, "traits": "Guardian, Force Power", "trigger": "You would be moved, pushed, or tripped by an external effect.", "action_cost": "[reaction]", "description": "You root yourself with the Force. You negate the movement or the Prone condition."}]}}',	'Guardian, Force Power',	8,	'0',	NULL),
('cftVitalityBurst',	'Vitality Burst',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Vitality Burst</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
    <div class="power-meta-top">
