    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Consular</span>
    <span class="trait-tag">Force Power</span>
    <span class="trait-tag">Connected</span>
    <span class="trait-tag">Overexertion</span>
    <span class="trait-tag">Healing</span>
  </div>
  <div class="power-card-meta-grid">
     </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You become a conduit for the Living Force, flooding the area with restorative light. You and all living allies in the area regain 6d8 Hit Points.
    <br><br>
    <strong>Heightened:</strong> This healing increases by 1d8 for every 2 levels you have beyond 11th.
  </div>
</div>',	'[{"subclass": [{"id": "subMandateOfLife"}]}]',	'You become a conduit for the Living Force, flooding the area with restorative light.',	'clsConsular',	'{"power": {"grant": [{"id": "powVitalityBurst", "name": "Vitality Burst", "level": 12, "traits": "Consular, Force Power, Connected, Overexertion, Healing", "action_cost": "[two-actions]", "description": "You become a conduit for the Living Force, flooding the area with restorative light. You and all living allies in the area regain 6d8 Hit Points.\n\n**Heightened:** This healing increases by 1d8 for every 2 levels you have beyond 11th."}]}}',	'Consular, Force Power, Healing, Connected, Overexertion',	12,	'0',	NULL),
('cftAbsorbEnergy',	'Absorb Energy',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Absorb Energy</h3>
      <span class="power-action-cost">[reaction]</span>
