    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Consular</span>
    <span class="trait-tag">Force Power</span>
    <span class="trait-tag">Sense</span>
    <span class="trait-tag">Connected</span>
  </div>
  <div class="power-card-meta-grid">
    <div>
      <strong>Range</strong>
      <span>30 feet</span>
    </div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You broadcast your sensory data to your team. Until the start of your next turn, all allies in the area gain the effect of your Mandate of Visions Connected Benefit.  If you also have the Force Sense consular feat, those allies gain the effects of that feat for the same duration.
  </div>
</div>',	'[{"subclass": [{"id": "subMandateOfVisions"}]}]',	'You broadcast your sensory data to your team.',	'clsConsular',	'{"power": {"grant": [{"id": "powSharedVision", "name": "Shared Vision", "level": 6, "range": "30 feet", "traits": "Consular, Force Power, Sense, Connected", "action_cost": "[one-action]", "description": "You broadcast your sensory data to your team. Until the start of your next turn, all allies in the area gain the effect of your Mandate of Visions Connected Benefit.  If you also have the Force Sense consular feat, those allies gain the effects of that feat for the same duration."}]}}',	'Consular, Force Power, Connected, Sense',	6,	'0',	NULL),
('cftQuake',	'Quake',	'<div class="power-card-display">
  <header class="power-card-header">
