('cftMagneticRepulsion',	'Magnetic Repulsion',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Magnetic Repulsion</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
    <span class="trait-tag">Manipulate</span>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You violently reverse the polarity of the ambient metals around you. All creatures in a 15-foot cone must succeed at a Fortitude save against your Tech Specialist Class DC or be pushed 5 feet away from you (10 feet on a critical failure). Until the start of your next turn, the area of the cone becomes difficult terrain for your enemies as jagged debris hovers in the air.
  </div>
</div>',	'[{"subclass": [{"id": "subScrapper"}]}]',	'You violently reverse the polarity of the ambient metals around you.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actMagneticRepulsion", "name": "Magnetic Repulsion", "traits": "Tech Specialist, Manipulate", "action_cost": "[two-actions]", "description": "You violently reverse the polarity of the ambient metals around you. All creatures in a 15-foot cone must succeed at a Fortitude save against your Tech Specialist Class DC or be pushed 5 feet away from you (10 feet on a critical failure). Until the start of your next turn, the area of the cone becomes difficult terrain for your enemies as jagged debris hovers in the air."}]}}',	'Tech Specialist, Manipulate',	10,	'0',	NULL),
('cftTerrorForming',	'Terror-Forming',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Terror-Forming</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Soldier</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You’re wielding an area or automatic weapon.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    Your weapon blasts apart the battlefield and leaves it a ruinous waste. You Area Fire or Auto-Fire. You don’t designate a primary target, but instead make each square in the area of your attack difficult terrain. If a square was already difficult terrain, it becomes greater difficult terrain. Any difficult or greater difficult terrain created by this action remains in place and can’t be changed without extensive engineering or magic.
  </div>
</div>',	NULL,	'Your weapon blasts apart the battlefield and leaves it a ruinous waste.',	'clsSoldier',	'{"action": {"grant": [{"id": "actTerrorForming", "name": "Terror-Forming", "traits": "Soldier", "action_cost": "[two-actions]", "description": "Your weapon blasts apart the battlefield and leaves it a ruinous waste. You Area Fire or Auto-Fire. You don’t designate a primary target, but instead make each square in the area of your attack difficult terrain. If a square was already difficult terrain, it becomes greater difficult terrain. Any difficult or greater difficult terrain created by this action remains in place and can’t be changed without extensive engineering or magic.", "requirements": "You’re wielding an area or automatic weapon."}]}}',	'Soldier',	14,	'0',	NULL),
('cftOmniRangeProtocols',	'Omni-Range Protocols',	'You have fundamentally upgraded your custom rig''s signal transmitters and wireless telemetry. The range of any Modification that you activate that has a range of at least 10 feet is doubled. If a Modification has a range of touch, its range becomes 30 feet.',	NULL,	'You have fundamentally upgraded your custom rig''s signal transmitters and wireless telemetry.',	'clsTechSpecialist',	NULL,	'Tech Specialist',	18,	'0',	NULL),
('cftAcquireAsset',	'Acquire Asset',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Acquire Asset</h3>
      <span class="power-action-cost">[one-action]</span>
