('cftNetworkBacklash',	'Network Backlash',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Network Backlash</h3>
      <span class="power-action-cost">[reaction]</span>
