('cftYoullHaveToGoThroughMe',	'You''ll Have to Go Through Me',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">You''ll Have to Go Through Me</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
