('cftScoutsCharge',	'Scout''s Charge',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Scout''s Charge</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Archetype</span>
    <span class="trait-tag">Flourish</span>
  </div>

  <div class="power-card-meta-grid">
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You meander around unpredictably, and then ambush your opponents without warning. Choose one enemy. Stride, Feint against that opponent, and then make a Strike against it. For your Feint, you can attempt a Stealth check instead of the Deception check that''s usually required, using the terrain around you to surprise your foe.
  </div>
</div>',	'[{"feat": [{"id": "cftScoutDedication", "type": "class"}]}]',	'You meander around unpredictably, and then ambush your opponents without warning.',	NULL,	'{"action": {"grant": [{"id": "actScoutsCharge", "name": "Scout''s Charge", "traits": "Archetype, Flourish", "action_cost": "[two-actions]", "description": "You meander around unpredictably, and then ambush your opponents without warning. Choose one enemy. Stride, Feint against that opponent, and then make a Strike against it. For your Feint, you can attempt a Stealth check instead of the Deception check that''s usually required, using the terrain around you to surprise your foe."}]}}',	'Archetype, Flourish',	4,	'0',	'arcScout'),
('cftScatteringFire',	'Scattering Fire',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Scattering Fire</h3>
