('cftPunitiveStrike',	'Punitive Strike',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Punitive Strike</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Soldier</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>A creature within your reach uses a manipulate action, makes a ranged Strike, uses a move action, or leaves a square during a move action it’s using.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    Your foe’s momentary lapse in defense gives you an opening Make a melee Strike against the triggering creature, ignoring the unwieldy trait on any weapons you’re wielding for this Strike. This Strike doesn’t count toward your multiple attack penalty, and your multiple attack penalty doesn’t apply to this Strike.
  </div>
</div>',	NULL,	'Your foe’s momentary lapse in defense gives you an opening Make a melee Strike against the triggering creature, ignoring the unwieldy trait on any weapons you’re wielding for this Strike.',	'clsSoldier',	'{"action": {"grant": [{"id": "actPunitiveStrike", "name": "Punitive Strike", "traits": "Soldier", "trigger": "A creature within your reach uses a manipulate action, makes a ranged Strike, uses a move action, or leaves a square during a move action it’s using.", "action_cost": "[reaction]", "description": "Your foe’s momentary lapse in defense gives you an opening Make a melee Strike against the triggering creature, ignoring the unwieldy trait on any weapons you’re wielding for this Strike. This Strike doesn’t count toward your multiple attack penalty, and your multiple attack penalty doesn’t apply to this Strike."}]}}',	'Soldier',	6,	'0',	NULL),
('cftQuip',	'Quip',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Quip</h3>
