('cftBasicSoldierTraining',	'Basic Soldier Training',	'You gain a 1st- or 2nd-level soldier feat.',	'[{"feat": [{"id": "cftSoldierDedication", "type": "class"}]}]',	'You gain a 1st- or 2nd-level soldier feat.',	NULL,	'{"feat": {"fixed": [{"id": "choice(''target_feat'')", "type": "class_feat"}]}, "inputs": [{"name": "target_feat", "type": "class_feat", "label": "Soldier Feat", "filter": {"trait": ["Soldier"], "max_level": 2}}]}',	'Archetype',	4,	'0',	'arcSoldier'),
('cftBeskarDeflection',	'Beskar Deflection',	'<strong>Requirements</strong> You are wearing medium or heavy armor made of beskar.<br><br><p>You have learned to catch lethal blows on the thickest plates of your armor. You gain the Shield Block reaction. You can use your beskar vambraces or pauldrons for this reaction as if you had a shield raised.</p>
<p>For the purposes of taking damage from a Shield Block, treat these reinforced areas as a separate item with statistics that scale based on the grade of your beskar armor. If this &quot;shield&quot; takes damage or is broken, it does not reduce your armor&#39;s Hit Points or impose any penalties to your Armor Class.</p>
<ul>
<li><p><strong>Commercial</strong> Hardness 10, HP 40, BT 20</p>
</li>
<li><p><strong>Tactical</strong> Hardness 13, HP 86, BT 43</p>
</li>
<li><p><strong>Advanced</strong> Hardness 13, HP 96, BT 48</p>
</li>
<li><p><strong>Superior</strong> Hardness 13, HP 108, BT 54</p>
</li>
<li><p><strong>Elite</strong> Hardness 15, HP 120, BT 60</p>
</li>
<li><p><strong>Ultimate</strong> Hardness 16, HP 140, BT 70</p>
</li>
<li><p><strong>Paragon</strong> Hardness 17, HP 160, BT 80</p>
</li>
</ul>
',	'[{"feat": [{"id": "cftMandalorianDedication", "type": "class"}]}]',	'You have learned to catch lethal blows on the thickest plates of your armor.',	NULL,	'{"action": {"grant": [{"id": "actShieldBlock", "name": "Shield Block", "traits": "Archetype", "trigger": "While you have your shield raised, you would take physical damage (bludgeoning, piercing, or slashing) from an attack.", "action_cost": "[reaction]", "description": "You snap your shield in place to ward off a blow. Your shield prevents you from taking an amount of damage up to the shield’s Hardness. You and the shield each take any remaining damage, possibly breaking or destroying the shield."}]}}',	'Archetype',	6,	'0',	'arcMandalorian'),
('cftBasicTechFeatures',	'Basic Tech Features',	'You expand your foundational tech knowledge. You gain a 1st- or 2nd-level Tech Specialist class feat.',	'[{"feat": [{"id": "cftTechSpecialistDedication", "type": "class"}]}]',	'You expand your foundational tech knowledge.',	NULL,	'{"feat": {"fixed": [{"id": "choice(''target_feat'')", "type": "class_feat"}]}, "inputs": [{"name": "target_feat", "type": "class_feat", "label": "Tech Specialist Feat", "filter": {"trait": ["Tech Specialist"], "max_level": 2}, "class_id": "clsTechSpecialist"}]}',	'Archetype',	4,	'0',	'arcTechSpecialist'),
('cftSearchHighAndLow',	'Search High and Low!',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Search High and Low!</h3>
      <span class="power-action-cost">[one-action] or [two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Envoy</span>
    <span class="trait-tag">Directive</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You alert your allies to look for enemies and hidden things in a stressful situation, coordinating their efforts so they can do so more efficiently. Until the beginning of your next turn, you and your allies gain a +2 circumstance bonus to Perception checks to Seek. As your envoy level increases, increase the bonus to +3 at 7th level, +4 at 12th level, and +5 at 17th level.<br><br><strong>Lead by Example</strong> If you used two actions, Seek. Each of your allies within 100 feet who can sense you can also immediately Seek as a reaction.
  </div>
</div>',	NULL,	'You alert your allies to look for enemies and hidden things in a stressful situation, coordinating their efforts so they can do so more efficiently.',	'clsEnvoy',	'{"action": {"grant": [{"id": "actSearchHighAndLow", "name": "Search High and Low!", "traits": "Envoy, Directive", "action_cost": "[one-action] or [two-actions]", "description": "You alert your allies to look for enemies and hidden things in a stressful situation, coordinating their efforts so they can do so more efficiently. Until the beginning of your next turn, you and your allies gain a +2 circumstance bonus to Perception checks to Seek. As your envoy level increases, increase the bonus to +3 at 7th level, +4 at 12th level, and +5 at 17th level.<br><br><strong>Lead by Example</strong> If you used two actions, Seek. Each of your allies within 100 feet who can sense you can also immediately Seek as a reaction."}]}}',	'Directive, Envoy',	2,	'0',	NULL),
('cftAdvancedSoldierTraining',	'Advanced Soldier Training',	'You gain one soldier feat. For the purpose of meeting its prerequisites, your soldier level is half your character level.<br><br><strong>Special</strong> You can select this feat more than once. Each time you do, you gain another soldier feat.',	'[{"feat": [{"id": "cftBasicSoldierTraining", "type": "class"}]}]',	'You gain one soldier feat.',	NULL,	'{"feat": {"fixed": [{"id": "choice(''target_feat'')", "type": "class_feat"}]}, "inputs": [{"name": "target_feat", "type": "class_feat", "label": "Soldier Feat", "filter": {"trait": ["Soldier"], "max_level": "{slot_level // 2}"}}]}',	'Archetype',	6,	'1',	'arcSoldier'),
('cftForcebreakersStrike',	'Forcebreaker''s Strike',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Forcebreaker''s Strike</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Archetype</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>A creature within your reach uses an action with the concentrate trait or the Force power trait.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You have been trained to recognize the subtle shifts in posture and focus that precede a Force power, and you know exactly how to punish them. You make a melee Strike against the triggering creature. If your attack is a critical hit, you disrupt the triggering action. This Strike does not count toward your multiple attack penalty, and your multiple attack penalty does not apply to it.
  </div>
</div>',	'[{"feat": [{"id": "cftMandalorianDedication", "type": "class"}]}]',	'You have been trained to recognize the subtle shifts in posture and focus that precede a Force power, and you know exactly how to punish them.',	NULL,	'{"action": {"grant": [{"id": "actForcebreakersStrike", "name": "Forcebreaker''s Strike", "traits": "Archetype", "trigger": "A creature within your reach uses an action with the concentrate trait or the Force power trait.", "action_cost": "[reaction]", "description": "You have been trained to recognize the subtle shifts in posture and focus that precede a Force power, and you know exactly how to punish them. You make a melee Strike against the triggering creature. If your attack is a critical hit, you disrupt the triggering action. This Strike does not count toward your multiple attack penalty, and your multiple attack penalty does not apply to it."}]}}',	'Archetype',	10,	'0',	'arcMandalorian'),
('cftExpandedModifications',	'Expanded Modifications',	'You upgrade your rig''s power draw and memory cache. You add two Level 7 Modifications to your Modification Library. Additionally, your capacity of simultaneously installed Modifications increases to two.',	'[{"feat": [{"id": "cftTechSpecialistDedication", "type": "class"}]}]',	'You upgrade your rig''s power draw and memory cache.',	NULL,	'{"7": {"modification": {"mod_slot": {"count": 1}, "library_slot": {"count": 2}}}}',	'Archetype',	8,	'0',	'arcTechSpecialist'),
('cftWidenForce',	'Widen Force',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Widen Force</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Consular</span>
    <span class="trait-tag">Concentrate</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You expand the aperture of your connection. You expand the aperture of your connection. If the next action you use is a Force Power that has an area (such as a Burst, Cone, or Line), increase the size of that area by 5 feet (for Bursts) or 10 feet (for Cones and Lines).
  </div>
</div>',	NULL,	'You expand the aperture of your connection.',	'clsConsular',	'{"action": {"grant": [{"id": "actWidenForce", "name": "Widen Force", "traits": "Consular, Concentrate", "action_cost": "[one-action]", "description": "You expand the aperture of your connection. You expand the aperture of your connection. If the next action you use is a Force Power that has an area (such as a Burst, Cone, or Line), increase the size of that area by 5 feet (for Bursts) or 10 feet (for Cones and Lines)."}]}}',	'Consular, Concentrate',	2,	'0',	NULL),
('cftReadyReload',	'Ready Reload',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Ready Reload</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Soldier</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You’re wielding a two-handed ranged weapon with a reload of 2 or more, and your last action was an attack that expended ammo from the weapon.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You know that reloading a weapon can be a delicate process, but you’ve mastered how to do so in the middle of combat, starting while still in the act of firing your weapon. Reduce your weapon’s reload cost by 1, then Interact to reload your weapon. Unlike most Interact actions, you don’t need a free hand to reload your ranged weapon in this way.
  </div>
</div>',	NULL,	'You know that reloading a weapon can be a delicate process, but you’ve mastered how to do so in the middle of combat, starting while still in the act of firing your weapon.',	'clsSoldier',	'{"action": {"grant": [{"id": "actReadyReload", "name": "Ready Reload", "traits": "Soldier", "action_cost": "[one-action]", "description": "You know that reloading a weapon can be a delicate process, but you’ve mastered how to do so in the middle of combat, starting while still in the act of firing your weapon. Reduce your weapon’s reload cost by 1, then Interact to reload your weapon. Unlike most Interact actions, you don’t need a free hand to reload your ranged weapon in this way.", "requirements": "You’re wielding a two-handed ranged weapon with a reload of 2 or more, and your last action was an attack that expended ammo from the weapon."}]}}',	'Soldier',	1,	'0',	NULL),
('cftExplosiveDeflection',	'Explosive Deflection',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Explosive Deflection</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Operative</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>You’re in the area of a grenade explosion.</span>
    </div>
    <div>
      <strong>Requirements</strong>
      <span>You''re aware of the attack, wielding a gun, and not off-guard.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You attempt to detonate the grenade with a well-timed shot from your gun. Expend an amount of ammunition from your gun equal to its usage, as if you’d fired the gun. You gain a +4 circumstance bonus to your Reflex save against the triggering grenade. Determine if you succeed on your save before rolling for anyone else in the area. If you succeed on your Reflex save, you cause the grenade to explode prematurely. Select a space of your choice directly between you and the attacker. The deflected grenade explodes in the selected space, and you don’t need to save again if you’re in the new explosion area.
  </div>
</div>',	NULL,	'You attempt to detonate the grenade with a well-timed shot from your gun.',	'clsOperative',	'{"action": {"grant": [{"id": "actExplosiveDeflection", "name": "Explosive Deflection", "traits": "Operative", "trigger": "You’re in the area of a grenade explosion.", "action_cost": "[reaction]", "description": "You attempt to detonate the grenade with a well-timed shot from your gun. Expend an amount of ammunition from your gun equal to its usage, as if you’d fired the gun. You gain a +4 circumstance bonus to your Reflex save against the triggering grenade. Determine if you succeed on your save before rolling for anyone else in the area. If you succeed on your Reflex save, you cause the grenade to explode prematurely. Select a space of your choice directly between you and the attacker. The deflected grenade explodes in the selected space, and you don’t need to save again if you’re in the new explosion area.", "requirements": "You''re aware of the attack, wielding a gun, and not off-guard."}]}}',	'Operative',	16,	'0',	NULL),
('cftBountyHunterDedication',	'Bounty Hunter Dedication',	'When focused on finding your quarry, you’re relentless. You gain the Hunt Prey action. You can use Hunt Prey to designate a creature that you’ve observed, heard about, or learned about through some other means, such as a bounty board or wanted poster. In addition to the other benefits of Hunt Prey, you can designate a target as your prey while Gathering Information about them, in addition to designating them as your prey when Tracking them as normal. If you have already identified your target and selected them as your prey, you gain a +2 circumstance bonus to checks to Gather Information about them.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Hunt Prey</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Archetype</span>
    <span class="trait-tag">Concentrate</span>
  </div>

  <div class="power-card-meta-grid">
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You designate a single creature as your prey and focus your attacks against that creature. You must be able to see or hear the prey, or you must be tracking the prey during exploration. You gain a +2 circumstance bonus to Perception checks when you Seek your prey and a +2 circumstance bonus to Survival checks when you Track your prey. You also ignore the penalty for making ranged attacks within your second range increment against the prey you''re hunting.<br><br>You can have only one creature designated as your prey at a time. If you use Hunt Prey against a creature when you already have a creature designated, the prior creature loses the designation and the new prey gains the designation. Your designation lasts until your next daily preparations.
  </div>
</div>',	NULL,	'When focused on finding your quarry, you’re relentless.',	NULL,	'{"action": {"grant": [{"id": "actHuntPrey", "name": "Hunt Prey", "traits": "Archetype, Concentrate", "action_cost": "[one-action]", "description": "You designate a single creature as your prey and focus your attacks against that creature. You must be able to see or hear the prey, or you must be tracking the prey during exploration. You gain a +2 circumstance bonus to Perception checks when you Seek your prey and a +2 circumstance bonus to Survival checks when you Track your prey. You also ignore the penalty for making ranged attacks within your second range increment against the prey you''re hunting.<br><br>You can have only one creature designated as your prey at a time. If you use Hunt Prey against a creature when you already have a creature designated, the prior creature loses the designation and the new prey gains the designation. Your designation lasts until your next daily preparations."}]}}',	'Archetype, Dedication',	2,	'0',	'arcBountyHunter'),
('cftEnvoyDedication',	'Envoy Dedication',	'You gain the envoy directives class feature (see Envoy), but do not gain the Lead by Example benefits of the Get ''Em! envoy directive. You become trained in Deception, Diplomacy, or Intimidation plus another skill of your choice. If you were already trained in Deception, Diplomacy, and Intimidation, you instead become trained in an additional skill of your choice. You also become trained in envoy class DC.',	'[{"attribute": [{"cha": 2}]}]',	'You gain the envoy directives class feature (see Envoy), but do not gain the Lead by Example benefits of the Get ''Em! envoy directive.',	NULL,	'{"dc": [{"name": "Envoy Class DC", "rank": "Trained", "attribute": "CHA"}], "skill": {"grant": {"count": 1, "label": "requires Deception, Diplomacy, or Intimidation", "filter": [{"id": ["sklDeception", "sklDiplomacy", "sklIntimidation"]}]}, "skill_increase": [{"max": "Trained", "count": 1}]}, "feature": ["clfEnvoyDirectives", "clfEnvoyInitialProficiencies"]}',	'Archetype, Dedication, Multiclass',	2,	'0',	'arcEnvoy'),
('cftGuardianDedication',	'Guardian Dedication',	'You have adopted the physical perfection and martial discipline of the Jedi Guardians. You become trained in Athletics and The Force. If you are already trained in both of these skills, you instead become trained in a skill of your choice.

You become trained in simple weapons and lightsabers, as well as the guardian class DC.

Additionally, you gain one 1st- or 2nd-level Guardian class feat with the form trait.<br><br><strong>Special</strong> You cannot select another dedication feat until you have gained at least two other feats from the Guardian archetype.',	'[{"attribute": [{"str": 2}]}]',	'You have adopted the physical perfection and martial discipline of the Jedi Guardians.',	NULL,	'{"dc": [{"name": "Guardian Class DC", "rank": "Trained", "attribute": "STR"}], "feat": {"fixed": [{"id": "choice(''form_feat'')", "type": "class"}]}, "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Trained"}]}, "attack": [{"simple": {"rank": "Trained"}}, {"group": [{"lightsaber": {"rank": "Trained"}}]}], "inputs": [{"name": "form_feat", "type": "class_feat", "label": "Form Feat", "filter": {"trait": ["Form"]}}]}',	'Archetype, Dedication, Multiclass',	2,	'0',	'arcGuardian'),
('cftConsularDedication',	'Consular Dedication',	'You have opened your mind to the cosmic energy of the galaxy, practicing the mystic arts of the Consular. You become trained in The Force and your choice of Diplomacy or Intimidation. If you are already trained in both of these skills, you instead become trained in a skill of your choice.

You become trained in simple weapons and lightsabers. You become trained in consular class DC. Additionally, you learn one 1st-level Force Power of your choice. You cannot choose a Force Power that requires the Connected state.
Special: You cannot select another dedication feat until you have gained at least two other feats from the Consular archetype.',	'[{"attribute": [{"wis": 2}]}]',	'You have opened your mind to the cosmic energy of the galaxy, practicing the mystic arts of the Consular.',	NULL,	'{"dc": [{"name": "Consular Class DC", "rank": "Trained", "attribute": "WIS"}], "power": {"power_slot": [{"count": 1, "level": 1}]}, "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}], "grant": {"count": 1, "label": "requires Diplomacy or Intimidation", "filter": [{"id": ["sklDiplomacy", "sklIntimidation"]}]}}, "attack": [{"simple": {"rank": "Trained"}}, {"group": [{"lightsaber": {"rank": "Trained"}}]}]}',	'Archetype, Dedication, Multiclass',	2,	'0',	'arcConsular'),
('cftSuppressiveShot',	'Suppressive Shot',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Suppressive Shot</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
  </div>
  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You are wielding a ranged weapon.</span>
    </div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You lay down a precise, overwhelming pattern of fire designed to pin an enemy down. Make a ranged Strike. If it hits, you deal damage normally, and the target is suppressed until the start of your next turn. If your Strike is a critical hit, the target is suppressed until the end of your next turn.
  </div>
</div>',	NULL,	'You lay down a precise, overwhelming pattern of fire designed to force an enemy to keep their head down.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actSuppressiveShot", "name": "Suppressive Shot", "traits": "Tech Specialist", "action_cost": "[two-actions]", "description": "You lay down a precise, overwhelming pattern of fire designed to pin an enemy down. Make a ranged Strike. If it succeeds, the target is suppressed until the start of your next turn. If your Strike is a critical hit, the target is suppressed until the end of your next turn.", "requirements": "You are wielding a ranged weapon."}]}}',	'Tech Specialist',	2,	'0',	NULL),
('cftPerfectOpportunity',	'Perfect Opportunity',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Perfect Opportunity</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Sentinel</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>You are the target of a hostile action, or an enemy moves adjacent to you.</span>
    </div>
    <div>
      <strong>Frequency</strong>
      <span>once per day</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You act before they can complete their thought. You take a full turn immediately (3 actions). After this interrupt turn is over, you are Stunned 3 (losing your next normal turn).
  </div>
</div>',	NULL,	'You act before they can complete their thought.',	'clsSentinel',	'{"action": {"grant": [{"id": "actPerfectOpportunity", "name": "Perfect Opportunity", "traits": "Sentinel", "trigger": "You are the target of a hostile action, or an enemy moves adjacent to you.", "frequency": "once per day", "action_cost": "[reaction]", "description": "You act before they can complete their thought. You take a full turn immediately (3 actions). After this interrupt turn is over, you are Stunned 3 (losing your next normal turn)."}]}}',	'Sentinel',	20,	'0',	NULL),
('cftUnforseenPreparation',	'Unforseen Preparation',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Unforseen Preparation</h3>
      <span class="power-action-cost">[free-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Sentinel</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>You encounter a hazard, obstacle, or missing item that hinders your progress.</span>
    </div>
    <div>
      <strong>Frequency</strong>
      <span>once per day</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You reveal that you foresaw this moment and prepared accordingly. You produce a mundane item of Light Bulk or less (like a keycard, a specific tool, or a breathing mask) that you "packed earlier."<br><br>Alternatively, you can attempt a Thievery, Computers, or Stealth check to overcome an obstacle (like unlocking a door or slicing a terminal) instantly, explaining that you actually performed the action minutes ago while the guards weren''t looking.
  </div>
</div>',	NULL,	'You reveal that you foresaw this moment and prepared accordingly.',	'clsSentinel',	'{"action": {"grant": [{"id": "actUnforseenPreparation", "name": "Unforseen Preparation", "traits": "Sentinel", "trigger": "You encounter a hazard, obstacle, or missing item that hinders your progress.", "frequency": "once per day", "action_cost": "[free-action]", "description": "You reveal that you foresaw this moment and prepared accordingly. You produce a mundane item of Light Bulk or less (like a keycard, a specific tool, or a breathing mask) that you \"packed earlier.\"\n\nAlternatively, you can attempt a Thievery, Computers, or Stealth check to overcome an obstacle (like unlocking a door or slicing a terminal) instantly, explaining that you actually performed the action minutes ago while the guards weren''t looking."}]}}',	'Sentinel',	14,	'0',	NULL),
('cftDidacticStrike',	'Didactic Strike',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Didactic Strike</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Sentinel</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You used Force Premonition and hit the target.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You expose the enemy''s fatal flaw to your team. Until the start of your next turn, all allies treat the target as Off-Guard, and their attacks deal an additional 2d6 precision damage.
  </div>
</div>',	'[{"feat": [{"id": "cftSharedPremonition", "type": "class"}]}]',	'You expose the enemy''s fatal flaw to your team.',	'clsSentinel',	'{"action": {"grant": [{"id": "actDidacticStrike", "name": "Didactic Strike", "traits": "Sentinel", "action_cost": "[one-action]", "description": "You expose the enemy''s fatal flaw to your team. Until the start of your next turn, all allies treat the target as Off-Guard, and their attacks deal an additional 2d6 precision damage.", "requirements": "You used Force Premonition and hit the target."}]}}',	'Sentinel',	16,	'0',	NULL),
('cftDualFocus',	'Dual Focus',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Dual Focus</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Consular</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You split your mind to maintain two complex weaves. If you currently have two active Force Powers that require Sustaining, you Sustain both of them with this single action.
  </div>
</div>',	NULL,	'You split your mind to maintain two complex weaves. ',	'clsConsular',	'{"action": {"grant": [{"id": "actDualFocus", "name": "Dual Focus", "traits": "Consular", "action_cost": "[one-action]", "description": "You split your mind to maintain two complex weaves. If you currently have two active Force Powers that require Sustaining, you Sustain both of them with this single action."}]}}',	'Consular, Connected',	10,	'0',	NULL),
('cftPredictiveDefense',	'Predictive Defense',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Predictive Defense</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Sentinel</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You have used Force Premonition this round.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You use your foresight to defend yourself rather than attack. You gain a +2 circumstance bonus to AC against the target of your Premonition until the start of your next turn. If your Premonition Roll was a natural 15 or higher, this bonus increases to +4.
  </div>
</div>',	NULL,	'You use your foresight to defend yourself rather than attack.',	'clsSentinel',	'{"action": {"grant": [{"id": "actPredictiveDefense", "name": "Predictive Defense", "traits": "Sentinel", "action_cost": "[one-action]", "description": "You use your foresight to defend yourself rather than attack. You gain a +2 circumstance bonus to AC against the target of your Premonition until the start of your next turn. If your Premonition Roll was a natural 15 or higher, this bonus increases to +4.", "requirements": "You have used Force Premonition this round."}]}}',	'Sentinel',	4,	'0',	NULL),
('cftRocketJump',	'Rocket Jump',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Rocket Jump</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Soldier</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You’re wielding an area (burst) weapon.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You fire your weapon as you jump, using the explosion to propel yourself to new heights or just out of a situation more dangerous than an explosion. You make an Area Fire and then Leap, using your weapon to add a status bonus to the distance traveled equal to double the burst of your weapon. You must be somewhere within the area of the weapon''s area attack, but you don''t have to save against the effect of your attack.<br><br>Movement made as part of this action doesn''t trigger reactions, though Area Fire still triggers them normally.
  </div>
</div>',	NULL,	'You fire your weapon as you jump, using the explosion to propel yourself to new heights or just out of a situation more dangerous than an explosion.',	'clsSoldier',	'{"action": {"grant": [{"id": "actRocketJump", "name": "Rocket Jump", "traits": "Soldier", "action_cost": "[two-actions]", "description": "You fire your weapon as you jump, using the explosion to propel yourself to new heights or just out of a situation more dangerous than an explosion. You make an Area Fire and then Leap, using your weapon to add a status bonus to the distance traveled equal to double the burst of your weapon. You must be somewhere within the area of the weapon''s area attack, but you don''t have to save against the effect of your attack.\n\nMovement made as part of this action doesn''t trigger reactions, though Area Fire still triggers them normally.", "requirements": "You’re wielding an area (burst) weapon."}]}}',	'Soldier',	12,	'0',	NULL),
('cftHairTrigger',	'Hair Trigger',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Hair Trigger</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Operative</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>The last creature you Aimed at since the start of your last turn uses a manipulate action or a move action, makes a ranged attack, or leaves a square during a move action.</span>
    </div>
    <div>
      <strong>Requirements</strong>
      <span>You’re wielding a gun.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You attempt a ranged Strike against the triggering creature. This Strike doesn’t count toward your multiple attack penalty, and your multiple attack penalty doesn’t apply to this Strike.
  </div>
</div>',	NULL,	'You attempt a ranged Strike against the triggering creature.',	'clsOperative',	'{"action": {"grant": [{"id": "actHairTrigger", "name": "Hair Trigger", "traits": "Operative", "trigger": "The last creature you Aimed at since the start of your last turn uses a manipulate action or a move action, makes a ranged attack, or leaves a square during a move action.", "action_cost": "[reaction]", "description": "You attempt a ranged Strike against the triggering creature. This Strike doesn’t count toward your multiple attack penalty, and your multiple attack penalty doesn’t apply to this Strike.", "requirements": "You’re wielding a gun."}]}}',	'Operative',	6,	'0',	NULL),
('cftAssaultOfTheVornskr',	'Assault of the Vornskr',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Assault of the Vornskr</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Form</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You are in Juyo Stance.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You unleash a chaotic flurry. Make three melee Strikes. These strikes take a –4 penalty (for the second) and –8 penalty (for the third) instead of the usual penalties. After the attacks, you are Off-Guard until the start of your next turn.<br><br><strong>Guardian Mastery</strong> You are not Off-Guard after using this ability.
  </div>
</div>',	'[{"feat": [{"id": "cftVornskrsFerocity", "type": "form"}]}]',	'You unleash a chaotic flurry.',	NULL,	'{"action": {"grant": [{"id": "actAssaultOfTheVornskr", "name": "Assault of the Vornskr", "traits": "Form", "action_cost": "[two-actions]", "description": "You unleash a chaotic flurry. Make three melee Strikes. These strikes take a –4 penalty (for the second) and –8 penalty (for the third) instead of the usual penalties. After the attacks, you are Off-Guard until the start of your next turn.<br><br><strong>Guardian Mastery</strong> You are not Off-Guard after using this ability.", "requirements": "You are in Juyo Stance."}]}}',	'Form',	8,	'0',	NULL),
('cftTargetingSafeties',	'Targeting Safeties',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Targeting Safeties</h3>
      <span class="power-action-cost">[free-action]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
    <span class="trait-tag">Manipulate</span>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You rapidly alter the IFF (Identify Friend/Foe) parameters of your ordnance. If your next action is to activate a Modification with an area (such as a cone, line, or burst), you can select a number of 5-foot squares within the area equal to your Intelligence modifier. Those squares are entirely unaffected by the Modification.
  </div>
</div>',	NULL,	'You rapidly alter the IFF (Identify Friend/Foe) parameters of your ordnance.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actTargetingSafeties", "name": "Targeting Safeties", "traits": "Tech Specialist, Manipulate", "action_cost": "[free-action]", "description": "You rapidly alter the IFF (Identify Friend/Foe) parameters of your ordnance. If your next action is to activate a Modification with an area (such as a cone, line, or burst), you can select a number of 5-foot squares within the area equal to your Intelligence modifier. Those squares are entirely unaffected by the Modification."}]}}',	'Tech Specialist, Manipulate',	2,	'0',	NULL),
('cftSharedPremonition',	'Shared Premonition',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Shared Premonition</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Sentinel</span>
    <span class="trait-tag">Auditory</span>
    <span class="trait-tag">Linguistic</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You have used Force Premonition this round but have not performed a Strike against the target.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You shout a warning or coordinate fire. Choose an ally who can hear you. The next time that ally attacks your Premonition target before the start of your next turn, the target is Off-Guard to them and the ally deals an additional 1d6 precision damage on a hit.
  </div>
</div>',	NULL,	'You shout a warning or coordinate fire.',	'clsSentinel',	'{"action": {"grant": [{"id": "actSharedPremonition", "name": "Shared Premonition", "traits": "Sentinel, Auditory, Linguistic", "action_cost": "[one-action]", "description": "You shout a warning or coordinate fire. Choose an ally who can hear you. The next time that ally attacks your Premonition target before the start of your next turn, the target is Off-Guard to them and the ally deals an additional 1d6 precision damage on a hit.", "requirements": "You have used Force Premonition this round but have not performed a Strike against the target."}]}}',	'Sentinel, Auditory, Linguistic',	2,	'0',	NULL),
('cftRangedInoculation',	'Ranged Inoculation',	'You have integrated micro-darts or localized teleportation into your medical dispensers. When you activate a Modification with the Healing trait that has a range of Touch (such as Kolto Burst or Stim-Injector), you can increase its range to 30 feet.',	'[{"subclass": [{"id": "subBioTech"}]}]',	'You have integrated micro-darts or localized teleportation into your medical dispensers.',	'clsTechSpecialist',	NULL,	'Tech Specialist',	2,	'0',	NULL),
('cftAdvancedDroidUpgrade',	'Advanced Droid Upgrade',	'You heavily modify your droid for specialized field operations. Your droid companion''s proficiency rank for unarmed attacks and unarmored defense increases to master. Its Dexterity modifier increases by 2 and its Strength and Constitution modifiers increase by 1.<br><br>Integrated Advanced Tools: The droid''s integrated tools are upgraded to Advanced-grade, granting a +2 item bonus to the relevant skill checks.<br><br>Choose one of the following hardware specializations for your droid:<br><br>Infiltrator-Spec: Your droid is optimized for stealth and evasion. Its proficiency rank in Stealth increases to expert, and its Speed increases by 10 feet. It gains an active optical camouflage system, allowing it to use the Hide action even if it does not have cover or concealment.<br><br>Escort-Spec: Your droid is optimized to protect you in firefights. Its unarmed attacks deal 3 additional damage. It gains a miniaturized deflector shield generator. When you roll Initiative, the droid grants Temporary Hit Points equal to its level to itself and one ally in its space or an adjacent square (usually you).',	'[{"subclass": [{"id": "subDroidwright"}]}]',	'You heavily modify your droid for specialized field operations.',	'clsTechSpecialist',	'{"minion": {"apply_template": "mature", "template_choice": {"key": "companion_type", "label": "Companion Type", "options": ["escort", "infiltrator"]}}}',	'Tech Specialist',	8,	'0',	NULL),
('cftFallingAvalanche',	'Falling Avalanche',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Falling Avalanche</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Form</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You are in Shien / Djem So Stance.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You raise your saber high and bring it down with crushing force. Make a melee Strike. This counts as two attacks for your multiple attack penalty. If you hit, you deal two extra dice of weapon damage.<br><br><strong>Guardian Mastery</strong> If you hit, the target is also knocked Prone.
  </div>
</div>',	'[{"feat": [{"id": "cftShienDjemSoStance", "type": "form"}]}]',	'You raise your saber high and bring it down with crushing force.',	NULL,	'{"action": {"grant": [{"id": "actFallingAvalanche", "name": "Falling Avalanche", "traits": "Form", "action_cost": "[two-actions]", "description": "You raise your saber high and bring it down with crushing force. Make a melee Strike. This counts as two attacks for your multiple attack penalty. If you hit, you deal two extra dice of weapon damage.<br><br><strong>Guardian Mastery</strong> If you hit, the target is also knocked Prone.", "requirements": "You are in Shien / Djem So Stance."}]}}',	'Form',	4,	'0',	NULL),
('cftRelentlessCurrent',	'Relentless Current',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Relentless Current</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Form</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>You reduce a creature to 0 HP with a Lightsaber Strike.</span>
    </div>
    <div>
      <strong>Requirements</strong>
      <span>You are in Shii-Cho Stance.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    The flow of the Force does not stop. You immediately make another Strike against a different creature within your reach. This strike does not count toward your Multiple Attack Penalty.<br><br><strong>Guardian Mastery</strong> You can Step before making the extra Strike.
  </div>
</div>',	'[{"feat": [{"id": "cftDisarmingBlast", "type": "form"}]}]',	'The flow of the Force does not stop.',	NULL,	'{"action": {"grant": [{"id": "actRelentlessCurrent", "name": "Relentless Current", "traits": "Form", "trigger": "You reduce a creature to 0 HP with a Lightsaber Strike.", "action_cost": "[reaction]", "description": "The flow of the Force does not stop. You immediately make another Strike against a different creature within your reach. This strike does not count toward your Multiple Attack Penalty.<br><br><strong>Guardian Mastery</strong> You can Step before making the extra Strike.", "requirements": "You are in Shii-Cho Stance."}]}}',	'Form',	14,	'0',	NULL),
('cftPushingSlash',	'Pushing Slash',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Pushing Slash</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 8</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Form</span>
    <span class="trait-tag">Force Power</span>
  </div>
  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You are in Niman Stance.</span>
    </div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You imbue your blade with telekinetic energy. Make a melee Strike. If it hits, deal normal damage plus 2d6 Force damage, and the target is pushed 10 feet away.<br><br><strong>Guardian Mastery</strong> If the strike is a Critical Hit, the target is pushed 30 feet and falls Prone.
  </div>
</div>',	'[{"feat": [{"id": "cftDrawCloser", "type": "form"}]}]',	'You imbue your blade with telekinetic energy.',	NULL,	'{"power": {"grant": [{"id": "powPushingSlash", "name": "Pushing Slash", "traits": "Form, Force Power", "action_cost": "[two-actions]", "description": "You imbue your blade with telekinetic energy. Make a melee Strike. If it hits, deal normal damage plus 2d6 Force damage, and the target is pushed 10 feet away.<br><br><strong>Guardian Mastery</strong> If the strike is a Critical Hit, the target is pushed 30 feet and falls Prone.", "requirements": "You are in Niman Stance."}]}}',	'Form',	8,	'0',	NULL),
('cftInstinctiveAim',	'Instinctive Aim',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Instinctive Aim</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Operative</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You draw your gun and take careful aim with the same motion. You Interact to draw a ranged weapon or Switch Hands and then Aim with that ranged weapon.
  </div>
</div>',	NULL,	'You draw your gun and take careful aim with the same motion.',	'clsOperative',	'{"action": {"grant": [{"id": "cftInstinctiveAim", "name": "Instinctive Aim", "traits": "Operative", "action_cost": "[one-action]", "description": "You draw your gun and take careful aim with the same motion. You Interact to draw a ranged weapon or Switch Hands and then Aim with that ranged weapon."}]}}',	'Operative',	1,	'0',	NULL),
('cftTacticalReposition',	'Tactical Reposition',	'You have optimized your rig''s power cycling to compensate for your physical movement. When you activate an installed Modification that takes exactly 2 actions to activate, you can Stride up to half your Speed as a free action either immediately before or immediately after activating the modification.',	NULL,	'You have optimized your rig''s power cycling to compensate for your physical movement.',	'clsTechSpecialist',	NULL,	'Tech Specialist',	8,	'0',	NULL),
('cftMasterModifications',	'Master Modifications',	'You integrate highly restricted, military-grade schematics into your rig. You add two Level 15 Modifications to your Modification Library. Additionally, your capacity of simultaneously installed Modifications increases to three.',	'[{"feat": [{"id": "cftExpandedModifications", "type": "class"}]}]',	'You integrate highly restricted, military-grade schematics into your rig.',	NULL,	'{"15": {"modification": {"mod_slot": {"count": 1}, "library_slot": {"count": 2}}}}',	'Archetype',	16,	'0',	'arcTechSpecialist'),
('cftAdrenalineSurge',	'Adrenaline Surge',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Adrenaline Surge</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
  </div>
  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>An ally you can see within 30 feet is reduced to 0 Hit Points.</span>
    </div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You maintain a linked biometric monitoring system that triggers automated, localized stimulant patches. The triggering ally can immediately Interact to pick up a dropped item, or Step as a free action. If they have the dying condition, their dying value does not increase from taking damage until the start of their next turn.
  </div>
</div>',	'[{"subclass": [{"id": "subBioTech"}]}]',	'You maintain a linked biometric monitoring system that triggers automated, localized stimulant patches.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actAdrenalineSurge", "name": "Adrenaline Surge", "traits": "Tech Specialist", "trigger": "An ally you can see within 30 feet is reduced to 0 Hit Points.", "action_cost": "[reaction]", "description": "You maintain a linked biometric monitoring system that triggers automated, localized stimulant patches. The triggering ally can immediately Interact to pick up a dropped item, or Step as a free action. If they have the dying condition, their dying value does not increase from taking damage until the start of their next turn."}]}}',	'Tech Specialist',	4,	'0',	NULL),
('cftAtaruStance',	'Form IV: Ataru',	'The acrobat''s form. Ataru relies on speed, jumping, and using the entire environment as a weapon. It is exhausting but overwhelming.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Ataru Stance</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Form</span>
    <span class="trait-tag">Stance</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You are wielding a lightsaber.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You enter a kinetic, acrobatic rhythm. While in this stance, you can Tumble Through the spaces of enemies even if they are larger than you. If you succeed at a Tumble Through check, enemies are Off-Guard against your attacks until the end of your turn.<br><br><strong>Guardian Mastery</strong> You gain a +10-foot status bonus to your Speed. You do not provoke Reactions when you Move (Stride, Step, or Jump).
  </div>
</div>',	'[{"attack": [{"group": [{"lightsaber": {"rank": "Trained"}}]}]}]',	'The acrobat''s form. Ataru relies on speed, jumping, and using the entire environment as a weapon. It is exhausting but overwhelming.',	NULL,	'{"action": {"grant": [{"id": "actAtaruStance", "name": "Ataru Stance", "traits": "Form, Stance", "action_cost": "[one-action]", "description": "You enter a kinetic, acrobatic rhythm. While in this stance, you can Tumble Through the spaces of enemies even if they are larger than you. If you succeed at a Tumble Through check, enemies are Off-Guard against your attacks until the end of your turn.<br><br><strong>Guardian Mastery</strong> You gain a +10-foot status bonus to your Speed. You do not provoke Reactions when you Move (Stride, Step, or Jump).", "requirements": "You are wielding a lightsaber."}]}}',	'Form, Stance',	1,	'0',	NULL),
('cftSecondWind',	'Second Wind',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Second Wind</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Guardian</span>
    <span class="trait-tag">Focused</span>
    <span class="trait-tag">Healing</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Frequency</strong>
      <span>once per day</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You dig deep into your reserves. You regain Hit Points equal to Level × Constitution modifier. You also gain a +2 circumstance bonus to AC until the start of your next turn.
  </div>
</div>',	NULL,	'You dig deep into your reserves.',	'clsGuardian',	'{"action": {"grant": [{"id": "actSecondWind", "name": "Second Wind", "traits": "Guardian, Focused, Healing", "frequency": "once per day", "action_cost": "[one-action]", "description": "You dig deep into your reserves. You regain Hit Points equal to Level × Constitution modifier. You also gain a +2 circumstance bonus to AC until the start of your next turn."}]}}',	'Guardian, Focused, Healing',	16,	'0',	NULL),
('cftLifesResurgence',	'Life''s Resurgence',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Life''s Resurgence</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
