('cftReachOfTheForce',	'Reach of the Force',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Reach of the Force</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Consular</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You extend your consciousness beyond your normal limits. If the next action you use is a Force Power with a range, increase that range by 30 feet. If the power has a range of touch, you can target a creature within 30 feet.
  </div>
</div>',	NULL,	'You extend your consciousness beyond your normal limits.',	'clsConsular',	'{"action": {"grant": [{"id": "actReachOfTheForce", "name": "Reach of the Force", "traits": "Consular", "action_cost": "[one-action]", "description": "You extend your consciousness beyond your normal limits. If the next action you use is a Force Power with a range, increase that range by 30 feet. If the power has a range of touch, you can target a creature within 30 feet."}]}}',	'Consular',	1,	'0',	NULL),
('cftTakeEmAlive',	'Take ‘Em Alive!',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Take ‘Em Alive!</h3>
      <span class="power-action-cost">[one-action] or [two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Envoy</span>
    <span class="trait-tag">Directive</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You urge your allies to take down your enemies without incurring any loss of life. Until the beginning of your next turn, you and your allies can add the nonlethal trait to your attacks with weapons (without taking the normal penalty), and to your spells that deal damage and don''t have the death or void trait.<br><br><strong>Lead by Example</strong> If you used two actions, Strike a target with a nonlethal attack. On a success, you gain a status bonus to damage equal to your Charisma modifier. On a critical success, an ally within 30 feet can Strike the target as a reaction using a nonlethal attack.
  </div>
</div>',	NULL,	'You urge your allies to take down your enemies without incurring any loss of life.',	'clsEnvoy',	'{"action": {"grant": [{"id": "actTakeEmAlive", "name": "Take ‘Em Alive!", "traits": "Envoy, Directive", "action_cost": "[one-action] or [two-actions]", "description": "You urge your allies to take down your enemies without incurring any loss of life. Until the beginning of your next turn, you and your allies can add the nonlethal trait to your attacks with weapons (without taking the normal penalty), and to your spells that deal damage and don''t have the death or void trait.<br><br><strong>Lead by Example</strong> If you used two actions, Strike a target with a nonlethal attack. On a success, you gain a status bonus to damage equal to your Charisma modifier. On a critical success, an ally within 30 feet can Strike the target as a reaction using a nonlethal attack."}]}}',	'Directive, Envoy',	1,	'0',	NULL),
('cftNotInTheFace',	'Not in the Face',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Not in the Face</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Envoy</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>A creature targets you with a melee attack.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You wave your arms to shield your face from harm and cower, acting meek and pitiful. Attempt a Deception check against the triggering creature''s Will DC. The triggering creature is then immune to Not in the Face for 1 hour.<br><br><strong>Critical Success</strong> Your attacker has second thoughts about harming you and is thoroughly thrown off. It takes a –2 status penalty to attack and damage rolls against you until the start of its next turn.<br><strong>Success</strong> Your attacker is thrown off. It takes a –1 status penalty to attack rolls against you until the start of its next turn.<br><strong>Failure</strong> Your attacker is temporarily thrown off. It takes a –1 status penalty to the triggering attack roll.<br><strong>Critical Failure</strong> Your attacker is unaffected.
  </div>
</div>',	'[{"skill": [{"id": "sklDeception", "rank": "Trained"}]}]',	'You wave your arms to shield your face from harm and cower, acting meek and pitiful.',	'clsEnvoy',	'{"action": {"grant": [{"id": "actNotInTheFace", "name": "Not in the Face", "traits": "Envoy", "trigger": "A creature targets you with a melee attack.", "action_cost": "[reaction]", "description": "You wave your arms to shield your face from harm and cower, acting meek and pitiful. Attempt a Deception check against the triggering creature''s Will DC. The triggering creature is then immune to Not in the Face for 1 hour.<br><br><strong>Critical Success</strong> Your attacker has second thoughts about harming you and is thoroughly thrown off. It takes a –2 status penalty to attack and damage rolls against you until the start of its next turn.<br><strong>Success</strong> Your attacker is thrown off. It takes a –1 status penalty to attack rolls against you until the start of its next turn.<br><strong>Failure</strong> Your attacker is temporarily thrown off. It takes a –1 status penalty to the triggering attack roll.<br><strong>Critical Failure</strong> Your attacker is unaffected."}]}}',	'Envoy',	4,	'0',	NULL),
('cftChangeOfPlans',	'Change of Plans',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Change of Plans</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Envoy</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>The target of your Get ''Em! is reduced to 0 Hit Points.</span>
    </div>
    <div>
      <strong>Requirements</strong>
      <span>You used Get ''Em! against a creature on your last turn.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    When the target you directed your allies to take down falls unconscious or is destroyed, you quickly direct them at another target. You use Get ’Em! against a new target following all the normal targeting restrictions for Get ''Em! You don’t count as leading by example against this new target.
  </div>
</div>',	NULL,	'When the target you directed your allies to take down falls unconscious or is destroyed, you quickly direct them at another target.',	'clsEnvoy',	'{"action": {"grant": [{"id": "actChangeOfPlans", "name": "Change of Plans", "traits": "Envoy", "trigger": "The target of your Get ''Em! is reduced to 0 Hit Points.", "action_cost": "[reaction]", "description": "When the target you directed your allies to take down falls unconscious or is destroyed, you quickly direct them at another target. You use Get ’Em! against a new target following all the normal targeting restrictions for Get ''Em! You don’t count as leading by example against this new target.", "requirements": "You used Get ''Em! against a creature on your last turn."}]}}',	'Envoy',	2,	'0',	NULL),
('cftHangInThere',	'Hang in There',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Hang in There</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Envoy</span>
    <span class="trait-tag">Healing</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You encourage yourself or an ally, psyching them up for a coming challenge and granting them temporary Hit Points. Choose yourself or an ally within 30 feet, then attempt a DC 20 Diplomacy check. If you have master proficiency in Diplomacy, you can instead attempt a DC 30 Diplomacy check to increase the temporary Hit Points gained on a successful check by 5. If you have legendary proficiency, you can instead attempt a DC 40 Diplomacy check to increase the temporary Hit Points gained on a successful check by 10. These temporary Hit Points last for 1 minute. The target is then temporarily immune to your Hang in There for 1 day.<br><br><strong>Critical Success</strong> The target gains temporary Hit Points equal to double their level plus your Charisma modifier.<br><strong>Success</strong> The target gains temporary Hit Points equal to their level plus your Charisma modifier.<br><strong>Failure</strong> The target is unaffected, and you can''t use Hang in There again for 1 minute.<br><strong>Critical Failure</strong> The target is unaffected, and you can''t use Hang in There again for 1 hour.
  </div>
</div>',	'[{"skill": [{"id": "sklDiplomacy", "rank": "Expert"}]}]',	'You encourage yourself or an ally, psyching them up for a coming challenge and granting them temporary Hit Points.',	'clsEnvoy',	'{"action": {"grant": [{"id": "actHangInThere", "name": "Hang in There", "traits": "Envoy, Healing", "action_cost": "[one-action]", "description": "You encourage yourself or an ally, psyching them up for a coming challenge and granting them temporary Hit Points. Choose yourself or an ally within 30 feet, then attempt a DC 20 Diplomacy check. If you have master proficiency in Diplomacy, you can instead attempt a DC 30 Diplomacy check to increase the temporary Hit Points gained on a successful check by 5. If you have legendary proficiency, you can instead attempt a DC 40 Diplomacy check to increase the temporary Hit Points gained on a successful check by 10. These temporary Hit Points last for 1 minute. The target is then temporarily immune to your Hang in There for 1 day.<br><br><strong>Critical Success</strong> The target gains temporary Hit Points equal to double their level plus your Charisma modifier.<br><strong>Success</strong> The target gains temporary Hit Points equal to their level plus your Charisma modifier.<br><strong>Failure</strong> The target is unaffected, and you can''t use Hang in There again for 1 minute.<br><strong>Critical Failure</strong> The target is unaffected, and you can''t use Hang in There again for 1 hour."}]}}',	'Envoy, Healing',	6,	'0',	NULL),
('cftConfoundingDisquisition',	'Confounding Disquisition',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Confounding Disquisition</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Envoy</span>
    <span class="trait-tag">Mental</span>
  </div>

  <div class="power-card-meta-grid">

  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You attempt to enthrall a foe with a convoluted and utterly pointless monologue that leaves your audience dumbfounded. Attempt a Deception or Diplomacy check against the Will DC of a single creature within 30 feet. The target is then temporarily immune to your Confounding Disquisition for 1 day.<br><br><strong>Critical Success</strong> The target is stunned 1 and is stupefied 1 for 1 round.<br><strong>Success</strong> The target is stupefied 1 for 1 round.<br><strong>Failure</strong> The target takes a –1 status penalty to Perception checks and Will saves for 1 round.<br><strong>Critical Failure</strong> The target is unaffected.
  </div>
</div>',	'[{"skill": [{"id": ["sklDeception", "sklDiplomacy"], "rank": "Trained"}]}]',	'You attempt to enthrall a foe with a convoluted and utterly pointless monologue that leaves your audience dumbfounded.',	'clsEnvoy',	'{"action": {"grant": [{"id": "actConfoundingDisquisition", "name": "Confounding Disquisition", "traits": "Envoy, Mental", "action_cost": "[two-actions]", "description": "You attempt to enthrall a foe with a convoluted and utterly pointless monologue that leaves your audience dumbfounded. Attempt a Deception or Diplomacy check against the Will DC of a single creature within 30 feet. The target is then temporarily immune to your Confounding Disquisition for 1 day.<br><br><strong>Critical Success</strong> The target is stunned 1 and is stupefied 1 for 1 round.<br><strong>Success</strong> The target is stupefied 1 for 1 round.<br><strong>Failure</strong> The target takes a –1 status penalty to Perception checks and Will saves for 1 round.<br><strong>Critical Failure</strong> The target is unaffected."}]}}',	'Envoy, Mental',	8,	'0',	NULL),
('cftSawItComing',	'Saw it Coming',	'<div class="power-card-display">
  <header class="power-card-header">
