('cftSecondaryDirective',	'Secondary Directive',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Secondary Directive</h3>
      <span class="power-action-cost">[one-action]</span>
