('cftAblativeBarrier',	'Ablative Barrier',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Ablative Barrier</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
    <span class="trait-tag">Manipulate</span>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You rapidly project a localized, hard-light force field or deploy a swarm of micro-drones to absorb incoming kinetic force. You gain temporary Hit Points equal to twice your level. These temporary Hit Points last for 1 minute. You cannot use Ablative Barrier again for 10 minutes.
  </div>
</div>',	NULL,	'You rapidly project a localized, hard-light force field or deploy a swarm of micro-drones to absorb incoming kinetic force.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actAblativeBarrier", "name": "Ablative Barrier", "traits": "Tech Specialist, Manipulate", "action_cost": "[one-action]", "description": "You rapidly project a localized, hard-light force field or deploy a swarm of micro-drones to absorb incoming kinetic force. You gain temporary Hit Points equal to twice your level. These temporary Hit Points last for 1 minute. You cannot use Ablative Barrier again for 10 minutes."}]}}',	'Tech Specialist, Manipulate',	12,	'0',	NULL),
('cftResuscitationProtocol',	'Resuscitation Protocol',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Resuscitation Protocol</h3>
      <span class="power-action-cost">[two-actions]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
    <span class="trait-tag">Healing</span>
    <span class="trait-tag">Manipulate</span>
  </div>
  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You are holding or wearing a medkit.</span>
    </div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You inject a massive, highly volatile dose of experimental nanites and stimulants directly into a recently deceased ally''s heart or primary neural cluster. Target one creature within your reach that died within the last round. Attempt a DC 30 Medicine check.<br><br><strong>Success</strong> The target returns to life with Hit Points equal to your level, and their wounded condition increases by 1.<br><br><strong>Critical Failure</strong> The shock to the system is too great; the target remains dead, and you cannot attempt to resuscitate them again.
  </div>
</div>',	'[{"subclass": [{"id": "subBioTech"}]}]',	'You inject a massive, highly volatile dose of experimental nanites and stimulants directly into a recently deceased ally''s heart or primary neural cluster.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actResuscitationProtocol", "name": "Resuscitation Protocol", "traits": "Tech Specialist, Healing, Manipulate", "action_cost": "[two-actions]", "description": "You inject a massive, highly volatile dose of experimental nanites and stimulants directly into a recently deceased ally''s heart or primary neural cluster. Target one creature within your reach that died within the last round. Attempt a DC 30 Medicine check.<br><br><strong>Success</strong> The target returns to life with Hit Points equal to your level, and their wounded condition increases by 1.<br><br><strong>Critical Failure</strong> The shock to the system is too great; the target remains dead, and you cannot attempt to resuscitate them again.", "requirements": "You are holding or wearing a medkit."}]}}',	'Tech Specialist, Healing, Manipulate',	12,	'0',	NULL),
('cftPredictiveTelemetry',	'Predictive Telemetry',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Predictive Telemetry</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
    <span class="trait-tag">Concentrate</span>
    <span class="trait-tag">Fortune</span>
  </div>
  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>An ally within 30 feet misses a creature with a ranged Strike.</span>
    </div>
    <div>
      <strong>Requirements</strong>
      <span>You can see or hear the triggering ally, and the target is observed by you.</span>
    </div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    Your rig''s combat algorithms instantly calculate the target''s evasive patterns and broadcast a firing correction directly to your ally''s HUD. The triggering ally rerolls the missed attack roll and must use the second result.
  </div>
</div>',	NULL,	'Your rig''s combat algorithms instantly calculate the target''s evasive patterns and broadcast a firing correction directly to your ally''s HUD.',	'clsTechSpecialist',	'{"action": {"grant": [{"id": "actPredictiveTelemetry", "name": "Predictive Telemetry", "traits": "Tech Specialist, Concentrate, Fortune", "trigger": "An ally within 30 feet misses a creature with a ranged Strike.", "action_cost": "[reaction]", "description": "Your rig''s combat algorithms instantly calculate the target''s evasive patterns and broadcast a firing correction directly to your ally''s HUD. The triggering ally rerolls the missed attack roll and must use the second result.", "requirements": "You can see or hear the triggering ally, and the target is observed by you."}]}}',	'Tech Specialist, Concentrate, Fortune',	12,	'0',	NULL),
('cftSystemOverride',	'System Override',	'<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">System Override</h3>
      <span class="power-action-cost">[free-action]</span>
