<h3 id="attacks">Attacks</h3>
<p>Trained in simple weapons<br>Trained in unarmed attacks</p>
<h3 id="defenses">Defenses</h3>
<p>Trained in light armor<br>Trained in unarmored defense</p>
<h3 id="class-dc">Class DC</h3>
<p>Trained in tech specialist class DC</p>',	'{"dc": [{"name": "Tech Specialist Class DC", "rank": "Trained", "attribute": "INT"}], "skill": {"fixed": [{"id": "sklCrafting", "rank": "Trained"}], "grant": {"count": 1, "label": "requires any Engineering Lore", "filter": [{"trait": "Engineering"}]}, "skill_increase": [{"max": "Trained", "count": 4}]}, "attack": [{"simple": {"rank": "Trained"}}, {"unarmed": {"rank": "Trained"}}], "defense": [{"light": {"rank": "Trained"}}, {"unarmored": {"rank": "Trained"}}], "perception": {"rank": "Trained"}, "saving_throw": [{"will": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"fortitude": {"rank": "Trained"}}]}'),
('clfUnfetteredProcessing',	'Unfettered Processing',	'<p>Your mind and your Rig process information at a staggering rate. You gain the following action.</p>

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Unfettered Processing</h3>
