('clfLightArmorMaster',	'Light Armor Master',	'Your skill with light armor improves, increasing your ability to dodge blows. Your proficiency ranks for light armor and unarmored defense increase to master.',	'{"defense": [{"unarmored": {"rank": "Master"}}, {"light": {"rank": "Master"}}]}'),
('clfEnvoyExpertise',	'Envoy Expertise',	'You''ve come a long way, and your hands-on experience has improved your skills. Your proficiency rank for your envoy class DC increases to expert.',	'{"dc": [{"name": "Envoy Class DC", "rank": "Expert"}]}'),
('clfWeaponExpertise',	'Weapon Expertise',	'You''ve learned a few tricks with your weapons. Your proficiency ranks for simple weapons, martial weapons, and unarmed attacks increase to expert. Whenever you attack the target of your Get ''Em!, you gain access to the critical specialization effects of all weapons for which you have expert proficiency.',	'{"attack": [{"unarmed": {"rank": "Expert"}}, {"simple": {"rank": "Expert"}}, {"martial": {"rank": "Expert"}}]}'),
('clfWeaponMastery',	'Weapon Mastery',	'You know your weapons like you know yourself. Your proficiency ranks for simple and martial weapons and unarmed attacks increase to master.',	'{"attack": [{"unarmed": {"rank": "Master"}}, {"simple": {"rank": "Master"}}, {"martial": {"rank": "Master"}}]}'),
('clfPerceptionExpertise',	'Perception Expertise',	'You have a keen eye for details and always manage to remain alert to threats around you. Your proficiency rank for Perception increases to expert.',	'{"perception": {"rank": "Expert"}}'),
