('clfLegendaryAlertness',	'Legendary Alertness',	'You remain alert to threats around you. Your proficiency rank for Perception increases to Legendary.
',	'{"perception": {"rank": "Legendary"}}'),
('clfEruditeWarrior',	'Erudite Warrior',	'',	'{"7": {"skill": {"fixed": [{"id": "choice(''target_skill1'')", "rank": "Expert"}, {"id": "choice(''target_skill2'')", "rank": "Expert"}]}}, "13": {"skill": {"fixed": [{"id": "choice(''target_skill1'')", "rank": "Master"}, {"id": "choice(''target_skill2'')", "rank": "Master"}]}}, "skill": {"fixed": [{"id": "choice(''target_skill1'')", "rank": "Trained"}, {"id": "choice(''target_skill2'')", "rank": "Trained"}]}, "inputs": [{"name": "target_skill1", "type": "skill", "label": "Diplomacy or Society", "filter": {"id": ["sklDiplomacy", "sklSociety"]}}, {"name": "target_skill2", "type": "skill", "label": "Lore Skill", "lore_filter": "untrained"}]}'),
('clfMasterTechSpecialist',	'Master Tech Specialist',	'Your mastery of technology is unparalleled. Your proficiency rank for your tech specialist class DC increases to master.',	'{"dc": [{"name": "Tech Specialist Class DC", "rank": "Master", "attribute": "INT"}]}'),
('clfBattleFocus',	'Battle Focus',	'You can center your mind on the immediate physical conflict, entering a state of hyper-awareness known as the  Focused  state.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Center for Battle</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 1</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Concentrate</span>
    <span class="trait-tag">Force Power</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Frequency</strong>
      <span>Once per round</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You clear your mind of distractions. You enter the Focused state. While Focused, if you are in a Stance gained from a Lightsaber Form feat, you gain the Guardian Mastery benefit listed in that feat. If you fall Unconscious, the Focused state ends.
  </div>
</div>
',	'{"action": {"grant": [{"id": "actCenterForBattle", "name": "Center for Battle", "traits": "Concentrate, Force Power", "frequency": "Once per round", "action_cost": "[one-action]", "description": "You clear your mind of distractions. You enter the Focused state. While Focused, if you are in a Stance gained from a Lightsaber Form feat, you gain the Guardian Mastery benefit listed in that feat. If you fall Unconscious, the Focused state ends."}]}}'),
('clfLightsaberDiscipline',	'Lightsaber Discipline',	'You are a student of the seven forms. You gain a level 1 class feat with the  [Form]  trait.

Additionally, any lightsaber you wield gains the  Parry  trait. (This allows you to spend an Action to gain a +1 circumstance bonus to AC until the start of your next turn).',	'{"feat": {"fixed": [{"id": "choice(''form_feat'')", "type": "class"}]}, "inputs": [{"name": "form_feat", "type": "class_feat", "label": "Form Feat", "filter": [{"trait": ["Form"]}]}]}'),
('clfJediWeaponExpertise',	'Jedi Weapon Expertise',	'You have trained until the lightsaber is an extension of your will. Your proficiency ranks for simple weapons, martial weapons, lightsabers, and unarmed attacks increase to expert. You gain access to the critical specialization effects of lightsabers.',	'{"attack": [{"unarmed": {"rank": "Expert"}}, {"simple": {"rank": "Expert"}}, {"martial": {"rank": "Expert"}}, {"group": [{"lightsaber": {"rank": "Expert"}}]}]}'),
('clfBattlefieldIntuitive',	'Battlefield Intuitive',	'Your proficiency rank for Perception increases to Master. In addition, you gain a +2 circumstance bonus to Perception checks for Initiative.',	'{"perception": {"rank": "Master"}}'),
('clfGuardianExpertise',	'Guardian Expertise',	'Your proficiency rank for your guardian class DC increases to expert.',	'{"dc": [{"name": "Guardian Class DC", "rank": "Expert"}]}'),
('clfMasterGuardian',	'Master Guardian',	'Your proficiency rank for your guardian class DC increases to master.',	'{"dc": [{"name": "Guardian Class DC", "rank": "Master"}]}'),
('clfJediWeaponMastery',	'Jedi Weapon Mastery',	'Your proficiency ranks for simple weapons, martial weapons, lightsabers, and unarmed attacks increase to master.',	'{"attack": [{"unarmed": {"rank": "Master"}}, {"simple": {"rank": "Master"}}, {"martial": {"rank": "Master"}}, {"group": [{"lightsaber": {"rank": "Master"}}]}]}'),
('clfEvasion',	'Evasion',	'You''ve learned to move quickly to avoid explosions and other area effects. Your proficiency rank for Reflex saves increases to Master. When you roll a success on a Reflex save, you get a critical success instead.',	'{"saving_throw": [{"reflex": {"rank": "Master"}}]}'),
('clfForceExpertise',	'Force Expertise',	'You let the Force guide your actions in non-combat situations. At 1st level, choose two skills. You can use your Wisdom modifier instead of the normal attribute modifier for checks with these skills.',	'{"skill": {"attribute_override": [{"id": "choice(''target_skill1'')", "attribute": "WIS"}, {"id": "choice(''target_skill2'')", "attribute": "WIS"}]}, "inputs": [{"name": "target_skill1", "type": "skill", "label": "Force Expertise Skill 1"}, {"name": "target_skill2", "type": "skill", "label": "Force Expertise Skill 2"}]}'),
('clfForceConnection',	'Force Connection',	'You have learned to open your mind to the flow of the Force, becoming a conduit for its power. You gain the Open Connection action.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Open Connection</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
    <div class="power-meta-top">
      <span class="power-level">Level 1</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Concentrate</span>
    <span class="trait-tag">Force Power</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Frequency</strong>
      <span>Once per round</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You center yourself, allowing the Force to flow through you freely. You enter the Connected state. While Connected, you can use abilities with the Connected trait. While Connected, you can use the Telekinetic Impact action. If you fall unconscious, the connection ends. You cannot use Open Connection if you are fatigued.
  </div>
</div>',	'{"action": {"grant": [{"id": "actOpenConnection", "name": "Open Connection", "traits": "Concentrate, Force Power", "frequency": "Once per round", "action_cost": "[one-action]", "description": "You center yourself, allowing the Force to flow through you freely. You enter the Connected state. While Connected, you can use abilities with the Connected trait. While Connected, you can use the Telekinetic Impact action. If you fall unconscious, the connection ends. You cannot use Open Connection if you are fatigued."}]}}'),
('clfWaysOfTheForce',	'Ways of the Force',	'You are experienced in the ways of the Force.  You learn two level 1 Force Powers.',	'{"power": {"power_slot": [{"count": 2, "level": 1}]}}'),
('clfSoldierInitialProficiencies',	'Soldier Initial Proficiencies',	'<p>At 1st level, you gain the listed proficiency ranks in the following statistics. You are untrained in anything not listed unless you gain a better proficiency rank in some other way.</p>
<div style="column-count: 2;">
<div><h3 id="perception">Perception</h3>
<p>Trained in Perception</p></div>
<div><h3 id="saving-throws">Saving Throws</h3>
<p>Expert in Fortitude<br>Trained in Reflex<br>Expert in Will</p></div>
<div><h3 id="skills">Skills</h3>
<p>Trained in Intimidation<br>Trained in a number of additional skills equal to 3 plus your Intelligence modifier</p></div>
<div><h3 id="attacks">Attacks</h3>
<p>Trained in simple weapons<br>Trained in martial weapons<br>Trained in unarmed attacks</p></div>
<div><h3 id="defenses">Defenses</h3>
<p>Trained in all armor<br>Trained in unarmored defense</p></div>
<div><h3 id="class-dc">Class DC</h3>
<p>Trained in soldier class DC</p></div>
</div>',	'{"dc": [{"name": "Soldier Class DC", "rank": "Trained", "attribute": "CON"}], "skill": {"fixed": [{"id": "sklIntimidation", "rank": "Trained"}], "skill_increase": [{"max": "Trained", "count": 3}]}, "attack": [{"simple": {"rank": "Trained"}}, {"martial": {"rank": "Trained"}}, {"unarmed": {"rank": "Trained"}}], "defense": [{"heavy": {"rank": "Trained"}}, {"light": {"rank": "Trained"}}, {"medium": {"rank": "Trained"}}, {"unarmored": {"rank": "Trained"}}], "perception": {"rank": "Trained"}, "saving_throw": [{"will": {"rank": "Expert"}}, {"reflex": {"rank": "Trained"}}, {"fortitude": {"rank": "Expert"}}]}'),
('clfOverclock',	'Overclock',	'<p>You know how to bypass safety limiters to achieve incredible results. Every Modification you prepare has an Overclock effect. When you use a Modification, you can choose to Overclock it. You apply the Overclock effect listed in the Modification''s description, altering the baseline action. Immediately after resolving an Overclocked action, you must attempt a DC 15 flat check.</p>
<ul>
<li><strong>Success</strong>  You stabilize the power surge. You suffer no ill effects.</li>
<li><strong>Failure</strong>  You lose the ability to Overclock for 10 minutes. Your prepared Modifications still work in their standard mode.</li>
<li><strong>Critical Failure</strong>  The specific Modification you used is disabled (including its Standby benefit) and completely unusable until you spend 10 minutes repairing it. You also lose the ability to Overclock for 10 minutes.</li>
</ul>
',	NULL),
('clfPredictiveEvasion',	'Predictive Evasion',	'Your rig’s predictive algorithms and your own reflexes are perfectly synced. Your proficiency rank for Reflex saves increases to legendary. When you roll a critical failure on a Reflex save, you get a failure instead. When you fail a Reflex save against a damaging effect, you take half damage.',	'{"saving_throw": [{"reflex": {"rank": "Legendary"}}]}'),
('clfGuardianInitialProficiencies',	'Guardian Initial Proficiencies',	'<p>At 1st level, you gain the listed proficiency ranks in the following statistics. You are untrained in anything not listed unless you gain a better proficiency rank in some other way.</p>
<div style="column-count: 2;">
<div><p><strong>Perception</strong></p>
<p>Expert in Perception</p>
<p><strong>Saving Throws</strong></p></div>
<div><p>Expert in Fortitude<br>Trained in Reflex<br>Expert in Will</p></div>
<div><p><strong>Skills</strong></p>
<p>Trained in The Force<br>Trained in Athletics<br>Trained in a number of additional skills equal to 3 plus your Intelligence modifier</p></div>
<div><p><strong>Attacks</strong></p>
<p>Trained in simple weapons<br>Trained in martial weapons<br>Trained in lightsabers<br>Trained in unarmed attacks</p></div>
<div><p><strong>Defenses</strong></p>
<p>Trained in light armor<br>Trained in medium armor<br>Trained in heavy armor<br>Trained in unarmored defense</p></div>
<div><p><strong>Class DC</strong></p>
<p>Trained in guardian class DC</p></div>
</div>',	'{"dc": [{"name": "Guardian Class DC", "rank": "Trained", "attribute": "STR"}], "skill": {"fixed": [{"id": "sklTheForce", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Trained"}], "skill_increase": [{"max": "Trained", "count": 3}]}, "attack": [{"unarmed": {"rank": "Trained"}}, {"simple": {"rank": "Trained"}}, {"martial": {"rank": "Trained"}}, {"group": [{"lightsaber": {"rank": "Trained"}}]}], "defense": [{"unarmored": {"rank": "Trained"}}, {"light": {"rank": "Trained"}}, {"medium": {"rank": "Trained"}}, {"heavy": {"rank": "Trained"}}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Trained"}}, {"will": {"rank": "Expert"}}]}'),
('clfEnvoyInitialProficiencies',	'Envoy Initial Proficiencies',	'<p>At 1st level, you gain the listed proficiency ranks in the following statistics. You are untrained in anything not listed unless you gain a better proficiency rank in some other way.</p>
<div style="column-count: 2;">

<div><strong>Perception</strong>
<p>Trained in Perception</p></div>
<div><strong>Saving Throws</strong>
<p>Trained in Fortitude<br>Expert in Reflex<br>Expert in Will</p></div>
<div><strong>Skills</strong>
<p>Trained in one of the following skills of your choice: Deception, Diplomacy, Intimidation<br>Trained in one skill based on your leadership style<br>Trained in a number of additional skills equal to 6 plus your Intelligence modifier</p></div>
<div><strong>Attacks</strong>
<p>Trained in simple weapons<br>Trained in martial weapons<br>Trained in unarmed attacks</p></div>
<div><strong>Defenses</strong>
<p>Trained in light armor<bd>Trained in unarmored defense</p></div>
<div><strong>Class DC</strong>
<p>Trained in envoy class DC</p></div>
</div>',	'{"dc": [{"name": "Envoy Class DC", "rank": "Trained", "attribute": "CHA"}], "skill": {"grant": {"count": 1, "label": "requires Deception, Diplomacy, or Intimidation", "filter": [{"id": ["sklDeception", "sklDiplomacy", "sklIntimidation"]}]}, "skill_increase": [{"max": "Trained", "count": 6}]}, "attack": [{"simple": {"rank": "Trained"}}, {"martial": {"rank": "Trained"}}, {"unarmed": {"rank": "Trained"}}], "defense": [{"light": {"rank": "Trained"}}, {"unarmored": {"rank": "Trained"}}], "perception": {"rank": "Trained"}, "saving_throw": [{"will": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"fortitude": {"rank": "Trained"}}]}'),
('clfIntegratedOrdnanceSystems',	'Integrated Ordnance Systems',	'You were built for war, and your chassis is designed to be as lethal as the weapons you wield. You become trained in Intimidation or Warfare Lore.

Additionally, you possess a specialized Weapon Hardpoint integrated into your frame (such as a retractable forearm assembly or a shoulder mount). You can spend 1 hour to integrate a single one-handed weapon into this hardpoint.  Once integrated, this weapon is physically bolted to your chassis; it cannot be disarmed or dropped.  You can draw or stow this specific integrated weapon as a free action. ',	'{"skill": {"grant": {"count": 1, "label": "requires Intimidation or Warfare Lore", "filter": [{"id": ["sklIntimidation", "sklLoreWarfare"]}]}}}'),
('clfReliableOverclock',	'Reliable Overclock',	'You have refined your hardware to handle heavier loads. The flat check DC for your Overclock actions is reduced from 15 to 13.',	NULL),
('clfSharpshooter',	'Sharpshooter',	'You can spot a target''s weak points, letting you deal additional precision damage with most types of ranged weapons. You gain the Aim action.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Aim</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Operative</span>
    <span class="trait-tag">Aim</span>
  </div>
  <div class="power-card-meta-grid">
    <div><strong>Requirements</strong><span>You''re wielding a ranged weapon that doesn''t have the area trait.</span></div>
  </div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You take careful aim at a single creature that you''re aware of, designating it as your mark until your next turn. Your ranged Strikes against your mark using the required ranged weapon deal an additional 1d4 precision damage and reduce the circumstance bonus to AC your mark gains from cover by 1. These benefits only apply if your mark is within your weapon''s first range increment. You can only have one mark at a time.<br><br>As your operative level increases, so does your ability to Aim. Increase the number of dice for the precision damage by one at 5th, 11th, and 17th levels. At 11th level, you reduce the circumstance bonus to AC your mark gains from cover by 2 rather than 1. At 17th level, you reduce the circumstance bonus to AC your mark gains from cover by 4 rather than 2.
  </div>
</div>',	'{"action": {"grant": [{"id": "actAim", "name": "Aim", "traits": "Operative, Aim", "action_cost": "[one-action]", "description": "You take careful aim at a single creature that you''re aware of, designating it as your mark until your next turn. Your ranged Strikes against your mark using the required ranged weapon deal an additional 1d4 precision damage and reduce the circumstance bonus to AC your mark gains from cover by 1. These benefits only apply if your mark is within your weapon''s first range increment. You can only have one mark at a time.\n\nAs your operative level increases, so does your ability to Aim. Increase the number of dice for the precision damage by one at 5th, 11th, and 17th levels. At 11th level, you reduce the circumstance bonus to AC your mark gains from cover by 2 rather than 1. At 17th level, you reduce the circumstance bonus to AC your mark gains from cover by 4 rather than 2.", "requirements": "You''re wielding a ranged weapon that doesn''t have the area trait."}]}}'),
('clfOperativeInitialProficiencies',	'Operative Initial Proficiencies',	'<p>At 1st level, you gain the listed proficiency ranks in the following statistics. You are untrained in anything not listed unless you gain a better proficiency rank in some other way.</p>
<div style="column-count: 2;">
<div><strong>Perception</strong>
<p>Expert in Perception</p></div>
<div><strong>Saving Throws</strong>
<p>Trained in Fortitude<br>Expert in Reflex<br>Expert in Will</p></div>
<div><strong>Skills</strong>
<p>Trained in one skill determined by your specialization<br>Trained in a number of additional skills equal to 3 plus your Intelligence modifier</p></div>
<div><strong>Attacks</strong>
<p>Expert in simple guns<br>Expert in martial guns<br>Trained in advanced guns<br>Trained in simple weapons<br>Trained in martial weapons<br>Trained in unarmed attacks</p></div>
<div><strong>Defenses</strong>
<p>Trained in light armor<br>Trained in unarmored defense</p>
<div><strong>Class DC</strong>
<p>Trained in operative class DC</p></div>
</div>',	'{"dc": [{"name": "Operative Class DC", "rank": "Trained", "attribute": "DEX"}], "skill": {"skill_increase": [{"max": "Trained", "count": 3}]}, "attack": [{"simple": [{"melee": {"rank": "Trained"}}, {"ranged": {"rank": "Expert"}}]}, {"martial": [{"melee": {"rank": "Trained"}}, {"ranged": {"rank": "Expert"}}]}, {"unarmed": {"rank": "Trained"}}, {"advanced": [{"ranged": {"rank": "Trained"}}]}], "defense": [{"light": {"rank": "Trained"}}, {"unarmored": {"rank": "Trained"}}], "perception": {"rank": "Expert"}, "saving_throw": [{"will": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"fortitude": {"rank": "Trained"}}]}'),
('clfEmergencyReroute',	'Emergency Reroute',	'You can rapidly shunt power to save your Rig from a catastrophic failure. You gain the Emergency Reroute reaction.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Emergency Reroute</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Trigger</strong>
      <span>You fail or critically fail the flat check for an Overclock action.</span>
    </div>
    <div>
      <strong>Frequency</strong>
      <span>Once per day.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You ground the electrical surge through your own body. You take electricity damage equal to your level, but you upgrade the result of the triggering flat check by one degree of success (from a critical failure to a failure, or a failure to a success).
  </div>
</div>',	'{"action": {"grant": [{"id": "actEmergencyReroute", "name": "Emergency Reroute", "traits": "Tech Specialist", "trigger": "You fail or critically fail the flat check for an Overclock action.", "frequency": "Once per day.", "action_cost": "[reaction]", "description": "You ground the electrical surge through your own body. You take electricity damage equal to your level, but you upgrade the result of the triggering flat check by one degree of success (from a critical failure to a failure, or a failure to a success)."}]}}'),
('clfModificationLibrary',	'Modification Library',	'<h3 id="modification-library">Modification Library</h3>
<p>You maintain a digital library of blueprints and code repositories. At 1st level, you add four 1st-level Modifications of your choice to your library. At 3rd level and every odd-numbered level thereafter, you add a new Modification of your level or lower to your library. You also gain the Learn a Modification downtime activity.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Learn a Modification</h3>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">Tech Specialist</span>
    <span class="trait-tag">Downtime</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Requirements</strong>
      <span>You have access to a physical schematic, an encrypted data shard, or an allied Tech Specialist who knows the Modification you want to learn.</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    <p>You spend time reverse-engineering and compiling a new Modification to permanently add to your Modification Library. This requires spending a specific amount of time and credits on specialized compilers, decryption keys, or hardware components, and attempting a <strong>Crafting</strong> check against a standard DC corresponding to the Modification&#39;s level.</p><ul><li><p><strong>Level 1 Modification:</strong> Requires 1 hour and costs <strong>20 credits</strong>.</p></li><li><p><strong>Level 7 Modification:</strong> Requires 4 hours and costs <strong>360 credits</strong>.</p></li><li><p><strong>Level 15 Modification:</strong> Requires 8 hours and costs <strong>6,500 credits</strong>.</p></li></ul><p><strong>Critical Success</strong> You successfully compile the Modification and add it to your Modification Library. Your brilliant optimization means you only spend half the required credits.<br><strong>Success</strong> You successfully compile the Modification, spend the required credits, and add it to your Modification Library.<br><strong>Failure</strong> You can&#39;t fully integrate the schematic with your rig&#39;s architecture. You don&#39;t spend the credits, but you can&#39;t try to learn this specific Modification again until you gain a level.<br><strong>Critical Failure</strong> You catastrophically corrupt the data or fry the necessary hardware components during the attempt. You waste half the required credits and can&#39;t try to learn this specific Modification again until you gain a level.</p>
  </div>
</div></p>',	'{"3": {"modification": {"library_slot": {"count": 1}}}, "5": {"modification": {"library_slot": {"count": 1}}}, "7": {"modification": {"library_slot": {"count": 1}}}, "9": {"modification": {"library_slot": {"count": 1}}}, "11": {"modification": {"library_slot": {"count": 1}}}, "13": {"modification": {"library_slot": {"count": 1}}}, "15": {"modification": {"library_slot": {"count": 1}}}, "17": {"modification": {"library_slot": {"count": 1}}}, "19": {"modification": {"library_slot": {"count": 1}}}, "action": {"grant": [{"id": "actLearnAModification", "name": "Learn a Modification", "traits": "Tech Specialist, Downtime", "description": "<p>You spend time reverse-engineering and compiling a new Modification to permanently add to your Modification Library. This requires spending a specific amount of time and credits on specialized compilers, decryption keys, or hardware components, and attempting a <strong>Crafting</strong> check against a standard DC corresponding to the Modification&#39;s level.</p><ul><li><p><strong>Level 1 Modification:</strong> Requires 1 hour and costs <strong>20 credits</strong>.</p></li><li><p><strong>Level 7 Modification:</strong> Requires 4 hours and costs <strong>360 credits</strong>.</p></li><li><p><strong>Level 15 Modification:</strong> Requires 8 hours and costs <strong>6,500 credits</strong>.</p></li></ul><p><strong>Critical Success</strong> You successfully compile the Modification and add it to your Modification Library. Your brilliant optimization means you only spend half the required credits.<br><strong>Success</strong> You successfully compile the Modification, spend the required credits, and add it to your Modification Library.<br><strong>Failure</strong> You can&#39;t fully integrate the schematic with your rig&#39;s architecture. You don&#39;t spend the credits, but you can&#39;t try to learn this specific Modification again until you gain a level.<br><strong>Critical Failure</strong> You catastrophically corrupt the data or fry the necessary hardware components during the attempt. You waste half the required credits and can&#39;t try to learn this specific Modification again until you gain a level.</p>", "requirements": "You have access to a physical schematic, an encrypted data shard, or an allied Tech Specialist who knows the Modification you want to learn."}]}, "modification": {"library_slot": {"count": 4}}}'),
('clfCustomRig',	'Custom Rig',	'<h3 id="custom-rig">Custom Rig</h3>
<p>You begin with a specialized hardware interface called a custom rig. Your custom rig weighs 1 Bulk and counts as both a commercial repair toolkit plus any one of the following toolkits of your choice: a commercial hacking toolkit, a commercial infiltrator’s toolkit, or a commercial maker’s toolkit. You can use your custom rig with one hand if you’re wearing it or two hands if you’re holding it.</p>

<p>Whenever you purchase one of the listed toolkits, or a higher-grade version of one of the listed toolkits, you can spend 10 minutes integrating that toolkit into your custom rig. If you do, your custom rig gains the properties of the toolkit. This does not increase the Bulk of your custom rig. Your custom rig and any integrated toolkits can’t be sold or used by another creature.</p>

<p>Additionally, your custom rig acts as the operational chassis for your technological abilities. You can keep up to three Modifications from your Modification Library actively installed in your custom rig. Installed Modifications grant their active effects and permanent passive Standby benefits until they are uninstalled. You can install an additional Modification at 5th level, 9th level, 13th level, and 17th level (for a total of seven).</p>

<p>During your daily preparations, you can completely reconfigure your rig, uninstalling any number of your current Modifications and installing different ones from your Modification Library. Furthermore, you can adapt to rapidly changing situations by spending 10 minutes interacting with your custom rig to hot-swap a single installed Modification for a different one from your Modification Library.</p>',	'{"5": {"modification": {"mod_slot": {"count": 1}}}, "9": {"modification": {"mod_slot": {"count": 1}}}, "13": {"modification": {"mod_slot": {"count": 1}}}, "17": {"modification": {"mod_slot": {"count": 1}}}, "item": {"grant": [{"id": "idCustomRig", "bulk": 1, "name": "Custom Rig", "level": 0, "traits": "Toolkit", "equipped": true, "features": {"reduce_bulk": 999}, "quantity": 1, "item_type": "item", "is_container": true, "trait_filter": ["Toolkit"], "contained_item_ids": [], "always_process_contents": true}]}, "modification": {"mod_slot": {"count": 3}}}');

DROP TABLE IF EXISTS "Heritage";
CREATE TABLE "public"."Heritage" (
    "HP" smallint,
    "Speed" smallint,
    "Languages" text,
    "Description" text NOT NULL,
    "HeritageID" character varying NOT NULL,
    "AncestryID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Traits" character varying NOT NULL,
    "Features" jsonb,
    "Size" character varying,
    CONSTRAINT "Heritage_HeritageID" PRIMARY KEY ("HeritageID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Heritage"."HP" IS 'Hit die size';

COMMENT ON COLUMN "public"."Heritage"."Speed" IS 'Speed in meters';

COMMENT ON COLUMN "public"."Heritage"."Languages" IS 'List of starting languages';

COMMENT ON COLUMN "public"."Heritage"."Description" IS 'Description text';

COMMENT ON COLUMN "public"."Heritage"."HeritageID" IS 'Unique Heritage ID';

COMMENT ON COLUMN "public"."Heritage"."AncestryID" IS 'ID of Parent Ancestry';

COMMENT ON COLUMN "public"."Heritage"."Name" IS 'Heritage Name';

COMMENT ON COLUMN "public"."Heritage"."Traits" IS 'Traits';

INSERT INTO "Heritage" ("HP", "Speed", "Languages", "Description", "HeritageID", "AncestryID", "Name", "Traits", "Features", "Size") VALUES
(NULL,	NULL,	NULL,	'<h3 id="class-iii-protocol-social-">Class III (Protocol &amp; Social)</h3>
<p>You were designed to facilitate communication and navigate the complex etiquette of organic society. Like the 3PO-series or the RA-7 servant droids, you are humanoid in shape and programmed with millions of forms of communication. While often physically stiff and unsuited for combat, your knowledge of culture and language is unparalleled.</p>
<p><strong>Cybot-Galactica Interaction Matrix</strong> You become trained in Diplomacy or Society. You learn two additional languages at 1st level. You gain a +1 circumstance bonus to checks to Make an Impression when following proper etiquette.</p>',	'herDroidClass3',	'ancDroid',	'Droid Class III',	'',	'{"feature": ["clfCybotGalacticaInteractionMatrix"], "attribute": {"flaw": "STR", "boost": ["WIS", "CHA"]}}',	NULL),
(NULL,	NULL,	NULL,	'<h3 id="class-v-labor-menial-">Class V (Labor &amp; Menial)</h3>
<p>You are the backbone of galactic industry. Designed for heavy lifting, mining, sanitation, or transport, you are built to endure. Examples include the GNK power droid (&quot;Gonk&quot;) or the heavy-lifting binary load lifters. While your processing power might be simpler than a Class I or II, your physical durability and torque are vastly superior. You are humble, tough, and notoriously difficult to knock off your feet.</p>
<p><strong>Heavy-Grade Hydraulic Frame</strong> You were built with a low center of gravity and high-torque servos. You gain a +1 circumstance bonus to your Fortitude or Reflex DC against attempts to Shove or Trip you. Additionally, you ignore the Speed penalty caused by the Encumbered condition (you still take the maximum Dex, check, and Speed penalties for being Overburdened).</p>
',	'herDroidClass5',	'ancDroid',	'Droid Class V',	'',	'{"feature": ["clfHeavyGradeHydraulicFrame"], "attribute": {"boost": ["STR"]}}',	NULL),
(NULL,	20,	NULL,	'<h3 id="class-ii-engineering-astromech-">Class II (Engineering &amp; Astromech)</h3>
<p>You are a technical genius, designed to interface with starships, computers, and complex machinery. This class includes the famous R2-series astromechs and the BB-series rolling units. You likely speak only Binary (unless modified), requiring others to check a datapad to understand you. You are fearless, utilitarian, and often develop a &quot;sassy&quot; personality due to your high level of independence.</p>
<p><strong>Integrated Utility Sockets</strong> You become trained in Computers or Crafting. You gain a built-in datajack or arc welder (choose one). You can use your internal comms to interface with local networks without a handheld device.</p>
',	'herDroidClass2',	'ancDroid',	'Droid Class II',	'',	'{"feature": ["clfIntegratedUtilitySockets"], "attribute": {"boost": ["DEX"]}}',	'Small'),
(NULL,	NULL,	NULL,	'<h3 id="class-i-physical-medical-science-">Class I (Physical &amp; Medical Science)</h3>
<p>You were built for high-level scientific calculation, medical surgery, or physical analysis. Droids of this class, such as the 2-1B surgical droid or the GH-7 medical analysis unit, possess sophisticated heuristic processors designed to understand complex biological and physical laws. You are analytical, precise, and often possess a bedside manner that is either comforting or terrifyingly clinical.</p>
<p><strong>Analytical Heuristics</strong> You become trained in Medicine or a Science lore, and your chassis is equipped with a basic integrated medkit.</p>
',	'herDroidClass1',	'ancDroid',	'Droid Class I',	'',	'{"feature": ["clfAnalyticalHeuristics"], "attribute": {"boost": ["WIS"]}}',	NULL),
(NULL,	NULL,	NULL,	'Raised in the absolute center of galactic civilization—such as Coruscant, Alderaan, or Hosnian Prime—your education was comprehensive. Surrounded by billions of citizens, cutting-edge technology, and endless databanks, your casual exposure to thousands of different disciplines makes you highly adaptable when forced outside your comfort zone.

You gain the Untrained Improvisation general feat, even if you do not meet the normal prerequisites.  You also know two more languages than a standard human.',	'herHumanDeepCore',	'ancHuman',	'Core World Human',	'',	'{"feat": {"fixed": [{"id": "feaUntrainedImprovisation", "type": "general"}]}, "extra_languages": 2}',	NULL),
(NULL,	NULL,	NULL,	'Humans are famously adaptable, able to thrive in almost any environment or social stratum. You represent the baseline ingenuity of the human species, unconstrained by a specific planetary culture.

You gain a 1st-level general feat of your choice. You also gain trained proficiency in one skill of your choice.
',	'herHumanVersatile',	'ancHuman',	'Versatile Human',	'',	'{"skill": {"skill_increase": [{"max": "Trained", "count": 1}]}, "feature": ["clfVersatile"]}',	NULL),
(NULL,	NULL,	NULL,	'Bred for battle by master cloning engineers and subjected to relentless flash-training from "birth," your genome is derived from a legendary warrior. You were built to function as part of a flawless military unit, possessing an instinctual grasp of squad tactics and a body designed to endure the horrors of a galactic war.

Your genetic conditioning and grueling training regimens make you exceptionally resilient. You gain the Toughness general feat. Additionally, you become trained in Athletics and Warfare Lore.',	'herHumanClone',	'ancHuman',	'Clone Trooper',	'',	'{"feat": {"fixed": [{"id": "feaToughness", "type": "general"}]}, "skill": {"fixed": [{"id": "sklAthletics", "rank": "Trained"}, {"id": "sklLoreWarfare", "rank": "Trained"}]}}',	NULL),
(NULL,	NULL,	NULL,	'Growing up on a harsh, sparsely populated fringe world like Tatooine, Jakku, or Hoth has hardened your body against extreme climates and privation. Far from the pampered comforts of the Core Worlds, you learned to survive where the environment itself is an enemy and help is never coming.

Choose Fire or Cold. You gain Resistance to that energy type equal to half your level (minimum 1). Additionally, you treat environmental conditions matching your chosen energy type (extreme heat or extreme cold) as one step less severe.',	'herHumanOuterRim',	'ancHuman',	'Outer Rim Human',	'',	'{"feature": ["clfOuterRimResistance"]}',	NULL),
(NULL,	NULL,	NULL,	'You hail from the Corellian sector, a region renowned for producing the galaxy''s best pilots, most notorious smugglers, and most stubborn dissidents. You have a cultural penchant for flying by the seat of your pants, making you a natural fit for high-stakes Rebel Alliance operations or underworld smuggling runs on planets like Ord Mantell.

<strong>Corellian Risk-Taker</strong> You become Trained in Piloting or Deception (your choice). At 5th level, your rank in your chosen skill automatically increases to Expert. You gain a +1 circumstance bonus to checks made to Feint in combat or to perform a Stunt while piloting a vehicle. Additionally, once per day, if you roll a Critical Failure on a Piloting or Deception check, you can treat it as a standard Failure instead.',	'herHumanCorellian',	'ancHuman',	'Corellian Human',	'',	'{"feature": ["clfCorellianRiskTaker"]}',	NULL),
(NULL,	NULL,	NULL,	'<h3 id="class-iv-combat-security-">Class IV (Combat &amp; Security)</h3>
<p>You were built for war. Whether you are a B1 battle droid, a fearsome IG-series assassin, or a KX-series security droid, your chassis is reinforced and your programming is centered on tactics and weaponry. You are intimidating, efficient, and often view violence as the most logical solution to a problem. Unlike other droids, you likely have armor plating integrated directly into your frame.</p>
<p><strong>Integrated Ordnance Systems</strong> You were built for war, and your chassis is designed to be as lethal as the weapons you                         wield. You become trained in Intimidation or Warfare Lore.</p>
<p>Additionally, you possess a specialized Weapon Hardpoint integrated into your frame (such as a retractable forearm assembly or a shoulder mount). You can spend 1 hour to integrate a single one-handed weapon (ranged or melee) into this hardpoint.  Once intagrated, this weapon is physically bolted to your chassis; it cannot be Disarmed or dropped.  You can Draw or Stow this specific integrated weapon as a free action. </p>
',	'herDroidClass4',	'ancDroid',	'Droid Class IV',	'',	'{"feature": ["clfIntegratedOrdnanceSystems"], "attribute": {"flaw": "CHA", "boost": ["STR", "DEX"]}}',	NULL);

DROP TABLE IF EXISTS "Item";
CREATE TABLE "public"."Item" (
    "ItemID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Level" smallint DEFAULT '0',
    "Price" character varying,
    "Bulk" character varying DEFAULT 'L',
    "Traits" character varying,
    "Description" text,
    "Features" jsonb,
    "Equippable" boolean DEFAULT false,
    "Container" boolean DEFAULT false,
    "Consumable" boolean DEFAULT false,
    CONSTRAINT "Item_ItemID" PRIMARY KEY ("ItemID")
)
WITH (oids = false);

INSERT INTO "Item" ("ItemID", "Name", "Level", "Price", "Bulk", "Traits", "Description", "Features", "Equippable", "Container", "Consumable") VALUES
