DROP TABLE IF EXISTS "Minion";
CREATE TABLE "public"."Minion" (
    "MinionID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Description" text,
    "Traits" character varying,
    "Size" character varying,
    "Mount" boolean,
    "Speed" jsonb,
    "Senses" jsonb,
    "Features" jsonb,
    "Level" smallint,
    "HP" smallint NOT NULL,
    "Attributes" jsonb,
    "Summary" character varying,
    "Skill" character varying,
    CONSTRAINT "Minion_pkey" PRIMARY KEY ("MinionID")
)
WITH (oids = false);

INSERT INTO "Minion" ("MinionID", "Name", "Description", "Traits", "Size", "Mount", "Speed", "Senses", "Features", "Level", "HP", "Attributes", "Summary", "Skill") VALUES
('minProbeDroid',	'Probe Droid',	'A spherical, floating espionage unit designed for surveillance and tracking, equipped with a light blaster for self-defense.

<strong>Support Benefit</strong> The probe droid uses its advanced sensor suite to paint a target for you. Until the start of your next turn, your Strikes against creatures in the droid''s line of sight ignore the concealed condition.',	'Construct, Minion, Tech',	'Small',	NULL,	'{"Fly": 25}',	'{"Darkvision": null}',	'{"name": "Basic Probe Droid", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The probe droid uses its advanced sensor suite to paint a target for you. Until the start of your next turn, your Strikes against creatures in the droid''s line of sight ignore the concealed condition."}]}, "weapon": {"grant": [{"id": "wepLightBlaster", "bulk": null, "name": "Light Blaster", "type": "Ranged", "group": "Brawling", "hands": "1", "category": "Unarmed", "damagedie": "d4", "damagetype": "Fire"}]}, "template": [{"infiltrator": {"name": "Infiltrator-Spec Probe Droid", "skill": [{"id": "sklStealth", "rank": "Master"}, {"id": "sklAcrobatics", "rank": "Expert"}], "speed": [{"amount": 10, "target": "all"}], "action": {"grant": [{"id": "actReconSweep", "name": "Recon Sweep", "action_cost": "[one-action]", "description": "The droid conducts a high-speed active scan. The droid takes the Seek action in a 30-foot burst centered on itself. It uses your Perception modifier for the check instead of its own, communicating the results directly to your HUD or datapad."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 3, "dex": 6, "int": 1, "str": 0, "wis": 3}, "damage_dice_count": 2}}, {"escort": {"name": "Escort-Spec Probe Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actReconSweep", "name": "Recon Sweep", "action_cost": "[one-action]", "description": "The droid conducts a high-speed active scan. The droid takes the Seek action in a 30-foot burst centered on itself. It uses your Perception modifier for the check instead of its own, communicating the results directly to your HUD or datapad."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 3, "dex": 6, "int": 1, "str": 0, "wis": 3}, "damage_dice_count": 2}}, {"upgraded": {"name": "Upgraded Probe Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 2, "dex": 4, "int": 1, "str": -1, "wis": 3}, "damage_dice_count": 2}}]}',	1,	6,	'{"cha": -1, "con": 1, "dex": 3, "int": 1, "str": -2, "wis": 2}',	'A spherical, floating espionage unit designed for surveillance and tracking, equipped with a light blaster for self-defense.',	'sklStealth'),
('minLaborDroid',	'Labor Droid',	'A folding, highly durable worker droid built to haul cargo, repair vehicles, and survive heavy impacts.

<strong>Support Benefit</strong> The labor droid uses its hydraulic strength to unbalance your enemies, grabbing at their legs or shoving them. Until the start of your next turn, if you hit a creature the labor droid threatens, that creature takes a -1 circumstance penalty to its Fortitude and Reflex DCs against your Athletics maneuvers (such as Trip or Shove) until the end of your turn.',	'Construct, Minion, Tech',	'Small',	NULL,	'{"base": 25}',	'{"Low-light Vision": null}',	'{"name": "Basic Labor Droid", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The GH-7 monitors your vitals and dispenses micro-stimulants. Until the start of your next turn, you and allies adjacent to the droid gain a +1 circumstance bonus to saving throws against poisons, diseases, and bleed effects."}]}, "weapon": {"grant": [{"id": "wepHeavyWrench", "bulk": null, "name": "Heavy Wrench", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Shove", "category": "Unarmed", "damagedie": "d8", "damagetype": "B"}]}, "template": [{"infiltrator": {"name": "Infiltrator-Spec Labor Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}], "speed": [{"amount": 10, "target": "all"}], "action": {"grant": [{"id": "actFieldPatch", "name": "Field Patch", "action_cost": "[one-action]", "description": "The droid rapidly welds or bolts the target together. It attempts a Crafting check to Repair the target using your Crafting modifier. This takes 1 action instead of the standard 10 minutes, but it restores half as many Hit Points as a standard Repair action.", "requirements": "The droid is adjacent to a construct, vehicle, or item that has taken damage."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -2, "con": 4, "dex": 4, "int": -2, "str": 5, "wis": 2}, "damage_dice_count": 2}}, {"escort": {"name": "Escort-Spec Labor Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actFieldPatch", "name": "Field Patch", "action_cost": "[one-action]", "description": "The droid rapidly welds or bolts the target together. It attempts a Crafting check to Repair the target using your Crafting modifier. This takes 1 action instead of the standard 10 minutes, but it restores half as many Hit Points as a standard Repair action.", "requirements": "The droid is adjacent to a construct, vehicle, or item that has taken damage."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -2, "con": 4, "dex": 4, "int": -2, "str": 5, "wis": 2}, "damage_dice_count": 2}}, {"upgraded": {"name": "Upgraded Labor Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -2, "con": 3, "dex": 2, "int": -2, "str": 4, "wis": 1}, "damage_dice_count": 2}}]}',	1,	8,	'{"cha": -2, "con": 2, "dex": 1, "int": -2, "str": 3, "wis": 0}',	'A folding, highly durable worker droid built to haul cargo, repair vehicles, and survive heavy impacts.',	'sklCrafting'),
('minExplorerDroid',	'Explorer Droid',	'A diminutive, bipedal or treaded utility droid designed for scouting, slicing, and assisting in hazardous environments.

<strong>Support Benefit</strong> Your droid flashes a targeting laser or projects a localized holomap, revealing enemy weaknesses. Until the start of your next turn, if you hit a creature that your droid is adjacent to (or a creature you are adjacent to, if the droid is sharing your space), that creature becomes off-guard against your next attack.',	'Construct, Minion, Tech',	'Tiny',	NULL,	'{"base": 25}',	'{"Low-light Vision": null}',	'{"name": "Basic Explorer Droid", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "Your droid flashes a targeting laser or projects a localized holomap, revealing enemy weaknesses. Until the start of your next turn, if you hit a creature that your droid is adjacent to (or a creature you are adjacent to, if the droid is sharing your space), that creature becomes off-guard against your next attack."}]}, "weapon": {"grant": [{"id": "wepShockProd", "bulk": null, "name": "Shock Prod", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Agile, Finesse, Nonlethal", "category": "Unarmed", "damagedie": "d4", "damagetype": "Electricity"}]}, "template": [{"infiltrator": {"name": "Infiltrator-Spec Explorer Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}], "speed": [{"amount": 10, "target": "all"}], "action": {"grant": [{"id": "actOverride", "name": "Override", "action_cost": "[one-action]", "description": "The droid interfaces with the tech. It attempts a Computers check to hack, disable, or open the device using your Computers modifier, rather than its own.", "requirements": "The Explorer Droid is adjacent to an electronic device, door control, or terminal."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 0, "con": 2, "dex": 5, "int": 2, "str": 0, "wis": 3}, "damage_dice_count": 2}}, {"escort": {"name": "Escort-Spec Explorer Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actOverride", "name": "Override", "action_cost": "[one-action]", "description": "The droid interfaces with the tech. It attempts a Computers check to hack, disable, or open the device using your Computers modifier, rather than its own.", "requirements": "The Explorer Droid is adjacent to an electronic device, door control, or terminal."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 0, "con": 2, "dex": 5, "int": 2, "str": 0, "wis": 3}, "damage_dice_count": 2}}, {"upgraded": {"name": "Upgraded Explorer Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 0, "con": 1, "dex": 3, "int": 2, "str": -1, "wis": 2}, "damage_dice_count": 2}}]}',	1,	6,	'{"cha": 0, "con": 1, "dex": 3, "int": 2, "str": -2, "wis": 1}',	'A diminutive, bipedal or treaded utility droid designed for scouting, slicing, and assisting in hazardous environments.',	'sklThievery'),
('minAstromechDroid',	'Astromech Droid',	'A stout, cylindrical astrogation and repair droid, heavily armored and packed with utility tools.

<strong>Support Benefit</strong> The astromech overcharges your weapons or directly shocks a distracted foe. Until the start of your next turn, your Strikes that hit a creature in the astromech''s reach deal 1d4 persistent electricity damage.',	'Construct, Minion, Tech',	'Small',	NULL,	'{"base": 25}',	'{"Darkvision": null}',	'{"name": "Basic Astromech Droid", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The astromech overcharges your weapons or directly shocks a distracted foe. Until the start of your next turn, your Strikes that hit a creature in the astromech''s reach deal 1d4 persistent electricity damage."}]}, "weapon": {"grant": [{"id": "wepArcWelder", "bulk": null, "name": "ArcWelder", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Agile, Finesse, Nonlethal", "category": "Unarmed", "damagedie": "d4", "damagetype": "Electricity"}]}, "template": [{"infiltrator": {"name": "Infiltrator-Spec Astromech Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}], "speed": [{"amount": 10, "target": "all"}], "action": {"grant": [{"id": "actExtinguish", "name": "Extinguish", "action_cost": "[one-action]", "description": "The droid sprays a burst of fire retardant or chemical neutralizer. The target immediately attempts a flat check to end the persistent damage, gaining a +2 circumstance bonus to the roll.", "requirements": "The astromech is adjacent to a creature taking persistent fire or acid damage."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 0, "con": 4, "dex": 5, "int": 1, "str": 3, "wis": 3}, "damage_dice_count": 2}}, {"escort": {"name": "Escort-Spec Astromech Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actExtinguish", "name": "Extinguish", "action_cost": "[one-action]", "description": "The droid sprays a burst of fire retardant or chemical neutralizer. The target immediately attempts a flat check to end the persistent damage, gaining a +2 circumstance bonus to the roll.", "requirements": "The astromech is adjacent to a creature taking persistent fire or acid damage."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 0, "con": 4, "dex": 5, "int": 1, "str": 3, "wis": 3}, "damage_dice_count": 2}}, {"upgraded": {"name": "Upgraded Astromech Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 0, "con": 3, "dex": 3, "int": 1, "str": 2, "wis": 2}, "damage_dice_count": 2}}]}',	1,	8,	'{"cha": 0, "con": 2, "dex": 2, "int": 1, "str": 1, "wis": 1}',	'A stout, cylindrical astrogation and repair droid, heavily armored and packed with utility tools.',	'sklComputers'),
('minMouseDroid',	'Mouse Droid',	'A tiny, boxy, wheeled droid designed for rapid message delivery, minor maintenance, and guiding personnel through complex facilities.

<strong>Support Benefit</strong> The mouse droid darts erratically around your target''s feet, emitting loud, panicky squeaks that ruin their concentration. Until the start of your next turn, if you hit a creature that your droid is adjacent to (or sharing a space with), that creature takes a -2 circumstance penalty to attack rolls made as a reaction (such as Reactive Strike) until the start of your next turn.',	'Construct, Minion, Tech',	'Tiny',	NULL,	'{"base": 35}',	'{"Low-light Vision": null}',	'{"name": "Basic Mouse Droid", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The mouse droid darts erratically around your target''s feet, emitting loud, panicky squeaks that ruin their concentration. Until the start of your next turn, if you hit a creature that your droid is adjacent to (or sharing a space with), that creature takes a -2 circumstance penalty to attack rolls made as a reaction (such as Reactive Strike) until the start of your next turn."}]}, "weapon": {"grant": [{"id": "wepRam", "bulk": null, "name": "Ram", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Agile, Finesse, Nonlethal", "category": "Unarmed", "damagedie": "d4", "damagetype": "B"}]}, "template": [{"infiltrator": {"name": "Infiltrator-Spec Mouse Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}], "speed": [{"amount": 10, "target": "all"}], "action": {"grant": [{"id": "actCouriersSprint", "name": "Courier''s Sprint", "action_cost": "[one-action]", "description": "The mouse droid kicks its drive motor into overdrive to deliver a payload. The droid Strides twice. It gains a +2 circumstance bonus to Acrobatics checks to Tumble Through enemy spaces during this movement. If it ends this movement adjacent to an ally, it can immediately use an Interact action to hand an item of Light bulk or less to that ally, or take an item of Light bulk or less from that ally."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 2, "con": 2, "dex": 7, "int": 0, "str": -1, "wis": 3}, "damage_dice_count": 2}}, {"escort": {"name": "Escort-Spec Mouse Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actCouriersSprint", "name": "Courier''s Sprint", "action_cost": "[one-action]", "description": "The mouse droid kicks its drive motor into overdrive to deliver a payload. The droid Strides twice. It gains a +2 circumstance bonus to Acrobatics checks to Tumble Through enemy spaces during this movement. If it ends this movement adjacent to an ally, it can immediately use an Interact action to hand an item of Light bulk or less to that ally, or take an item of Light bulk or less from that ally."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 2, "con": 2, "dex": 7, "int": 0, "str": -1, "wis": 3}, "damage_dice_count": 2}}, {"upgraded": {"name": "Upgraded Mouse Droid", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": 2, "con": 1, "dex": 5, "int": 0, "str": -2, "wis": 2}, "damage_dice_count": 2}}]}',	1,	6,	'{"cha": 2, "con": 0, "dex": 4, "int": 0, "str": -3, "wis": 1}',	'A tiny, boxy, wheeled droid designed for rapid message delivery, minor maintenance, and guiding personnel through complex facilities.',	'sklDeception'),
('minWompRat',	'Womp Rat',	'A vicious, oversized rodent native to Tatooine. Known for their aggressive pack tactics, jagged teeth, and surprisingly high speed.

<strong>Support Benefit</strong> The womp rat relentlessly tears at an enemy''s blind spots. Until the start of your next turn, your Strikes against off-guard creatures in the womp rat''s reach deal an additional 1d4 precision damage.',	'Animal, Minion',	'Small',	NULL,	'{"base": 30, "Burrow": 10}',	'{"Darkvision": null}',	'{"name": "Young Womp Rat", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The womp rat relentlessly tears at an enemy''s blind spots. Until the start of your next turn, your Strikes against off-guard creatures in the womp rat''s reach deal an additional 1d4 precision damage.<br><br>If the animal uses the Support action, the only other actions it can use on this turn are basic move actions to get into position to take advantage of the Support benefits; if it has already used any other action this turn, it can’t Support you."}]}, "weapon": {"grant": [{"id": "wepJaws", "bulk": null, "name": "Jaws", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Finesse", "category": "Unarmed", "damagedie": "d6", "damagetype": "P"}]}, "template": [{"nimble": {"name": "Nimble Womp Rat", "size": "Medium", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Expert"}, {"id": "sklIntimidation", "rank": "Trained"}, {"id": "sklAcrobatics", "rank": "Expert"}], "action": {"grant": [{"id": "actViciousBite", "name": "Vicious Bite", "action_cost": "[one-action]", "description": "The target must attempt a Fortitude save against your class DC. On a failure, the creature is sickened 1 from the filthy bite.", "requirement": "The womp rat''s last action was a successful Jaws Strike."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 4, "dex": 5, "int": -4, "str": 4, "wis": 3}, "damage_dice_count": 2}}, {"savage": {"name": "Savage Womp Rat", "size": "Large", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Expert"}, {"id": "sklIntimidation", "rank": "Trained"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actViciousBite", "name": "Vicious Bite", "action_cost": "[one-action]", "description": "The target must attempt a Fortitude save against your class DC. On a failure, the creature is sickened 1 from the filthy bite.", "requirement": "The womp rat''s last action was a successful Jaws Strike."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 4, "dex": 4, "int": -4, "str": 5, "wis": 3}, "damage_dice_count": 2}}, {"mature": {"name": "Mature Womp Rat", "size": "Medium", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Expert"}, {"id": "sklIntimidation", "rank": "Trained"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 3, "dex": 3, "int": -4, "str": 3, "wis": 2}, "damage_dice_count": 2}}]}',	1,	6,	'{"cha": -2, "con": 2, "dex": 3, "int": -4, "str": 1, "wis": 1}',	'A vicious, oversized rodent native to Tatooine known for its aggressive pack tactics.',	'sklSurvival'),
('minBlurrg',	'Blurrg',	'A stubborn, thick-skinned reptilian beast of burden with a massive mouth, famous for their charging speed and loyalty once tamed.

<strong>Support Benefit</strong> The blurrg throws its massive weight forward, giving your attacks crushing momentum. Until the start of your next turn, if you are mounted on your blurrg and it uses the Stride action, your next melee Strike deals an additional 1d8 damage. If your blurrg is upgraded, this additional damage increases to 2d8.',	'Animal, Minion',	'Medium',	'1',	'{"base": 30}',	'{"Low-light Vision": null}',	'{"action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The blurrg throws its massive weight forward, giving your attacks crushing momentum. Until the start of your next turn, if you are mounted on your blurrg and it uses the Stride action, your next melee Strike deals an additional 1d8 damage. If your blurrg is upgraded, this additional damage increases to 2d8.<br><br>If the animal uses the Support action, the only other actions it can use on this turn are basic move actions to get into position to take advantage of the Support benefits; if it has already used any other action this turn, it can’t Support you."}]}, "weapon": {"grant": [{"id": "wepRam", "bulk": null, "name": "Ram", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Agile, Finesse, Nonlethan", "category": "Unarmed", "damagedie": "d4", "damagetype": "B"}]}, "template": [{"nimble": {"name": "Nimble Blurrg", "size": "Large", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Trained"}, {"id": "sklIntimidation", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}], "action": {"grant": [{"id": "actDevastatingCharge", "name": "Devastating Charge", "action_cost": "[two-actions]", "description": "The blurrg Strides twice in a straight line and then makes a jaws Strike. If it moved at least 20 feet, it gains a +2 circumstance bonus to the attack roll."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -2, "con": 4, "dex": 4, "int": -4, "str": 5, "wis": 3}, "damage_dice_count": 2}}, {"savage": {"name": "Savage Blurrg", "size": "Large", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Trained"}, {"id": "sklIntimidation", "rank": "Expert"}, {"id": "sklAthletics", "rank": "Expert"}], "action": {"grant": [{"id": "actDevastatingCharge", "name": "Devastating Charge", "action_cost": "[two-actions]", "description": "The blurrg Strides twice in a straight line and then makes a jaws Strike. If it moved at least 20 feet, it gains a +2 circumstance bonus to the attack roll."}]}, "perception": {"rank": "Expert"}, "damage_bonus": 3, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -2, "con": 4, "dex": 3, "int": -4, "str": 6, "wis": 3}, "damage_dice_count": 2}}, {"mature": {"name": "Mature Blurrg", "size": "Large", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Trained"}, {"id": "sklIntimidation", "rank": "Expert"}], "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -2, "con": 3, "dex": 2, "int": -4, "str": 4, "wis": 2}, "damage_dice_count": 2}}]}',	1,	8,	'{"cha": -2, "con": 2, "dex": 1, "int": -4, "str": 3, "wis": 1}',	'A stubborn, thick-skinned reptilian beast of burden with a massive mouth, famous for their charging speed and loyalty once tamed.',	'sklIntimidation'),
('minSecurityDroid',	'Security Droid',	'A compact, heavily armored law enforcement and security droid designed for crowd control and facility pacification.

