('minSabotageDroid',	'Sabotage Droid',	'A spherical, insectoid droid designed to deploy in swarms, unpack itself, and rapidly dismantle enemy technology or armor using an array of cutting tools.

<strong>Support Benefit</strong> The sabotage droid latches onto the target, finding weak points in its armor or chassis. Until the start of your next turn, if you hit a creature the buzz droid threatens, your attack ignores up to 2 points of the target''s physical Resistance or Hardness.',	'Construct, Minion, Tech',	'Tiny',	NULL,	'{"base": 20, "Climb": 20}',	'{"Darkvision": null}',	'{"name": "Basic Sabotage Droid", "action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The sabotage droid latches onto the target, finding weak points in its armor or chassis. Until the start of your next turn, if you hit a creature the buzz droid threatens, your attack ignores up to 2 points of the target''s physical Resistance or Hardness."}]}, "weapon": {"grant": [{"id": "wepPlasmaTorch", "bulk": null, "name": "Plasma Torch", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Agile, Finesse", "category": "Unarmed", "damagedie": "d4", "damagetype": "Plasma"}]}, "template": [{"infiltrator": {"name": "Infiltrator-Spec Sabotage Droid", "skill": [{"id": "sklStealth", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}, {"id": "sklAcrobatics", "rank": "Expert"}], "speed": [{"amount": 10, "target": "all"}], "action": {"grant": [{"id": "actDismantle", "name": "Dismantle", "action_cost": "[one-action]", "description": "The buzz droid uses its plasma cutting torches and tools to rip apart the target''s gear. It attempts a Crafting check against the target''s Reflex DC. On a success, the target takes a -1 circumstance penalty to AC until the end of its next turn.", "requirements": "The buzz droid is adjacent to a construct, vehicle, or a creature wearing manufactured armor."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha": -1, "con": 3, "dex": 6, "int": 2, "str": 2, "wis": 2}, "damage_dice_coun