('minPufferPig',	'Puffer Pig',	'A squat, highly perceptive porcine creature with an incredibly keen sense of smell, famous for ballooning to a massive size when frightened.

<strong>Support Benefit</strong> The puffer pig rapidly inflates to absorb incoming impacts. Until the start of your next turn, if an enemy makes a melee attack against the puffer pig or an ally sharing its space, the attacker is pushed back 5 feet after the attack resolves.',	'Animal, Minion',	'Small',	NULL,	'{"base": 25}',	'{"Scent": "Precise", "Low-light Vision": null}',	'{"action": {"grant": [{"id": "actSupport", "name": "Support", "action_cost": "[one-action]", "description": "The puffer pig rapidly inflates to absorb incoming impacts. Until the start of your next turn, if an enemy makes a melee attack against the puffer pig or an ally sharing its space, the attacker is pushed back 5 feet after the attack resolves.<br><br>If the animal uses the Support action, the only other actions it can use on this turn are basic move actions to get into position to take advantage of the Support benefits; if it has already used any other action this turn, it can’t Support you."}]}, "weapon": {"grant": [{"id": "wepTusks", "bulk": null, "name": "Tusks", "type": "Melee", "group": "Brawling", "hands": "1", "traits": "Nonlethal, Shove", "category": "Unarmed", "damagedie": "d6", "damagetype": "P"}]}, "template": [{"nimble": {"name": "Nimble Puffer Pig", "size": "Medium", "skill": [{"id": "sklStealth", "rank": "Trained"}, {"id": "sklSurvival", "rank": "Expert"}, {"id": "sklIntimidation", "rank": "Trained"}, {"id": "sklAcrobatics", "rank": "Expert"}], "action": {"grant": [{"id": "actDefensiveInflation", "name": "Defensive Inflation", "action_cost": "[one-action]", "description": "The puffer pig drastically expands in size. For 1 round, it gains Resistance 3 to bludgeoning damage and its size category counts as one size larger for the purpose of blocking enemy movement and determining who can share its space."}]}, "perception": {"rank": "Expert"}, "saving_throw": [{"fortitude": {"rank": "Expert"}}, {"reflex": {"rank": "Expert"}}, {"will": {"rank": "Expert"}}], "attribute_set": {"cha"