DROP TABLE IF EXISTS "Subclass";
CREATE TABLE "public"."Subclass" (
    "SubclassID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Description" text NOT NULL,
    "Traits" character varying,
    "ClassID" character varying NOT NULL,
    "Features" jsonb,
    CONSTRAINT "Subclass_SubclassID" PRIMARY KEY ("SubclassID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Subclass"."SubclassID" IS 'Unique Subclass ID';

COMMENT ON COLUMN "public"."Subclass"."Name" IS 'Class Name';

COMMENT ON COLUMN "public"."Subclass"."Description" IS 'Subclass description text';

COMMENT ON COLUMN "public"."Subclass"."Traits" IS 'Subclass traits';

COMMENT ON COLUMN "public"."Subclass"."ClassID" IS 'Parent Class ID';

COMMENT ON COLUMN "public"."Subclass"."Features" IS 'Subclass features JSON';

INSERT INTO "Subclass" ("SubclassID", "Name", "Description", "Traits", "ClassID", "Features") VALUES
('subBioTech',	'Bio-Tech',	'<p>You view the organic body as just another complex machine—one that is frustratingly fragile, but fully capable of being repaired, optimized, and overclocked with the right chemical cocktails and surgical precision. You are a lifesaver in the harshest environments.</p>
<p><h3>Trauma Interface</h3>You become trained in Medicine, and you gain the Battle Medicine skill feat. Whenever you roll a Medicine check, you can use your Intelligence modifier instead of your Wisdom modifier.</p>
<p><h3>Vitality Override</h3>Your Custom Rig is equipped with advanced bio-scanners and synthesizers, allowing it to function as a commercial medical toolkit in addition to its other integrated toolkits. You understand how to rapidly accelerate cellular regeneration. You automatically add the Kolto Burst modification to your modification library, and you can keep it loaded in your Rig without it counting against your prepared modifications.</p>
<p><h3>Resuscitation Surge</h3>When you Overclock a modification to restore Hit Points to an ally who has the dying condition, you can choose to intentionally bypass all safety regulators to save their life. You do not roll the Overclock flat check; instead, you automatically critically fail it. In exchange, the Overclocked healing restores the maximum possible Hit Points for its dice roll, and the target''s wounded condition does not increase when they lose the dying condition.</p>',	NULL,	'clsTechSpecialist',	'{"feat": {"fixed": [{"id": "feaBattleMedicine", "type": "skill"}]}, "skill": {"fixed": [{"id": "sklMedicine", "rank": "Trained"}], "attribute_override": [{"id": "sklMedicine", "attribute": "INT"}]}, "modification": {"mod_slot": {"fixed": ["modKoltoBurst"]}, "library_slot": {"fixed": ["modKoltoBurst"]}}}'),
('subActionHero',	'Action Hero',	'You believe that anything can be solved by shooting your way out. Somehow, your bravado and over-the-top actions have a way of working out for you, despite logic often suggesting otherwise. To you, there''s no problem that a barrage of bullets or laser blasts can''t fix. You''ve become a specialist at dealing out devastation with automatic weapons, whether you''re fighting on the front line, operating a turret in a speeding vehicle, or blasting through a crowd of enemies.

When you successfully make a ranged Strike with an automatic weapon, you suppress the target until the start of your next turn. In addition, when you Auto-Fire, the size of the cone is equal to the weapon''s full range increment, rather than half. When using the Auto-Fire action, you can designate a target anywhere in the cone to be your primary target, rather than the creature closest to you.',	'Soldier',	'clsSoldier',	NULL),
('subEruditeWarrior',	'Erudite Warrior',	'You realize that not every situation should be solved with a gun. You''re an intellectual as well as a warrior, solving problems logically and learning about the galaxy. You keep your mind sharp with formal education or self-guided study. When logic breaks down, you''re always ready to fall back on your combat training.

Choose either Diplomacy or Society. You become trained in the chosen skill and one Lore skill of your choice. When you gain armor expertise, you gain expert proficiency in Diplomacy or Society (whichever you selected) and the Lore skill you selected. This increases to master proficiency when you gain armor mastery, and to legendary proficiency when you gain legendary armor. You also gain the Oppressive Presence action.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Oppressive Presence</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
  </header>

  <div class="power-card-traits">
    <span class="trait-tag">[Soldier]</span>
  </div>

  <div class="power-card-meta-grid">
    <div>
      <strong>Frequency</strong>
      <span>Once per round</span>
    </div>
  </div>

  <hr class="power-card-divider" />

  <div class="power-card-description markdown-body">
    You unnerve foes with a look, or similarly unsettle them with subtle mannerisms or veiled threats. One enemy creature of your choice within 60 feet becomes suppressed until the start of your next turn. If the creature targets you with a Strike or other offensive action, it loses the suppressed condition from this effect.
  </div>
</div>',	'Soldier',	'clsSoldier',	'{"action": {"grant": [{"id": "actOppressivePresence", "name": "Oppressive Presence", "traits": "Soldier", "frequency": "Once per round", "action_cost": "[one-action]", "description": "You unnerve foes with a look, or similarly unsettle them with subtle mannerisms or veiled threats. One enemy creature of your choice within 60 feet becomes suppressed until the start of your next turn. If the creature targets you with a Strike or other offensive action, it loses the suppressed condition from this effect."}]}, "feature": ["clfEruditeWarrior"]}'),
('subInfiltrator',	'Infiltrator',	'You specialize in bypassing security systems, hazards, traps, and other defenses. From hacking  a computer system or cutting power to a building, to bypassing a biometric lock and cracking a secure vault, you''re skilled at accessing locations without alerting security or tripping safeguards. You''re trained in Computers. You gain a skill feat for Computers.

<h3>Exploit</h3>

Your tinkering causes technological items and creatures to experience glitches and malfunctions. You gain the Sabotage action.

<div style="display: flex; justify-content: space-between;"><span><h3>Enhanced Exploit</h3></span><span><h3>Level 9</h3></span></div>

You can Sabotage as a free action whenever you critically hit a tech creature with a melee or ranged attack, targeting the triggering creature. You can Sabotage as a reaction whenever a tech creature or a creature using a tech weapon critically fails a melee attack roll against you, targeting the triggering creature or weapon.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Sabotage</h3>
      <span class="power-action-cost">[one-action]</span>
    </div>
    <div class="power-meta-top"><span class="power-level">Subclass Feature</span></div>
  </header>
  <div class="power-card-traits">
    <span class="trait-tag">Operative</span><span class="trait-tag">Concentrate</span><span class="trait-tag">Manipulate</span>
  </div>
  <div class="power-card-meta-grid"></div>
  <hr class="power-card-divider" />
  <div class="power-card-description markdown-body">
    You disrupt enemy tech to cover your tracks or gain a tactical advantage. Select a single tech creature or tech item within 15 feet that you can detect. If your target is a tech creature, attempt a Computers check against the creature''s Fortitude DC. If your target is a tech item, attempt a Computers check against the item''s DC or the Reflex DC of the creature possessing the item if the item is being carried, held, or worn.<br><br>If you''re an expert in Computers, you can Sabotage a tech creature or tech item within 30 feet. If you''re a master, this range increases to 45 feet. If you''re legendary, this range increases to 60 feet.<br><br>**Critical Success** The target becomes glitching 1 for 1 minute.<br>**Success** The target becomes glitching 1 for 2 rounds.<br>**Failure** Your attempt fails and requires more persistent analysis. The target is immune to your Sabotage until the end of your next turn.<br>**Critical Failure** Your attempt backfires. The target is immune to your Sabotage for 10 minutes.
  </div>
</div>',	'Operative',	'clsOperative',	'{"flag": {"operative_spec_skill": "Computers"}, "skill": {"fixed": [{"id": "sklComputers", "rank": "Trained"}]}, "action": {"grant": [{"id": "actSabotage", "name": "Sabotage", "traits": "Operative, Concentrate, Manipulate", "action_cost": "[one-action]", "description": "You disrupt enemy tech to cover your tracks or gain a tactical advantage. Select a single tech creature or tech item within 15 feet that you can detect. If your target is a tech creature, attempt a Computers check against the creature''s Fortitude DC. If your target is a tech item, attempt a Computers check against the item''s DC or the Reflex DC of the creature possessing the item if the item is being carried, held, or worn.\n\nIf you''re an expert in Computers, you can Sabotage a tech creature or tech item within 30 feet. If you''re a master, this range increases to 45 feet. If you''re legendary, this range increases to 60 feet.\n\n**Critical Success** The target becomes glitching 1 for 1 minute.\n**Success** The target becomes glitching 1 for 2 rounds.\n**Failure** Your attempt fails and requires more persistent analysis. The target is immune to your Sabotage until the end of your next turn.\n**Critical Failure** Your attempt backfires. The target is immune to your Sabotage for 10 minutes."}]}, "feature": ["clfSpecializedSkillSet"]}'),
('subMandateOfLife',	'Mandate of Life',	'You view the Force as a river of energy that binds all living things. Your training focuses on mending wounds, purging toxins, and shielding life from harm.

You gain the Vital Transfer power.

<strong>Connected Benefit</strong> Your connection overflows with life energy. Whenever you use an action with the Force Power trait that restores Hit Points to a creature, that creature gains temporary Hit Points equal to your Level (minimum 1). These temporary Hit Points last until the start of your next turn.',	'Consular',	'clsConsular',	'{"power": {"fixed": ["powVitalTransfer"]}}'),
('subScrapper',	'Scrapper',	'<p>You don''t need pristine, military-grade tech; you can build a thermal detonator out of a rusty power converter and a damaged comlink. You understand the hidden value in things others throw away, and your gear is a chaotic mess of mismatched, highly effective parts.</p>
<p><h3>Salvager''s Intuition</h3> You are a master of quick, dirty fixes and destructive bypasses. You can perform the Repair exploration activity in half the usual time. You automatically add the Fusion Torch modification to your modification library, and you can keep it loaded in your Rig without it counting against your prepared modifications. Additionally, you can use your Custom Rig to substitute a Crafting check (or an appropriate Engineering Lore check, at the GM''s discretion) for Thievery when attempting to Disable a Device or Pick a Lock by physically short-circuiting or dismantling the mechanism.<br><br>
You become trained in Survival. Whenever you roll a Survival check, you can use your Intelligence modifier instead of your Wisdom modifier.</p>
<h2 id="jury-rigged-adapter">Jury-Rigged Adapter</h2>
<p>Your Custom Rig is a hazardous mess of exposed wiring, bypass shunts, and universal ports, allowing you to forcefully modify components. During your daily preparations, you can select one installed Modification and physically alter its output parameters. Choose one of the following adaptations to apply to that Modification. This alteration lasts until your next daily preparations, even if you uninstall and reinstall the Modification later in the day using a Hot-Swap.</p>
<ul>
<li><p><strong>Energy Conversion:</strong> If the Modification deals acid, cold, electricity, fire, or sonic damage, you can change the damage type to a different one from that list. You also replace the Modification&#39;s corresponding energy trait with the new trait (for example, replacing the fire trait with the acid trait).</p>
</li>
<li><p><strong>Kinetic Conversion:</strong> If the Modification deals bludgeoning, piercing, or slashing damage, you can change the damage type to a different one from that list. You also replace the corresponding damage trait.</p>
</li>
<li><p><strong>Aperture Shift:</strong> If the Modification affects an area, you can physically alter its projector nozzle or blast casing to change its shape. You can change a 15-foot cone into a 30-foot line, a 30-foot line into a 15-foot cone, or a 10-foot burst into a 15-foot emanation.</p>
</li>
</ul>

<p><h3>Ablative Casing</h3> You constantly bolt physical scrap and spare fuses to your gear. When you fail the flat check for an Overclock action, you can choose to have your Ablative Casing take the blowout. You ignore the failure effect and do not lose the ability to Overclock. However, your casing is blown to pieces; you cannot use this ability again until you spend 10 minutes performing a specialized Crafting activity to bolt new scrap onto your rig.</p>',	NULL,	'clsTechSpecialist',	'{"skill": {"fixed": [{"id": "sklSurvival", "rank": "Trained"}], "attribute_override": [{"id": "sklSurvival", "attribute": "INT"}]}, "modification": {"mod_slot": {"fixed": ["modFusionTorch"]}, "library_slot": {"fixed": ["modFusionTorch"]}}}'),
('subArmstech',	'Armstech',	'<p>You focus on weapon modifications, armor plating, and explosive ordnance. You prefer to be in the middle of a firefight, trusting the gear you built with your own hands to keep you alive and tear through enemy defenses.</p>
<p><h3>Jury-Rigged Arsenal</h3> You gain proficiency in medium armor and martial weapons. When class features increase your proficency in light armor or simple weapons, your respective proficiency in medium armor and martial weapons also increases.</p>
<p><h3>Predictive Ballistics</h3> You can wire your weapons directly into your custom rig''s targeting sensors. As part of your daily preparations, or as a 10-minute activity, you can interface your custom rig into a ranged weapon with the tech trait. You use your Intelligence modifier instead of your Dexterity modifier for ranged attack rolls with this weapon. You automatically add the Fragmentation Charge modification to your modification library, and you can keep it loaded in your Rig without it counting against your prepared modifications.</p>
<p><h3>Suppressive Overdrive</h3> You can Overclock a standard ranged weapon to push it far beyond its firing rate. You can make an Area Fire or Auto-Fire attack using the weapon interfaced to your custom rig, treating it as if it had the Automatic or Area (Burst 5ft) trait. You use your tech specialist class DC for this effect. If you fail the Overclock flat check, your weapon misfires in addition to you losing the ability to Overclock for 10 minutes. You must spend an Interact action to clear the weapon before it can be used to make ranged Strikes again.</p>',	NULL,	'clsTechSpecialist',	'{"1": {"attack": [{"martial": {"rank": "Trained"}}], "defense": [{"medium": {"rank": "Trained"}}]}, "5": {"attack": [{"martial": {"rank": "Expert"}}]}, "13": {"attack": [{"martial": {"rank": "Master"}}], "defense": [{"medium": {"rank": "Expert"}}]}, "19": {"defense": [{"medium": {"rank": "Master"}}]}, "modification": {"mod_slot": {"fixed": ["modFragmentationCharge"]}, "library_slot": {"fixed": ["modFragmentationCharge"]}}}'),
('subSniper',	'Sniper',	'You specialize in targeting foes from far away and attacking while unseen. Whether you''re peeking around a corner, perching on a distant rooftop, or aiming from the back line of a squad formation, you favor sniper rifles and prefer to line up the perfect shot rather than rush into combat. You''re trained in Stealth. You gain a skill feat for Stealth.

<h3>Exploit</h3>

You ignore the unwieldy and volley trait of guns you wield belonging to the sniper group. You gain one of the following operative feats as a bonus feat: Keep Them in Your Sights or Scope Sight.

<div style="display: flex; justify-content: space-between;"><span><h3>Enhanced Exploit</h3></span><span><h3>Level 9</h3></span></div>

If you fail your first ranged Strike against your mark using a weapon in the sniper weapon group, you Reload your sniper weapon as a free action. The Strike doesn''t count toward your multiple attack penalty.',	'Operative',	'clsOperative',	'{"flag": {"operative_spec_skill": "Stealth"}, "skill": {"fixed": [{"id": "sklStealth", "rank": "Trained"}]}, "inputs": [{"name": "target_feat", "type": "class_feat", "label": "Sniper Feat", "filter": {"id": ["cftKeepThemInYourSights", "cftScopeSight"]}}], "feature": ["clfSpecializedSkillSet"]}'),
('subStriker',	'Striker',	'You specialize in hand-to-hand combat and prefer to fight with your fists or lightweight melee weapons, rather than guns. Whether you''re a daredevil who lives for the thrill, a martial artist who likes to show off, or an assassin who kills with a personal touch, you take the fight to your foes and use your body as a weapon. You''re trained in Athletics. You gain a skill feat for Athletics.

<h3>Exploit</h3>

You have expert proficiency with one-handed melee weapons and unarmed attacks with the agile or finesse traits instead of with martial guns. Whenever you increase your proficiency with martial guns, you instead increase your proficiency with one-handed agile and finesse melee weapons, agile and finesse unarmed attacks, and simple guns.  
  
In addition, when you Aim, you can Aim with and apply the benefits to a one-handed melee weapon or unarmed attack with the agile or finesse trait rather than with a ranged weapon. Treat any one-handed melee weapon or unarmed attack with the agile or finesse trait as a gun for purposes of meeting the requirements of operative feats. Instead of making a ranged Strike with an operative feat, you can make a Strike with an one-handed melee weapon or unarmed attack with the agile or finesse trait.  
  
You gain the Reactive Step reaction.

<div style="display: flex; justify-content: space-between;"><span><h3>Enhanced Exploit</h3></span><span><h3>Level 9</h3></span></div>

You find yourself able to overwhelm foes that you study. You gain the Overwhelming Strike free action.

<div class="power-card-display">
  <header class="power-card-header">
    <div class="power-title-line">
      <h3 class="power-name">Reactive Step</h3>
      <span class="power-action-cost">[reaction]</span>
    </div>
    <div class="power-meta-top"><span class="power-level">Subclass Feature</span></div>
  </header>
  <div class="power-card-traits">
