DROP TABLE IF EXISTS "Weapon";
CREATE TABLE "public"."Weapon" (
    "WeaponID" character varying NOT NULL,
    "Name" character varying NOT NULL,
    "Category" character varying NOT NULL,
    "Group" character varying,
    "Level" smallint DEFAULT '0',
    "DamageDie" character varying,
    "DamageType" character varying,
    "Hands" character varying DEFAULT '1',
    "Range" smallint,
    "Reload" character varying DEFAULT '-',
    "Bulk" character varying DEFAULT 'L',
    "Traits" character varying,
    "Description" text,
    "Features" jsonb,
    "Type" character varying NOT NULL,
    "Expend" smallint,
    "Magazine" smallint,
    "Price" integer,
    "Upgrades" smallint DEFAULT '1' NOT NULL,
    CONSTRAINT "Weapon_WeaponID" PRIMARY KEY ("WeaponID")
)
WITH (oids = false);

COMMENT ON COLUMN "public"."Weapon"."Category" IS 'Proficiency Category (Simple, Martial, Advanced)';

COMMENT ON COLUMN "public"."Weapon"."DamageDie" IS 'Base damage die size (e.g. d6, d8)';

COMMENT ON COLUMN "public"."Weapon"."Range" IS 'Range increment in feet. NULL indicates melee only.';

INSERT INTO "Weapon" ("WeaponID", "Name", "Category", "Group", "Level", "DamageDie", "DamageType", "Hands", "Range", "Reload", "Bulk", "Traits", "Description", "Features", "Type", "Expend", "Magazine", "Price", "Upgrades") VALUES
('wepHeavyRepeater',	'Heavy Repeater',	'Martial',	'Projectile',	0,	'd10',	'P',	'2',	60,	'[two-actions]',	'3',	'Automatic, Kickback, Tech, Unwieldy',	'A support weapon designed to lay down suppressing fire. It is heavy and cannot be fired accurately on the move.',	NULL,	'Ranged',	2,	100,	65,	1),
('wepCyclerRifle',	'Cycler Rifle',	'Martial',	'Sniper',	0,	'd8',	'P',	'2',	100,	'[one-action]',	'2',	'Analog, Concussive, Fatal d12, Tusken Raider',	'Before the widespread adoption of blasters, slugthrowers were the standard, and the Cycler Rifle is a terrifyingly effective relic of that era. Firing solid kinetic slugs (often carved from stone or salvaged metal) rather than energy bolts, it possesses massive stopping power and an incredibly long range. The deafening crack of a cycler firing is a dreaded sound in the deep desert.',	NULL,	'Ranged',	1,	1,	100,	1),
('wepLightsaber',	'Lightsaber',	'Advanced',	'Lightsaber',	1,	'd8',	'Plasma',	'1',	NULL,	'-',	'L',	'Concealable, Deadly d8, Finesse, Razing, Tech',	'An elegant weapon consisting of a plasma blade contained in a magnetic field. It can cut through almost anything but requires force-sensitivity or intense training to use safely.',	NULL,	'Melee',	NULL,	NULL,	50,	1),
('wepRiotScattergun',	'Riot Scattergun',	'Martial',	'Projectile',	0,	'd8',	'P',	'2',	20,	'[one-action]',	'2',	'Area (Cone), Tech',	'A pump-action weapon that fires a spread of pellets or flechettes. It is devastating at close range but loses effectiveness quickly over distance.',	NULL,	'Ranged',	1,	8,	30,	1),
('wepHeavyBlasterCannon',	'Heavy Blaster Cannon',	'Martial',	'Plasma',	0,	'd12',	'Plasma',	'2',	80,	'[two-actions]',	'4',	'Area (Burst 10ft), Heavy, Tech, Unwieldy',	'A stripped-down vehicle weapon modified for infantry use. It fires unstable plasma bolts that explode on contact, suppressing entire squads.',	NULL,	'Ranged',	5,	20,	120,	1),
('wepVibrosword',	'Vibrosword',	'Martial',	'Sword',	0,	'd8',	'S',	'1',	NULL,	'-',	'1',	'Tech, Versatile P',	'A balanced blade with a sonic generator in the hilt that vibrates the edge at high frequencies to cut through dense material.',	NULL,	'Melee',	NULL,	NULL,	25,	1),
('wepVambraceVibroBlade',	'Vambrace Vibro-Blade',	'Advanced',	'Knife',	0,	'd4',	'S',	'1',	NULL,	'-',	'L',	'Agile, Finesse, Free-hand, Mandalorian, Versatile P',	'A concealed, retractable blade housed in the vambrace housing, vibrating at ultrasonic frequencies to slice through armor.',	NULL,	'Melee',	NULL,	NULL,	20,	1),
('wepVambraceFlamethrower',	'Vambrace Flamethrower',	'Advanced',	'Flame',	0,	'd4',	'Fire',	'1',	15,	'[one-action]',	'L',	'Area (Cone), Free-hand, Mandalorian',	'A miniaturized incendiary projector that sprays a burst of ignited chemical fuel over a short distance.',	NULL,	'Ranged',	1,	4,	40,	1),
('wepRiotShockStaff',	'Riot Shock-Staff',	'Martial',	'Staff',	0,	'd8',	'B',	'2',	NULL,	'-',	'2',	'Backswing, Nonlethal, Reach, Tech',	'A long, insulated staff with conductive striking surfaces. Excellent for keeping crowds at bay without lethal force.',	NULL,	'Melee',	NULL,	NULL,	20,	1),
('wepDoubleBladedLightsaber',	'Double-Bladed Lightsaber',	'Advanced',	'Lightsaber',	1,	'd6',	'Plasma',	'2',	NULL,	'-',	'1',	'Agile, Finesse, Tech, Twin',	'A long hilt with a lightsaber emitter at both ends. It creates a wall of energy but is notoriously dangerous to the wielder.',	NULL,	'Melee',	NULL,	NULL,	60,	1),
('wepBlasterCarbine',	'Blaster Carbine',	'Martial',	'Plasma',	0,	'd8',	'Plasma',	'2',	80,	'[one-action]',	'1',	'Tech',	'A shorter, lighter version of the blaster rifle. Favored by vehicle crews and boarding parties.',	NULL,	'Ranged',	1,	50,	35,	1),
('wepBlasterPistol',	'Blaster Pistol',	'Martial',	'Plasma',	0,	'd6',	'Plasma',	'1',	60,	'[one-action]',	'L',	'Fatal d8, Tech',	'The galaxy standard sidearm. Reliable, good range, and decent stopping power.',	NULL,	'Ranged',	1,	50,	20,	1),
('wepBlasterSniperRifle',	'Blaster Sniper Rifle',	'Martial',	'Sniper',	0,	'd8',	'Plasma',	'2',	120,	'[one-action]',	'2',	'Tech, Volley 30ft',	'The backbone of infantry forces. It offers superior range and damage but is difficult to use in close quarters.',	NULL,	'Ranged',	1,	50,	45,	1),
('wepCombatKnife',	'Combat Knife',	'Simple',	'Knife',	0,	'd4',	'S',	'1',	NULL,	'-',	'L',	'Agile, Finesse, Thrown 10ft, Versatile P',	'A standard issue dura-steel knife carried by soldiers and survivalists alike.',	NULL,	'Melee',	NULL,	NULL,	2,	1),
('wepGaffiStick',	'Gaffi Stick',	'Martial',	'Club',	0,	'd10',	'B',	'2',	NULL,	'-',	'1',	'Analog, Trip, Tusken Raider, Versatile P',	'The traditional melee weapon of the Tusken Raiders is a heavy, polearm-like club, typically forged from salvaged starship plating or durasteel piping. One end features a heavy bludgeoning weight or flange, while the opposite end is capped with a vicious piercing spike, making it highly adaptable in close-quarters combat.',	NULL,	'Melee',	NULL,	NULL,	20,	1),
('wepHoldoutBlaster',	'Holdout Blaster',	'Simple',	'Plasma',	0,	'd4',	'Plasma',	'1',	30,	'[one-action]',	'L',	'Agile, Concealable, Tech',	'A tiny blaster pistol easily hidden in a boot or sleeve. Short range, but deadly in a pinch.',	NULL,	'Ranged',	1,	10,	10,	1),
('wepIonBlaster',	'Ion Blaster',	'Simple',	'Ion',	0,	'd6',	'Ion',	'1',	30,	'[one-action]',	'L',	'Nonlethal, Tech',	'A specialized pistol that fires ion energy. It is highly effective against droids and electronics but generally non-lethal to organics.',	NULL,	'Ranged',	1,	15,	15,	1),
('wepIonRifle',	'Ion Rifle',	'Martial',	'Ion',	0,	'd10',	'Ion',	'2',	100,	'[one-action]',	'2',	'Nonlethal, Tech',	'A long-barreled rifle designed to disable electronics and droids from a distance. Its massive discharge can overload circuitry instantly.',	NULL,	'Ranged',	1,	20,	40,	1),
('wepPortableIonCannon',	'Portable Ion Cannon',	'Martial',	'Ion',	1,	'd12',	'Ion',	'2',	60,	'[two-actions]',	'3',	'Area (Burst 10ft), Heavy, Nonlethal, Tech, Unwieldy',	'A shoulder-mounted cannon that lobs a concentrated sphere of ion energy. Upon impact, it releases a pulse that disables anything in the blast radius.',	NULL,	'Ranged',	4,	12,	90,	1),
('wepShatterRifle',	'Shatter Rifle',	'Martial',	'Sniper',	0,	'd8',	'P',	'2',	120,	'[one-action]',	'2',	'Concussive, Fatal d10, Kickback, Tech, Unwieldy, Volley 30ft',	'',	NULL,	'Ranged',	1,	8,	110,	1),
('wepSlugthrowerPistol',	'Slugthrower Pistol',	'Simple',	'Projectile',	0,	'd6',	'P',	'1',	40,	'[one-action]',	'L',	'Analog, Fatal d10',	'An archaic projectile weapon. While less flashy than a blaster, it is cheap, hard to trace, and effective against unarmored targets.',	NULL,	'Ranged',	1,	8,	4,	1),
('wepStunBaton',	'Stun Baton',	'Simple',	'Club',	0,	'd4',	'B',	'1',	NULL,	'-',	'1',	'Agile, Finesse, Nonlethal, Tech',	'A weighted rod with a shock emitter tip, used widely by police forces for apprehension.',	NULL,	'Melee',	NULL,	NULL,	5,	1),
('wepVambraceFibercord',	'Vambrace Fibercord',	'Advanced',	'Flail',	0,	'd4',	'B',	'1',	NULL,	'-',	'L',	'Disarm, Finesse, Free-hand, Grapple, Mandalorian, Reach',	'A high-tensile wire attached to a pneumatic spool, designed to bind targets or rip weapons from their grasp.',	NULL,	'Melee',	NULL,	NULL,	25,	1),
('wepWhistlingBirdLauncher',	'Whistling Bird Launcher',	'Advanced',	'Dart',	0,	'd4',	'P',	'1',	30,	'[one-action]',	'L',	'Automatic, Fatal d8, Free-hand, Mandalorian',	'A specialized launcher that fires small, guided munitions constructed of beskar, designed to drop multiple targets with a lethal flurry of projectiles.',	NULL,	'Ranged',	1,	10,	50,	1),
('wepArggarok',	'Arg''garok',	'Advanced',	'Axe',	0,	'd12',	'S',	'2',	NULL,	'-',	'2',	'Analog, Deadly d10, Gamorrean, Sweep',	'The Arg''garok is the quintessential Gamorrean weapon. It is a massive, two-handed axe forged from dense, low-grade durasteel. It is intentionally designed to be extremely top-heavy, relying on the Gamorrean''s natural low center of gravity and immense upper-body strength to control the swing. In the hands of a properly trained bruiser, the sheer kinetic force of the axe head can easily cleave through personal energy shields and stormtrooper armor.',	NULL,	'Melee',	NULL,	NULL,	40,	1),
('wepBolas',	'Bolas',	'Martial',	'Sling',	0,	'd4',	'B',	'1',	20,	'[one-action]',	'L',	'Analog, Ewok, Nonlethal, Thrown, Trip',	'A simple but highly effective hunting tool made from leather straps and heavy stone or scavenged durasteel weights. When thrown, the bolas spin rapidly, wrapping around the target''s legs to instantly drop them to the ground. This was the exact weapon used to immobilize Imperial scout troopers before they could draw their blasters.',	NULL,	'Ranged',	1,	1,	15,	1),
('wepBowcaster',	'Bowcaster',	'Advanced',	'Projectile',	0,	'd10',	'P',	'2',	80,	'[one-action]',	'2',	'Kickback, Tech, Wookiee',	'A Wookiee-designed weapon that launches explosive quarrels magnetically. It has tremendous recoil and stopping power.',	NULL,	'Ranged',	1,	5,	90,	1),
('wepCesta',	'Cesta (Booma Launcher)',	'Martial',	'Sling',	0,	'd8',	'Electricity',	'1',	80,	'[one-action]',	'1',	'Concussive, Gungan, Propulsive, Tech',	'The cesta is a long, flexible throwing stick used to hurl "boomas"—spheres of localized, naturally occurring plasma mined from the Naboo ocean core. While a booma can be thrown by hand, the cesta dramatically increases its range and impact velocity. When a booma strikes a target, the containment field shatters, releasing a concussive wave of electrical energy.',	NULL,	'Ranged',	1,	1,	40,	1),
('wepEwokHuntersBow',	'Ewok Hunter''s Bow',	'Simple',	'Bow',	0,	'd6',	'P',	'2',	60,	NULL,	'1',	'Analog, Deadly d8, Ewok',	'A compact, recurve bow carved from the dense wood of Endor''s massive trees. Because of its size, it lacks the raw penetrative power of a Wookiee Bowcaster or the range of a standard rifle, but it is entirely silent and can be drawn and fired rapidly from the thick forest canopy.',	NULL,	'Ranged',	NULL,	NULL,	20,	1),
('wepGamorreanCleaver',	'Gamorrean Cleaver',	'Martial',	'Axe',	0,	'd8',	'S',	'1',	NULL,	'-',	'1',	'Analog, Forceful, Gamorrean',	'For Gamorreans who prefer to keep one hand free for grappling, punching, or holding a blaster they barely know how to aim, the cleaver is the weapon of choice. It is essentially a slab of sharpened durasteel bolted to a thick handle. It lacks the finesse of a vibroblade, but what it lacks in elegance it makes up for in raw, crushing weight.',	NULL,	'Melee',	NULL,	NULL,	20,	1),
('wepGunganElectropole',	'Gungan Electropole',	'Martial',	'Spear',	0,	'd8',	'P',	'2',	NULL,	'-',	'2',	'Gungan, Parry, Reach, Tech, Versatile E',	'The standard issue weapon of the Gungan Grand Army. At first glance, it looks like a simple staff or spear, but the tips are energized with a potent, crackling purple plasma that can pierce armor or shock a target into submission. It is elegant, lightweight, and highly effective at keeping dangerous fauna—or battle droids—at a distance.',	NULL,	'Melee',	NULL,	NULL,	30,	1),
('wepJawaIonizationBlaster',	'Jawa Ionization Blaster',	'Simple',	'Ion',	0,	'd6',	'Ion',	'2',	60,	'[one-action]',	'1',	'Jawa, Nonlethal, Tech',	'Essentially a heavily modified, scavenged blaster rifle hooked up to a high-capacity power cell, the ionization blaster fires a dense ring of ion energy. It is designed to instantly overload a droid''s behavioral matrix and short-circuit their motivators, allowing the Jawas to safely capture and sell them. Against organic targets, the shock is incredibly painful and causes severe muscle spasms, but it is rarely fatal.',	NULL,	'Ranged',	1,	20,	40,	1),
('wepNightsisterEnergyBow',	'Nightsister Energy Bow',	'Advanced',	'Bow',	0,	'd8',	'Plasma',	'2',	100,	'-',	'2',	'Deadly d10, Propulsive, Tech, Zabrak',	'Wielded almost exclusively by the Dathomirian Zabraks (specifically the Nightsister clans), this weapon is a terrifying fusion of physical archery and raw plasma generation. The physical bow acts as a magnetic conduit; when the wielder draws back the string, the weapon generates an arrow of pure, localized plasma that incinerates targets on impact. Because of the intense heat and specialized draw weight, it requires specialized training to use without burning oneself.',	NULL,	'Ranged',	NULL,	NULL,	80,	1),
('wepRyykBlade',	'Ryyk Blade',	'Martial',	'Sword',	0,	'd8',	'S',	'1',	NULL,	'-',	'1',	'Analog, Sweep, Wookiee',	'The traditional melee weapon of the Wookiees, the Ryyk blade is a heavy, slightly curved sword that looks like a cross between a machete and a scimitar. While they are often wielded in pairs by Wookiee berserkers, even a single Ryyk blade carries enough heft to cleave through heavy armor or thick jungle undergrowth with terrifying ease.',	NULL,	'Melee',	NULL,	NULL,	20,	1),
('wepScavengersControlProd',	'Scavenger''s Control Prod',	'Simple',	'Ion',	0,	'd4',	'Ion',	'1',	NULL,	'-',	'L',	'Agile, Finesse, Jawa, Nonlethal, Tech',	'When a captured astromech gets stubborn, or a protocol droid refuses to march into the Sandcrawler, Jawas rely on these short, insulated batons tipped with a sparking electro-node. They are easy to swing, easy to carry, and hold enough charge to force compliance.',	NULL,	'Melee',	NULL,	NULL,	15,	1),
('wepVibroAxe',	'Vibro-Axe',	'Martial',	'Axe',	0,	'd10',	'S',	'2',	NULL,	'-',	'2',	'Reach, Tech, Wookiee',	'While the Ryyk blade is elegant, the Wookiee Vibro-Axe is an instrument of pure, brute-force trauma. Forged from dense Kashyyyk timber and heavy durasteel, the axe head features ultrasonic vibration generators that allow it to saw through blast doors and stormtrooper plating alike.',	NULL,	'Melee',	NULL,	NULL,	35,	1),
('wepZhaboka',	'Zhaboka (Iridonian Double-Blade)',	'Martial',	'Polearm',	0,	'd8',	'S',	'2',	NULL,	'-',	'2',	'Analog, Parry, Sweep, Zabrak',	'The traditional weapon of the Iridonian Zabraks, the zhaboka is a highly lethal, two-meter-long weapon consisting of a central solid grip flanked by two long, heavy durasteel blades. Mastering the zhaboka is a rite of passage on Iridonia. It relies on a continuous, twirling momentum that creates a localized sphere of defensive and offensive steel, a fighting style that eventually heavily influenced the design and use of the double-bladed lightsaber.',	NULL,	'Melee',	NULL,	NULL,	30,	1),
('wepVambraceRepulsor',	'Vambrace Repulsor',	'Martial',	'Shock',	0,	'd6',	'B',	'1',	15,	'[one-action]',	'L',	'Free-Hand, Mandalorian, Nonlethal, Shove, Tech',	'Often used to create space when swarmed by enemies or to knock a target off balance before a lethal strike, the repulsor emits a short, violently compressed wave of kinetic energy. It doesn''t deal lethal damage, but the concussive force hits like a speeder truck.',	NULL,	'Ranged',	1,	1,	45,	1),
('wepVambraceDartLauncher',	'Vambrace Dart Launcher (Kamini Darts)',	'Martial',	'Dart',	0,	'd4',	'P',	'1',	30,	'[one-action]',	'L',	'Agile, Concealable, Free-Hand, Injection, Mandalorian, Tech',	'A stealthier option favored by Mandalorian bounty hunters and assassins. This miniaturized pneumatic launcher fires tiny, armor-piercing darts. On their own, the darts barely break the skin, but they are designed with microscopic reservoirs intended to deliver potent neurotoxins, sedatives, or tracking fobs.',	NULL,	'Ranged',	1,	4,	35,	1),
('wepMortarRifle',	'Mortar Rifle',	'Advanced',	'Sniper',	0,	'd10',	'Plasma',	'2',	80,	'[one-action]',	'2',	'Area (5ft), Tech, Trandoshan',	'Made infamous by the bounty hunter Bossk, the Relby-v10 mortar rifle is a terrifying piece of hardware that blurs the line between a heavy targeting rifle and a micro-grenade launcher. It fires highly explosive plasma charges that detonate on impact.',	NULL,	'Ranged',	1,	5,	85,	1),
('wepTrandoshanHuntingSword',	'Trandoshan Hunting Sword',	'Martial',	'Sword',	0,	'd8',	'S',	'1',	NULL,	'-',	'1',	'Analog, Forceful, Sweep, Trandoshan',	'Trandoshans view melee combat as the most honorable way to score Jagannath points. Their traditional hunting swords are perfectly balanced for their physiology: heavy, single-edged, and aggressively serrated to cause massive bleeding.',	NULL,	'Melee',	NULL,	NULL,	25,	1),
('wepRotaryBlasterCannon',	'Rotary Blaster Cannon',	'Martial',	'Plasma',	0,	'd8',	'Plasma',	'2',	60,	'[one-action]',	'2',	'Automatic, Tech',	'The rotary blaster cannon is a heavy-duty suppression tool defined by its signature bundle of six oscillating barrels. Driven by a high-torque electric motor, the weapon cycles its cooling actuators rapidly to allow for a staggering rate of fire that would melt the galven circuitry of a standard rifle. While its weight and the gyroscopic pull of the spinning barrels make it difficult to aim with precision, it is unparalleled at "clearing a hallway" or pinning down entrenched infantry. Soldiers often refer to the weapon by the rhythmic, low-frequency hum it emits while active—a sound that usually precedes a devastating hail of glowing plasma.',	NULL,	'Ranged',	1,	10,	60,	1),
('wepACPArrayGun',	'ACP Array Gun',	'Martial',	'Plasma',	0,	'd8',	'Plasma',	'2',	30,	'[one-action]',	'2',	'Automatic, Tech, Trandoshan',	'The signature weapon of Trandoshan slavers and bounty hunters, the accelerated charged particle array gun is functionally a particle shotgun. It fires a widespread burst of charged kinetic energy that is almost impossible to dodge at close range, making it ideal for dropping fast-moving prey or suppressing a group of targets.',	NULL,	'Ranged',	1,	10,	45,	1),
('wepVambraceTwinBlaster',	'Vambrace Twin-Blaster',	'Simple',	'Plasma',	0,	'd6',	'Plasma',	'1',	40,	'[one-action]',	'L',	'Agile, Free-Hand, Mandalorian, Tech',	'Made famous by Death Watch and the Nite Owls, these are miniaturized, twin-barreled blaster emitters built directly into the top of the gauntlet housing. They lack the range and raw stopping power of a standard blaster pistol, but they are instantly available when a warrior is disarmed or locked in a grapple.',	NULL,	'Ranged',	1,	10,	30,	1),
('wepSpearBlaster',	'Spear-Blaster',	'Martial',	'Plasma',	0,	'd6',	'Plasma',	'2',	60,	'[one-action]',	'2',	'Aquatic, Mon Calamari, Tech',	'Carried by the Mon Calamari Knights during the Clone Wars, this weapon appears to be an elegant, two-handed energy pike. However, the shaft contains a fully functional blaster barrel, allowing a soldier to hold a defensive line with a polearm while laying down suppressing fire. Both the energy blade and the blaster emitter are specially shielded to fire perfectly underwater without damage or range penalties.',	'{"weapon": {"grant": [{"id": "wepSpearBlasterSpear", "bulk": null, "name": "Spear-Blaster", "type": "Melee", "group": "Spear", "hands": "2", "traits": "Aquatic, Finesse, Mon Calamari, Reach, Tech", "category": "Martial", "damagedie": "d8", "damagetype": "P"}]}}',	'Ranged',	1,	20,	60,	1);

